INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ingles', 'bachillerato', '{1}', '["Tom decided to apply for a summer internship at a tech company in London.","He prepared his curriculum vitae and wrote a motivation letter explaining his skills.","After a long interview process he received an offer from one of the leading firms.","During the internship he learned about teamwork programming and project management.","At the end of the summer he was offered a permanent position in the company."]'),
('ingles', 'bachillerato', '{1}', '["Albert Einstein was born in Germany in 1879 and showed an early interest in physics.","He developed the special theory of relativity while working at a patent office.","His famous equation E equals mc squared revolutionized modern scientific thought.","In 1921 he was awarded the Nobel Prize for his work on the photoelectric effect.","Einstein later moved to the United States where he continued his research until his death."]'),
('ingles', 'bachillerato', '{1}', '["The Beatles formed in Liverpool in 1960 with John Paul George and Ringo.","They became famous in Britain after several successful singles and television appearances.","In 1964 they travelled to America and started the so-called British Invasion.","They released groundbreaking albums that transformed popular music forever.","The band split up in 1970 but their influence is still felt around the world."]'),
('ingles', 'bachillerato', '{1}', '["A young athlete decided to train for the marathon in her home city.","She followed a strict schedule running every morning before going to school.","Her coach designed a balanced diet rich in carbohydrates and proteins.","On race day she felt nervous but confident thanks to months of preparation.","She crossed the finish line in three hours and felt proud of her achievement."]'),
('ingles', 'bachillerato', '{1}', '["The Wright brothers spent years studying birds and experimenting with gliders.","They built their first powered aircraft in a small bicycle workshop in Ohio.","On December 17 1903 Orville flew the plane for twelve seconds at Kitty Hawk.","This historic flight marked the beginning of modern aviation in the world.","Within decades aeroplanes had become a common form of long distance transport."]'),
('ingles', 'bachillerato', '{1}', '["A volunteer group decided to clean a polluted beach in their local town.","They organized a community event using social media to invite young people.","On Saturday morning over a hundred volunteers gathered with bags and gloves.","They collected several tons of plastic waste and broken fishing nets.","The local council praised the initiative and promised to support future actions."]'),
('ingles', 'bachillerato', '{1}', '["Alexander Fleming was a Scottish bacteriologist working in a London hospital.","One day in 1928 he noticed mould growing in one of his petri dishes.","He observed that the mould was killing the bacteria around it on the plate.","This accidental discovery led to the development of penicillin as a powerful antibiotic.","Fleming received the Nobel Prize and his discovery has saved millions of human lives."]'),
('ingles', 'bachillerato', '{1}', '["The first underground railway in the world opened in London in 1863.","It used steam locomotives that created clouds of smoke inside the dark tunnels.","Despite the discomfort millions of passengers used it to commute every week.","Later electric trains replaced steam engines making journeys cleaner and faster.","Today the London Underground carries over a billion passengers every single year."]'),
('ingles', 'bachillerato', '{1}', '["A family decided to spend their holidays exploring the national parks of Scotland.","They rented a small camper van and packed maps boots and warm clothes.","During the trip they hiked through forests lochs and ancient stone ruins.","They met local people who told them stories about Scottish history and traditions.","After two weeks they returned home with hundreds of photos and great memories."]'),
('ingles', 'bachillerato', '{1}', '["The internet was originally developed as a military communication network in the 1960s.","Universities later joined the network to share research and academic resources.","In 1989 Tim Berners-Lee invented the World Wide Web at CERN in Switzerland.","During the 1990s personal computers and modems brought the web into millions of homes.","Today the internet connects almost every aspect of human life around the planet."]'),
('ingles', 'bachillerato', '{1}', '["A young chef opened a small restaurant in the historic centre of Edinburgh.","She used local ingredients and traditional recipes from her grandmother.","Word spread quickly and soon the restaurant was full every single night.","A famous food critic wrote a positive review in a national newspaper.","Within two years she was awarded her first prestigious culinary distinction."]'),
('ingles', 'bachillerato', '{1}', '["Jane Austen was born in 1775 in a small English village in Hampshire.","She started writing novels at a young age inspired by everyday life.","Her novel Pride and Prejudice was published anonymously in the year 1813.","Her stories explore love marriage and the role of women in Georgian society.","Today she is considered one of the greatest novelists in English literature."]'),
('ingles', 'bachillerato', '{1}', '["A scientist studied the migration patterns of monarch butterflies in North America.","She tagged thousands of butterflies with tiny labels to track their long journey.","The butterflies travelled from Canada to central Mexico over several months.","Her research revealed previously unknown stops along the migration route.","The findings helped conservationists protect the habitats these insects depend on."]'),
('ingles', 'bachillerato', '{1}', '["A Spanish student decided to spend a year studying in Dublin under Erasmus.","He had to look for accommodation and open a bank account on arrival.","At first he struggled with the local accent and the rainy weather.","He gradually made friends and improved his English in everyday situations.","By the end of the year he felt at home and decided to stay longer."]'),
('ingles', 'bachillerato', '{1}', '["The construction of the Panama Canal started at the very beginning of the twentieth century.","Thousands of workers struggled against tropical diseases and difficult terrain.","Engineers designed massive locks to lift ships across the central mountain range.","The canal opened in 1914 dramatically reducing the distance between two oceans.","Today it remains one of the most important shipping routes in international trade."]'),
('ingles', 'bachillerato', '{1}', '["A teenager noticed that her elderly neighbour rarely received any visitors at home.","She started visiting him every afternoon to chat and bring fresh groceries.","The old man told her fascinating stories about his youth during wartime.","She decided to record his memories and write them down in a small notebook.","Later she published the stories online and many readers were deeply moved."]'),
('ingles', 'bachillerato', '{1}', '["Marie Curie was born in Poland and moved to Paris to study physics.","She married Pierre Curie and together they investigated mysterious radioactive elements.","They discovered polonium and radium working in extremely difficult laboratory conditions.","Marie became the first woman to win a Nobel Prize in the year 1903.","She later won a second Nobel Prize this time in the field of chemistry."]'),
('ingles', 'bachillerato', '{1}', '["A photographer decided to document the daily life of fishermen on a remote island.","He spent six months living with a small community on the windy coast.","He learned how to repair nets and prepare boats for early morning trips.","His photographs captured the harsh beauty of life by the cold sea.","His exhibition in the capital attracted thousands of visitors and critical praise."]'),
('ingles', 'bachillerato', '{1}', '["The Statue of Liberty was a gift from France to the United States in 1886.","It was designed by sculptor Frédéric Bartholdi and engineer Gustave Eiffel.","The statue was shipped across the Atlantic Ocean in over two hundred crates.","It was assembled on a small island in New York harbour over several months.","Since then it has welcomed millions of immigrants arriving by sea to America."]'),
('ingles', 'bachillerato', '{1}', '["A local council decided to transform an abandoned factory into a cultural centre.","Architects designed a modern building preserving the original brick walls.","The renovation took two years and required careful planning and significant funding.","The new centre included galleries a library and rooms for music workshops.","On the opening day hundreds of citizens visited and celebrated the transformation."]'),
('ingles', 'bachillerato', '{1}', '["Charles Darwin sailed around the world aboard the HMS Beagle in 1831.","During the voyage he observed many different plants animals and geological formations.","On the Galapagos Islands he noticed small differences between birds on each island.","Years later he published On the Origin of Species explaining natural selection.","His revolutionary theory completely transformed our understanding of life on Earth."]'),
('ingles', 'bachillerato', '{1}', '["A young inventor designed a portable water filter for use in remote villages.","He tested several prototypes using locally available and inexpensive materials.","His final design could clean enough water for a family for a whole week.","He travelled to Africa to distribute the filters in communities without clean water.","His project won an international award for sustainable engineering and humanitarian impact."]'),
('ingles', 'bachillerato', '{1}', '["Walt Disney started his career as a young cartoonist in Kansas City.","He moved to Hollywood and produced his first successful animated short films.","In 1928 he created Mickey Mouse who quickly became a worldwide icon.","Years later he opened his first theme park in California in 1955.","His company has since become one of the largest entertainment empires in history."]'),
('ingles', 'bachillerato', '{1}', '["A group of students organized a debate competition about climate change in their school.","They invited experts to give short talks about renewable energy and recycling.","Each team prepared arguments for and against various environmental policies.","The final debate took place in front of parents teachers and local journalists.","After the event the school decided to install solar panels on the roof."]'),
('ingles', 'bachillerato', '{1}', '["Florence Nightingale was a British nurse during the Crimean War in the 1850s.","She introduced strict hygiene practices in military hospitals reducing mortality drastically.","She was nicknamed the Lady with the Lamp because of her night rounds.","After the war she founded the first modern school for professional nurses.","Her reforms transformed nursing into a respected and scientific medical profession."]'),
('ingles', 'bachillerato', '{1}', '["A small startup developed a mobile app to help people learn foreign languages.","The app used short games and daily challenges to keep users motivated.","Within a year it had over a million downloads in dozens of countries.","Major investors offered funding to expand the team and add new languages.","Today the app is used by students teachers and travellers all over the world."]'),
('ingles', 'bachillerato', '{1}', '["The Great Wall of China was built over many centuries by different dynasties.","Its main purpose was to protect the empire from invasions from the north.","Thousands of soldiers and peasants worked under extremely harsh conditions.","The wall stretches for thousands of kilometres across deserts and mountain ranges.","Today it is a symbol of Chinese history and a major tourist attraction."]'),
('ingles', 'bachillerato', '{1}', '["A teacher organized an exchange programme between her school and a Japanese institute.","Spanish students travelled to Tokyo for two weeks of cultural immersion.","They lived with local families and attended traditional classes every morning.","They learned about Japanese customs cuisine calligraphy and modern technology.","The experience created lasting friendships and a passion for international exchange."]'),
('ingles', 'bachillerato', '{1}', '["Mahatma Gandhi led the nonviolent movement for Indian independence from Britain.","He encouraged peaceful protests boycotts and acts of civil disobedience.","His famous Salt March in 1930 inspired millions of Indians to join the cause.","After years of struggle India finally gained its independence in August 1947.","Gandhi remains a global symbol of peace tolerance and nonviolent resistance."]'),
('ingles', 'bachillerato', '{1}', '["A girl from a small village dreamed of becoming a professional violinist.","Her parents could not afford lessons but a kind neighbour offered to teach her.","She practised every day after school for several long and patient years.","At sixteen she won a national competition and received a music scholarship.","Today she performs with one of the finest orchestras in Europe."]'),
('ingles', 'bachillerato', '{1}', '["The Olympic Games were originally held in ancient Greece every four years.","Athletes competed in running wrestling chariot racing and other physical events.","The modern Olympics were revived in Athens in the year 1896.","Since then the games have grown to include thousands of athletes worldwide.","The Olympic spirit continues to celebrate excellence friendship and fair competition."]'),
('ingles', 'bachillerato', '{1}', '["A research team studied the effects of music on people suffering from anxiety.","They selected hundreds of volunteers to participate in a controlled experiment.","The volunteers listened to classical music for thirty minutes every single day.","After eight weeks most participants reported significant improvements in their mood.","The findings were published in a respected medical journal and attracted wide attention."]'),
('ingles', 'bachillerato', '{1}', '["Neil Armstrong joined the United States Navy and trained as a fighter pilot.","He later became a test pilot and then joined the NASA astronaut programme.","On July 20 1969 he became the first human being to walk on the Moon.","His famous words about a small step were broadcast to millions worldwide.","His historic mission marked a major milestone in the conquest of space."]'),
('ingles', 'bachillerato', '{1}', '["A young entrepreneur opened a small bookshop specialised in second-hand novels.","She organized weekly reading clubs and storytelling events for local children.","The shop quickly became a meeting place for writers students and book lovers.","She started publishing local authors who could not find traditional publishers.","Within five years her small initiative had grown into a thriving cultural project."]'),
('ingles', 'bachillerato', '{1}', '["The Roman Empire reached its greatest territorial extent under Emperor Trajan.","It covered most of Europe parts of Africa and the Middle East.","Roman engineers built impressive roads aqueducts and amphitheatres across the empire.","Latin became the common language uniting people from very different cultures.","The empire eventually collapsed but its legacy still shapes Western civilization today."]'),
('ingles', 'bachillerato', '{1}', '["A high school student became interested in beekeeping after watching a documentary.","His grandfather helped him build his first wooden hive in the garden.","He learned about the role of bees in pollination and food production.","After a year his hive produced its first jars of golden delicious honey.","He started giving talks at school about the importance of protecting bees."]'),
('ingles', 'bachillerato', '{1}', '["Nelson Mandela spent twenty-seven years in prison fighting against apartheid in South Africa.","He was released in 1990 and continued negotiations for a peaceful democratic transition.","In 1994 he was elected the first black president in the history of his country.","He worked tirelessly to promote reconciliation between different racial communities.","His example of forgiveness and leadership inspired people all around the world."]'),
('ingles', 'bachillerato', '{1}', '["A meteorologist analysed satellite data to predict an approaching tropical storm.","She warned coastal communities to evacuate before the dangerous storm arrived.","Local authorities organized buses and shelters for thousands of vulnerable residents.","The hurricane struck the coast with strong winds and heavy torrential rain.","Thanks to the early warning casualties were significantly lower than expected."]'),
('ingles', 'bachillerato', '{1}', '["The London Olympic Games of 2012 attracted athletes from over two hundred countries.","Organizers built impressive new venues in a previously neglected industrial area.","The opening ceremony celebrated British history culture and creative imagination.","Athletes broke many world records during seventeen days of intense competition.","The games left a positive legacy of urban regeneration and sporting inspiration."]'),
('ingles', 'bachillerato', '{1}', '["A teenager discovered a rare fossil while walking on a beach in Dorset.","She carefully photographed the fossil before contacting a local museum specialist.","Experts confirmed that the bones belonged to a previously unknown marine reptile.","The fossil was excavated and transported to a research centre for analysis.","Her discovery contributed valuable new information to the field of palaeontology."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ingles', 'bachillerato', '{2}', '["The author begins the essay by introducing a controversial thesis about social media.","She develops several arguments supported by recent statistics and academic sources.","She acknowledges counterarguments before refuting them with logical reasoning and evidence.","She concludes by suggesting practical solutions for individuals and policy makers.","The essay ends with a powerful call to action urging readers to reflect."]'),
('ingles', 'bachillerato', '{2}', '["George Orwell published his dystopian novel Nineteen Eighty-Four in 1949.","The story takes place in a totalitarian state ruled by the mysterious Big Brother.","The protagonist Winston Smith secretly questions the official propaganda and surveillance.","His doomed love affair with Julia leads to capture torture and ideological betrayal.","The novel remains a powerful warning against authoritarian control of information and thought."]'),
('ingles', 'bachillerato', '{2}', '["A linguist conducted a study on how children acquire their first language.","She recorded hours of natural conversation between toddlers and their caregivers.","She analysed the data identifying specific patterns in vocabulary and grammatical development.","Her findings showed striking similarities across different cultures and language families.","The research has important implications for early education and speech therapy.","The conclusions were widely cited in subsequent academic publications."]'),
('ingles', 'bachillerato', '{2}', '["William Shakespeare wrote Macbeth around the year 1606 during the Jacobean era.","The tragedy explores themes of ambition guilt and supernatural intervention in human affairs.","Three witches predict that Macbeth will become the future king of Scotland.","Encouraged by his ruthless wife he murders King Duncan and seizes the throne.","His tyranny leads to madness rebellion and ultimately his violent downfall."]'),
('ingles', 'bachillerato', '{2}', '["A journalist investigated allegations of corruption in a major construction company.","She interviewed dozens of former employees and obtained confidential internal documents.","Her detailed report revealed systematic bribery involving several local government officials.","The article was published on the front page of a leading national newspaper.","The investigation led to legal proceedings and significant political consequences."]'),
('ingles', 'bachillerato', '{2}', '["Charles Dickens grew up in poverty after his father was sent to debtors prison.","As a child he worked in a factory pasting labels onto bottles of polish.","These early experiences shaped his social conscience and his powerful literary themes.","He became a successful novelist publishing works like Oliver Twist and Great Expectations.","His novels exposed the harsh realities of Victorian society and inspired social reform."]'),
('ingles', 'bachillerato', '{2}', '["The professor introduces the topic of artificial intelligence in his opening lecture.","He explains the main differences between supervised and unsupervised learning algorithms.","He illustrates the concepts with practical examples from medicine and finance.","He warns students about the ethical challenges raised by automated decision making.","Finally he encourages a class discussion on the future of human work."]'),
('ingles', 'bachillerato', '{2}', '["Mary Shelley wrote Frankenstein when she was only nineteen years old.","The novel tells the story of a scientist who creates life from dead matter.","The creature feels rejected and abandoned by his ambitious and irresponsible creator.","His desperate search for acceptance ends in violence vengeance and deep tragedy.","The book is considered one of the first works of modern science fiction."]'),
('ingles', 'bachillerato', '{2}', '["A research team analysed the long term effects of bilingual education on children.","They followed hundreds of students over a period of several years.","The bilingual children showed greater cognitive flexibility and better problem solving skills.","They also demonstrated improved attention control and memory in standardized tests.","The findings support the introduction of bilingual programmes in early childhood education."]'),
('ingles', 'bachillerato', '{2}', '["Jane Austen subtly criticised the limited options available to women in her time.","Her novel Pride and Prejudice introduces the witty and independent Elizabeth Bennet.","Elizabeth initially rejects the proud Mr Darcy because of his arrogant manners.","Through misunderstandings and revelations both characters overcome their personal flaws.","Their eventual marriage represents the triumph of mutual respect and emotional honesty."]'),
('ingles', 'bachillerato', '{2}', '["Globalization has dramatically transformed international trade over the last few decades.","Multinational companies now produce goods in many countries to reduce manufacturing costs.","Workers in developing nations often face very low wages and poor conditions.","Critics argue that globalization increases inequality between rich and developing countries.","Supporters claim it has lifted millions of people out of extreme poverty."]'),
('ingles', 'bachillerato', '{2}', '["Virginia Woolf was a leading figure of the modernist literary movement in Britain.","She experimented with stream of consciousness narration in novels like Mrs Dalloway.","Her essay A Room of Ones Own argues for womens intellectual independence.","She co-founded the Hogarth Press publishing innovative works by emerging writers.","Her struggles with mental illness eventually led to her tragic suicide in 1941."]'),
('ingles', 'bachillerato', '{2}', '["A scientist developed a new method for detecting plastic particles in ocean water.","She published her preliminary findings in a peer reviewed environmental journal.","Other researchers replicated her experiments confirming the validity of the new technique.","The method was adopted by international organizations to monitor marine pollution levels.","Her work has contributed significantly to global awareness of microplastic contamination."]'),
('ingles', 'bachillerato', '{2}', '["The Great Gatsby by F Scott Fitzgerald is set in the Roaring Twenties.","Jay Gatsby a mysterious millionaire throws lavish parties at his Long Island mansion.","His true motivation is to win back his lost love Daisy Buchanan.","The novel explores the corruption of the American Dream through wealth and obsession.","Gatsbys tragic death symbolizes the failure of his romantic illusions and ambitions."]'),
('ingles', 'bachillerato', '{2}', '["A historian examined newly declassified documents about the Cold War in Europe.","She discovered evidence of secret negotiations between American and Soviet diplomats.","Her analysis challenged the traditional interpretation of several major historical events.","She published her findings in a highly acclaimed academic monograph.","The book sparked an intense debate among scholars and political commentators."]'),
('ingles', 'bachillerato', '{2}', '["Oscar Wilde was a celebrated playwright and wit in late Victorian London.","His witty comedies satirized the hypocrisy of the British upper classes.","His novel The Picture of Dorian Gray explored themes of beauty and moral corruption.","After a scandalous trial he was imprisoned for two years of hard labour.","He died in poverty in Paris but his literary legacy remains influential."]'),
('ingles', 'bachillerato', '{2}', '["The student prepares an essay on the causes of the French Revolution.","She begins by reading several scholarly sources from the school library.","She drafts an outline organizing her main arguments into clear paragraphs.","She writes the essay carefully developing each idea with relevant evidence.","Finally she revises the text checking grammar coherence and academic referencing."]'),
('ingles', 'bachillerato', '{2}', '["Emily Bronte published her only novel Wuthering Heights in the year 1847.","The story takes place in the wild Yorkshire moors of northern England.","It follows the passionate and destructive love between Catherine and Heathcliff.","Their tragic relationship affects two generations of two intertwined families.","The novel is now considered a masterpiece of English Romantic literature."]'),
('ingles', 'bachillerato', '{2}', '["The economist analysed the impact of automation on the global labour market.","She gathered statistics from dozens of industries across many different countries.","Her research showed that routine jobs were the most vulnerable to replacement.","She proposed policies to help workers adapt through retraining and education programmes.","Her recommendations influenced labour reforms in several European governments."]'),
('ingles', 'bachillerato', '{2}', '["Harper Lee published her novel To Kill a Mockingbird in the year 1960.","The story is narrated through the eyes of a young girl named Scout.","Her father Atticus Finch defends a black man falsely accused of a crime.","The trial exposes the deep racism and injustice in the southern United States.","The novel became a powerful symbol of the civil rights movement in America."]'),
('ingles', 'bachillerato', '{2}', '["A psychologist studied how stress affects academic performance in university students.","She designed an experiment involving questionnaires interviews and physiological measurements.","Her results showed a clear correlation between high stress and lower exam grades.","She suggested mindfulness and time management techniques as effective coping strategies.","The university implemented her recommendations across all undergraduate degree programmes."]'),
('ingles', 'bachillerato', '{2}', '["Ernest Hemingway developed a distinctive minimalist style of literary prose.","He worked as a journalist before publishing his first major novel.","His experiences in the Spanish Civil War inspired For Whom the Bell Tolls.","He won the Nobel Prize for Literature in the year 1954.","His direct economic style influenced generations of writers throughout the twentieth century."]'),
('ingles', 'bachillerato', '{2}', '["A team of biologists studied the population decline of bees in rural Europe.","They identified pesticides habitat loss and disease as the main contributing factors.","They proposed concrete measures to protect pollinators in agricultural landscapes.","Their report was sent to the European Parliament for legislative consideration.","Several countries soon adopted new restrictions on harmful agricultural chemicals."]'),
('ingles', 'bachillerato', '{2}', '["Aldous Huxley published his dystopian novel Brave New World in 1932.","The story is set in a future society obsessed with technology and consumption.","Citizens are conditioned from birth to accept their predetermined social roles.","A character named John questions the loss of individuality and authentic emotion.","The novel raises enduring questions about freedom progress and human dignity."]'),
('ingles', 'bachillerato', '{2}', '["A philosopher examined the ethical implications of genetic engineering in humans.","He reviewed arguments from scientists religious leaders and political activists.","He analysed historical examples of similar debates about emerging technologies.","He concluded that society needs strict regulation alongside open public discussion.","His book became a key reference in the field of bioethics."]'),
('ingles', 'bachillerato', '{2}', '["Toni Morrison was the first African American woman to win the Nobel Prize.","Her novel Beloved tells the story of a former slave haunted by memories.","The novel uses fragmented narrative and lyrical prose to convey trauma.","Her work explores the legacy of slavery and racism in American history.","Morrison received numerous honours and remains one of the great voices of literature."]'),
('ingles', 'bachillerato', '{2}', '["A reporter investigated the rise of fake news on social media platforms.","She traced misleading articles back to coordinated networks of anonymous accounts.","Her investigation revealed how foreign actors influenced political opinions abroad.","She published a series of articles exposing the techniques used by these networks.","Her work led to new policies and stricter content moderation by social platforms."]'),
('ingles', 'bachillerato', '{2}', '["The poet T S''Eliot moved from America to England in the year 1914.","He published The Waste Land in 1922 a complex and fragmented modernist poem.","The poem reflects the disillusionment of European society after the First World War.","Eliot used multiple voices languages and literary references throughout the text.","He won the Nobel Prize for Literature in the year 1948."]'),
('ingles', 'bachillerato', '{2}', '["A doctor conducted a clinical trial of a new treatment for diabetes.","Patients were divided randomly into a control group and a treatment group.","The trial lasted two years and included regular medical examinations and blood tests.","The new treatment reduced blood sugar levels significantly with fewer side effects.","The results were published and the treatment was approved for widespread use."]'),
('ingles', 'bachillerato', '{2}', '["Margaret Atwood published The Handmaids Tale in the year 1985.","The novel imagines a future theocratic regime that strips women of their rights.","The protagonist Offred narrates her daily life as a forced reproductive servant.","The story explores themes of patriarchy religious extremism and personal resistance.","The novel was later adapted into a successful and award winning television series."]'),
('ingles', 'bachillerato', '{2}', '["A team of engineers designed an electric car prototype with extended battery range.","They tested the vehicle in extreme weather conditions across several countries.","Their innovative design used recycled materials and energy efficient components.","The prototype was presented at a major international motor show in Germany.","Several manufacturers expressed interest in licensing the new technology for production."]'),
('ingles', 'bachillerato', '{2}', '["Samuel Beckett was an Irish playwright who wrote in both English and French.","His play Waiting for Godot premiered in Paris in the year 1953.","The play features two characters waiting endlessly for a mysterious Godot.","Critics consider it a defining work of the Theatre of the Absurd movement.","Beckett received the Nobel Prize for Literature in the year 1969."]'),
('ingles', 'bachillerato', '{2}', '["A scientist discovered a new species of frog in the Amazon rainforest.","She described its unique colouration vocalizations and reproductive habits in detail.","Her discovery highlighted the urgent need to protect tropical biodiversity.","She campaigned to create a protected area where the new species lives.","Her efforts led to international funding for rainforest conservation programmes."]'),
('ingles', 'bachillerato', '{2}', '["James Joyce was an Irish modernist writer born in Dublin in 1882.","His novel Ulysses published in 1922 retells Homers Odyssey in modern Dublin.","He used innovative narrative techniques including stream of consciousness and inner monologue.","His work was initially controversial and even banned in several countries.","Today he is regarded as one of the most influential writers in English literature."]'),
('ingles', 'bachillerato', '{2}', '["A historian wrote a book about the role of women during the Second World War.","She gathered personal letters diaries and oral testimonies from survivors and their descendants.","She described how women took on factory jobs traditionally reserved for men.","Her account challenged the traditional male centred narrative of the conflict.","The book received critical acclaim and was translated into several languages."]'),
('ingles', 'bachillerato', '{2}', '["John Steinbeck published The Grapes of Wrath in the year 1939.","The novel follows the Joad family migrating from Oklahoma during the Dust Bowl.","It depicts the suffering and resilience of poor farmers during the Great Depression.","The book was both praised for its social criticism and condemned by conservatives.","Steinbeck received the Nobel Prize for Literature in the year 1962."]'),
('ingles', 'bachillerato', '{2}', '["A researcher analysed the influence of advertising on adolescent eating habits.","She conducted interviews with hundreds of teenagers in different European countries.","Her data revealed that exposure to junk food adverts increased unhealthy snacking.","She recommended stricter regulations on food advertising aimed at young viewers.","Several countries adopted her recommendations within their public health policies."]'),
('ingles', 'bachillerato', '{2}', '["The Romantic poets reacted against the rationalism of the eighteenth century.","Wordsworth and Coleridge published the Lyrical Ballads in the year 1798.","They celebrated nature emotion imagination and the experiences of ordinary people.","Later Romantic poets included Byron Shelley and the young John Keats.","Their innovations transformed English poetry and influenced generations of writers."]'),
('ingles', 'bachillerato', '{2}', '["A nutritionist designed a balanced diet plan for a group of elite athletes.","She analysed the specific nutritional needs of each sport and physical demand.","She created weekly menus including the proper amounts of proteins and carbohydrates.","She monitored the athletes performance and adjusted the diet according to results.","Her plan helped the team improve endurance recovery and overall competitive performance."]'),
('ingles', 'bachillerato', '{2}', '["The novelist Kazuo Ishiguro was born in Japan but raised in England.","His novel The Remains of the Day examines the life of an English butler.","Through subtle narration the protagonist reveals his repressed emotions and missed opportunities.","The novel won the Booker Prize and was later adapted into a successful film.","Ishiguro received the Nobel Prize for Literature in the year 2017."]'),
('ingles', 'bachillerato', '{2}', '["A team of archaeologists excavated a Roman site in northern England.","They discovered well preserved mosaics coins and fragments of pottery.","Their findings shed new light on daily life in the Roman frontier provinces.","The artefacts were carefully cleaned catalogued and transported to a regional museum.","The excavation provided valuable data for understanding Roman provincial society."]'),
('ingles', 'bachillerato', '{2}', '["Doris Lessing was a British writer born in Persia and raised in Africa.","Her novel The Golden Notebook published in 1962 explored female identity and freedom.","The book combined experimental narrative techniques with sharp political commentary.","Lessing wrote prolifically across novels short stories essays and science fiction.","She received the Nobel Prize for Literature in the year 2007."]'),
('ingles', 'bachillerato', '{2}', '["A computer scientist developed a new encryption algorithm for secure communications.","She tested the algorithm against various known cryptographic attack methods.","The algorithm proved resistant to even the most sophisticated decryption attempts.","She published her findings in a top international cybersecurity conference.","Her work contributed significantly to advancing digital privacy and online safety."]'),
('ingles', 'bachillerato', '{2}', '["The student begins her oral presentation by introducing the topic clearly.","She supports her arguments with statistics graphs and credible academic references.","She maintains steady eye contact and uses appropriate body language throughout.","She handles unexpected questions from the audience with confidence and clarity.","Her professor congratulates her on the structure delivery and persuasive content."]'),
('ingles', 'bachillerato', '{2}', '["Salman Rushdie was born in India and educated in England as a young scholar.","His novel Midnights Children won the Booker Prize in the year 1981.","His later novel The Satanic Verses provoked international controversy and threats.","He spent years in hiding under police protection following religious death threats.","Rushdie continued writing and remains a major voice in postcolonial literature."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('frances', 'bachillerato', '{1}', '["Pierre a décidé de partir étudier à Lyon pour suivre des cours d''ingénierie.","Il a cherché un appartement près de l''université et a signé un contrat de location.","Pendant les premières semaines il a découvert la ville et rencontré ses camarades.","Il a participé à de nombreuses activités sportives et culturelles proposées par la fac.","À la fin du semestre il avait obtenu d''excellentes notes dans toutes les matières."]'),
('frances', 'bachillerato', '{1}', '["Louis Pasteur est né en 1822 dans une petite ville de l''est de la France.","Il a étudié la chimie et a découvert l''existence des micro-organismes dans l''air.","Il a inventé le procédé de pasteurisation pour conserver les aliments plus longtemps.","Il a aussi développé le premier vaccin contre la rage en 1885.","Ses découvertes ont sauvé des millions de vies à travers le monde entier."]'),
('frances', 'bachillerato', '{1}', '["Une jeune chef a ouvert un petit restaurant dans le centre historique de Bordeaux.","Elle a choisi des produits locaux et de saison pour composer ses plats originaux.","Très vite la presse gastronomique locale a fait l''éloge de sa cuisine inventive.","Le restaurant est devenu très populaire et il fallait réserver longtemps à l''avance.","Trois ans plus tard elle a obtenu sa première étoile au célèbre guide Michelin."]'),
('frances', 'bachillerato', '{1}', '["La tour Eiffel a été construite pour l''Exposition universelle de Paris en 1889.","Gustave Eiffel et son équipe ont travaillé pendant plus de deux ans sur le projet.","Beaucoup de Parisiens critiquaient ce monument métallique qu''ils trouvaient laid.","Aujourd''hui la tour est devenue le symbole le plus connu de la France.","Elle reçoit chaque année des millions de visiteurs venus du monde entier."]'),
('frances', 'bachillerato', '{1}', '["Sophie a toujours aimé les animaux depuis sa plus tendre enfance.","Après le bac elle a décidé de s''inscrire à l''école vétérinaire de Toulouse.","Pendant ses études elle a effectué des stages dans plusieurs cliniques de campagne.","Elle a obtenu son diplôme avec mention et s''est installée en zone rurale.","Elle soigne désormais les animaux d''une vingtaine de fermes de sa région."]'),
('frances', 'bachillerato', '{1}', '["Une association de quartier a décidé de nettoyer les rives du fleuve voisin.","Elle a lancé un appel à bénévoles via les réseaux sociaux et la presse locale.","Le samedi suivant plus de cent personnes se sont retrouvées avec des sacs.","Elles ont ramassé des centaines de kilos de déchets plastiques et de bouteilles.","La mairie a félicité l''initiative et promis d''installer de nouvelles poubelles."]'),
('frances', 'bachillerato', '{1}', '["Le métro parisien a été inauguré en juillet 1900 lors de l''Exposition universelle.","Sa première ligne reliait Porte Maillot à Porte de Vincennes en moins d''une heure.","Les Parisiens ont rapidement adopté ce nouveau moyen de transport souterrain rapide.","Le réseau s''est ensuite étendu pour couvrir toute la capitale et sa banlieue.","Aujourd''hui le métro transporte plus de quatre millions de voyageurs chaque jour."]'),
('frances', 'bachillerato', '{1}', '["Un photographe a voulu documenter la vie quotidienne des pêcheurs bretons.","Il a passé six mois dans un petit port de la côte atlantique sauvage.","Il a appris à réparer les filets et à préparer les bateaux avant le départ.","Ses photos ont saisi la dureté et la beauté de cette vie maritime.","Son exposition à Paris a attiré des milliers de visiteurs et de critiques élogieuses."]'),
('frances', 'bachillerato', '{1}', '["Marie Curie est arrivée à Paris en 1891 pour étudier les sciences à la Sorbonne.","Elle a rencontré Pierre Curie et ils se sont mariés quelques années plus tard.","Ensemble ils ont découvert deux nouveaux éléments radioactifs très''importants.","Marie a reçu le prix Nobel de physique en 1903 puis celui de chimie en 1911.","Elle est la première personne à avoir reçu deux prix Nobel dans des domaines différents."]'),
('frances', 'bachillerato', '{1}', '["Une jeune lycéenne s''est passionnée pour l''astronomie après''avoir vu un documentaire.","Elle a participé à un club d''observation et a appris à utiliser un télescope.","Son professeur lui a conseillé de présenter un projet à un concours national.","Elle a passé des mois à préparer son étude sur les exoplanètes lointaines.","Elle a remporté le premier prix et obtenu une bourse pour étudier les sciences."]'),
('frances', 'bachillerato', '{1}', '["Coco Chanel est née en 1883 dans une famille pauvre du sud-ouest français.","Elle a commencé sa carrière comme couturière dans un petit atelier de Paris.","Elle a révolutionné la mode féminine en libérant les femmes du corset rigide.","Sa célèbre petite robe noire est devenue un symbole intemporel de l''élégance.","La maison Chanel reste aujourd''hui l''une des marques de luxe les plus prestigieuses."]'),
('frances', 'bachillerato', '{1}', '["Un groupe d''élèves a organisé un échange linguistique avec un lycée allemand.","Ils ont préparé le voyage pendant plusieurs mois avec leur professeur de langue.","Pendant deux semaines chaque élève français a vécu chez une famille d''accueil.","Ils ont assisté aux cours et découvert la culture et la cuisine locales.","De solides amitiés sont nées et plusieurs ont continué à correspondre par la suite."]'),
('frances', 'bachillerato', '{1}', '["Le Tour de France a été créé en 1903 par le journal L''Auto pour attirer des lecteurs.","La première édition comptait soixante coureurs sur un parcours de plus de deux mille kilomètres.","La course est rapidement devenue l''événement sportif le plus populaire de France.","Aujourd''hui elle attire des millions de spectateurs sur les routes chaque été.","Le maillot jaune est porté par le coureur en tête du classement général."]'),
('frances', 'bachillerato', '{1}', '["Un ingénieur a conçu un système innovant pour récupérer l''eau de pluie.","Il a testé son prototype dans plusieurs maisons de son village natal.","Le système permettait d''économiser jusqu''à la moitié de la consommation habituelle.","Il a obtenu un brevet et créé sa propre entreprise pour commercialiser l''invention.","Aujourd''hui son produit est utilisé dans des milliers de foyers à travers l''Europe."]'),
('frances', 'bachillerato', '{1}', '["Le cinéma a été inventé par les frères Lumière à Lyon à la fin du XIXe siècle.","Ils ont organisé la première projection publique payante à Paris en décembre 1895.","Le public était fasciné par les images en mouvement projetées sur le grand écran.","Très rapidement le cinéma s''est répandu dans toute l''Europe et le monde entier.","Cette invention a marqué le début d''une nouvelle forme d''art populaire."]'),
('frances', 'bachillerato', '{1}', '["Une agricultrice a converti son exploitation familiale à l''agriculture biologique.","Elle a cessé d''utiliser des pesticides et engrais chimiques sur ses cultures.","Pendant les premières années les rendements ont baissé et elle a connu des difficultés.","Petit à petit ses produits ont trouvé une clientèle fidèle dans les marchés locaux.","Sa ferme est devenue un modèle pour d''autres agriculteurs de la région."]'),
('frances', 'bachillerato', '{1}', '["Antoine de Saint-Exupéry était à la fois écrivain et pilote d''avion.","Il a volé pour l''Aéropostale au-dessus du désert du Sahara et de l''Amérique du Sud.","Il a écrit Le Petit Prince pendant son exil aux États-Unis pendant la guerre.","Le livre est devenu l''un des plus traduits et lus au monde.","Il a disparu en mission de reconnaissance au-dessus de la Méditerranée en 1944."]'),
('frances', 'bachillerato', '{1}', '["Une équipe de chercheurs a étudié les effets de la musique sur la mémoire.","Ils ont sélectionné des centaines de volontaires âgés pour participer à l''expérience.","Les participants écoutaient de la musique classique pendant leurs séances d''apprentissage.","Les résultats ont montré une amélioration nette de la mémoire à long terme.","L''étude a été publiée dans une revue scientifique internationale très reconnue."]'),
('frances', 'bachillerato', '{1}', '["Le château de Versailles a été construit sous le règne de Louis XIV.","L''architecte Louis Le Vau et le jardinier André Le Nôtre ont dirigé le projet.","Le roi a installé sa cour à Versailles en 1682 pour mieux contrôler la noblesse.","Le palais comporte des centaines de pièces et des jardins immenses et magnifiques.","Aujourd''hui le château reçoit des millions de touristes venus du monde entier."]'),
('frances', 'bachillerato', '{1}', '["Un jeune écrivain a passé deux ans à rédiger son premier roman historique.","Il a fait des recherches approfondies dans les archives municipales et nationales.","Plusieurs éditeurs ont d''abord refusé son manuscrit avant qu''un petit éditeur l''accepte.","Le livre a obtenu un prix littéraire et a connu un grand succès commercial.","Aujourd''hui il vit de sa plume et publie un roman tous les deux ans."]'),
('frances', 'bachillerato', '{1}', '["L''impressionnisme est né en France à la fin du XIXe siècle.","Des peintres comme Monet Renoir et Degas ont rompu avec la tradition académique.","Ils ont peint en plein air pour saisir la lumière et les couleurs changeantes.","Leur première exposition collective a eu lieu à Paris en avril 1874.","Ce mouvement a profondément transformé l''histoire de la peinture occidentale."]'),
('frances', 'bachillerato', '{1}', '["Une pédiatre a ouvert un centre médical gratuit dans un quartier défavorisé.","Elle voulait offrir des soins à toutes les familles sans ressources financières.","Au début elle travaillait seule avec quelques bénévoles dans un local modeste.","De nombreux médecins et infirmiers ont rejoint son projet au fil des années.","Le centre soigne aujourd''hui des centaines d''enfants chaque mois sans frais."]'),
('frances', 'bachillerato', '{1}', '["La gastronomie française a été inscrite au patrimoine de l''UNESCO en 2010.","Cette reconnaissance célèbre l''art du repas comme pratique sociale et culturelle.","Le repas gastronomique réunit famille et amis autour de plats préparés''avec soin.","Il comporte généralement un apéritif une entrée un plat principal du fromage et un dessert.","Cette tradition se transmet de génération en génération dans toutes les régions."]'),
('frances', 'bachillerato', '{1}', '["Un astronome amateur a observé un objet lumineux inhabituel dans le ciel nocturne.","Il a photographié le phénomène et envoyé ses images à un observatoire professionnel.","Les experts ont confirmé qu''il s''agissait d''une comète jusque-là inconnue.","La nouvelle comète a reçu le nom de son découvreur selon la tradition astronomique.","Il a donné des conférences dans des écoles pour partager sa passion avec les jeunes."]'),
('frances', 'bachillerato', '{1}', '["La cathédrale Notre-Dame de Paris a commencé à être construite en 1163.","Sa construction a duré près de deux siècles à travers plusieurs générations de bâtisseurs.","Pendant des siècles elle a été le cœur religieux et culturel de la capitale.","Un terrible incendie a ravagé sa toiture et sa flèche en avril 2019.","Les travaux de restauration ont mobilisé des centaines d''artisans pour la reconstruire."]'),
('frances', 'bachillerato', '{1}', '["Une lycéenne a remarqué qu''une voisine âgée vivait seule sans famille proche.","Elle a commencé à lui rendre visite tous les jours après les cours.","Elle l''aidait pour les courses et écoutait les histoires de sa jeunesse.","Une vraie amitié s''est créée entre les deux femmes malgré leur différence d''âge.","Cette expérience a inspiré la lycéenne à devenir aide-soignante après le bac."]'),
('frances', 'bachillerato', '{1}', '["Le philosophe René Descartes est né en France en 1596.","Il a étudié la philosophie et les mathématiques au collège des Jésuites.","Il a écrit son célèbre Discours de la méthode publié en 1637.","Sa formule Je pense donc je suis est devenue l''une des phrases les plus citées.","Il est considéré comme le fondateur de la philosophie moderne occidentale."]'),
('frances', 'bachillerato', '{1}', '["Une jeune danseuse a été admise à l''école de l''Opéra de Paris à dix ans.","Elle a suivi un entraînement intensif quotidien pendant de nombreuses années difficiles.","Elle a participé à plusieurs spectacles avant d''intégrer le corps de ballet.","À vingt-cinq ans elle est devenue première danseuse étoile de l''Opéra national.","Elle a tourné dans le monde entier et inspiré de jeunes danseuses partout."]'),
('frances', 'bachillerato', '{1}', '["Le code civil français a été promulgué par Napoléon Bonaparte en 1804.","Il rassemblait pour la première fois toutes les lois civiles du pays.","Le code a unifié le droit privé entre toutes les régions de France.","Il a servi de modèle pour de nombreux autres pays d''Europe et d''Amérique latine.","Il reste encore aujourd''hui la base du droit civil français contemporain."]'),
('frances', 'bachillerato', '{1}', '["Un boulanger a décidé de revenir aux méthodes traditionnelles de panification.","Il a appris à utiliser le levain naturel et la farine de blés''anciens.","Son pain artisanal a rapidement séduit les habitants de son petit quartier.","Une longue file d''attente se forme désormais chaque matin devant sa boutique.","Il forme de jeunes apprentis pour transmettre son savoir-faire à la génération suivante."]'),
('frances', 'bachillerato', '{1}', '["Jeanne d''Arc est née vers 1412 dans un village de Lorraine.","À dix-sept ans elle a affirmé entendre des voix lui demandant de libérer la France.","Elle a convaincu le roi Charles VII de lui confier une armée militaire.","Elle a libéré Orléans des Anglais et permis le sacre du roi à Reims.","Capturée et brûlée en 1431 elle est devenue une grande figure nationale française."]'),
('frances', 'bachillerato', '{1}', '["Une équipe d''archéologues a découvert des peintures rupestres dans une grotte ardéchoise.","Les peintures représentaient des animaux préhistoriques avec un réalisme étonnant.","Les datations au carbone ont révélé qu''elles avaient plus de trente mille ans.","La grotte a été immédiatement protégée pour préserver ce trésor historique unique.","Une réplique a été ouverte au public pour permettre la visite sans abîmer l''originale."]'),
('frances', 'bachillerato', '{1}', '["Un jeune musicien a appris à jouer de la guitare en autodidacte sur internet.","Il a publié ses premières compositions sur une plateforme de musique en ligne.","Ses chansons ont rapidement été écoutées par des milliers d''auditeurs enthousiastes.","Un producteur l''a contacté pour lui proposer d''enregistrer un véritable album.","Aujourd''hui il fait des tournées dans toute la France et au-delà."]'),
('frances', 'bachillerato', '{1}', '["L''Académie française a été fondée par le cardinal Richelieu en 1635.","Sa mission principale est de veiller sur la pureté de la langue française.","Elle est composée de quarante membres élus à vie appelés les immortels.","L''Académie publie un dictionnaire qui fait autorité dans tout le monde francophone.","Ses séances ont lieu chaque semaine sous la coupole d''un palais parisien."]'),
('frances', 'bachillerato', '{1}', '["Un chercheur a inventé un matériau biodégradable pour remplacer le plastique.","Il a fabriqué le matériau à partir de déchets agricoles bon marché.","Ses tests ont montré que le matériau se décomposait en quelques mois seulement.","Plusieurs entreprises ont signé des contrats pour utiliser sa nouvelle invention écologique.","Son projet a reçu un prix international pour son impact environnemental positif."]'),
('frances', 'bachillerato', '{1}', '["Le Mont-Saint-Michel est un îlot rocheux situé entre la Normandie et la Bretagne.","Une abbaye y a été fondée au VIIIe siècle par l''évêque d''Avranches.","Le site est entouré d''immenses marées qui remontent très rapidement parfois.","Une digue routière a été remplacée par un pont pour préserver les marées naturelles.","Le Mont est inscrit au patrimoine mondial de l''UNESCO depuis 1979."]'),
('frances', 'bachillerato', '{1}', '["Une infirmière a quitté son hôpital pour rejoindre une mission humanitaire en Afrique.","Elle a travaillé dans un camp de réfugiés''où les conditions étaient très difficiles.","Elle soignait les enfants malades et formait du personnel local aux gestes médicaux.","Après deux ans elle est rentrée en France pour témoigner de son expérience.","Elle continue à recueillir des fonds pour soutenir le travail dans le camp."]'),
('frances', 'bachillerato', '{1}', '["Le métro de Lille a été le premier métro entièrement automatique au monde.","Il a été inauguré en avril 1983 après plusieurs années de travaux importants.","Les rames circulent sans conducteur grâce à un système informatique avancé.","Cette innovation française a ensuite été exportée dans plusieurs grandes villes étrangères.","Le réseau s''est progressivement étendu pour desservir toute la métropole lilloise."]'),
('frances', 'bachillerato', '{1}', '["Une enseignante a créé un atelier de théâtre pour ses élèves de seconde.","Elle voulait les aider à prendre confiance en eux et à mieux s''exprimer.","Pendant toute l''année scolaire ils ont préparé une pièce écrite collectivement.","Le spectacle a été présenté devant les familles et le reste du lycée.","Plusieurs élèves timides ont vu leur comportement transformé par cette expérience théâtrale."]'),
('frances', 'bachillerato', '{1}', '["Le TGV a effectué son premier voyage commercial entre Paris et Lyon en 1981.","Il pouvait alors atteindre une vitesse record de deux cent soixante kilomètres par heure.","Le train a réduit le temps de trajet entre les deux villes à deux heures.","Le réseau à grande vitesse s''est ensuite étendu vers toutes les régions françaises.","Aujourd''hui le TGV transporte des millions de passagers chaque année à travers l''Europe."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('frances', 'bachillerato', '{2}', '["Victor Hugo a publié Les Misérables en 1862 après de longues années de travail.","Le roman raconte l''histoire de Jean Valjean ancien forçat en quête de rédemption.","L''oeuvre dénonce les injustices sociales de la France du XIXe siècle.","Le livre a connu un succès''immédiat et international dès sa publication.","Aujourd''hui ce roman reste l''un des chefs-d''oeuvre de la littérature française."]'),
('frances', 'bachillerato', '{2}', '["Albert Camus est né en Algérie française en 1913 dans une famille modeste.","Il a étudié la philosophie à l''université d''Alger malgré ses problèmes de santé.","Il a publié L''Étranger en 1942 un roman emblématique de la philosophie existentialiste.","Son essai Le Mythe de Sisyphe explore l''absurdité de la condition humaine.","Il a reçu le prix Nobel de littérature en 1957 à seulement quarante-quatre ans."]'),
('frances', 'bachillerato', '{2}', '["L''étudiante commence sa dissertation en présentant clairement la problématique du sujet.","Elle développe ensuite une première partie qui analyse la thèse principale du texte.","Dans la deuxième partie elle examine les arguments contraires avec rigueur méthodologique.","Elle propose enfin une synthèse personnelle nuancée et bien argumentée.","Sa conclusion ouvre la réflexion sur des questions plus larges et contemporaines."]'),
('frances', 'bachillerato', '{2}', '["Marcel Proust a commencé à écrire À la recherche du temps perdu en 1908.","Le premier volume Du côté de chez Swann a été publié en 1913.","Le roman explore la mémoire involontaire à travers la fameuse scène de la madeleine.","Proust a consacré le reste de sa vie à compléter cette œuvre monumentale.","Le dernier volume a été publié à titre posthume après la mort de l''auteur."]'),
('frances', 'bachillerato', '{2}', '["Une journaliste a enquêté pendant des mois sur un scandale environnemental majeur.","Elle a interrogé des dizaines de témoins et obtenu des documents internes confidentiels.","Son article révélait la pollution systématique d''une rivière par une grande entreprise.","Le reportage a été publié dans un journal national et a provoqué une polémique.","La justice a ouvert une enquête et l''entreprise a finalement été condamnée."]'),
('frances', 'bachillerato', '{2}', '["Simone de Beauvoir a publié Le Deuxième Sexe en 1949 sous une grande controverse.","Le livre analyse la condition féminine à travers l''histoire la biologie et la psychologie.","Sa célèbre formule On ne naît pas femme on le devient a marqué le féminisme.","L''ouvrage a été initialement censuré et critiqué par les milieux conservateurs traditionnels.","Aujourd''hui il est considéré comme un texte fondateur du féminisme contemporain."]'),
('frances', 'bachillerato', '{2}', '["Jean-Paul Sartre est né à Paris en 1905 dans une famille bourgeoise cultivée.","Il a étudié la philosophie à l''École normale supérieure avec brio remarquable.","Il a développé l''existentialisme à travers des essais romans et pièces de théâtre.","Son ouvrage L''Être et le Néant publié en 1943 a marqué la pensée moderne.","Il a refusé le prix Nobel de littérature en 1964 pour des raisons politiques."]'),
('frances', 'bachillerato', '{2}', '["Une chercheuse a étudié l''influence des réseaux sociaux sur les adolescents européens.","Elle a interrogé des milliers de jeunes dans différents pays pendant plusieurs années.","Ses résultats ont montré une corrélation entre l''usage excessif et l''anxiété adolescente.","Elle a recommandé des mesures éducatives pour favoriser un usage plus responsable.","Son rapport a été utilisé par plusieurs ministères de l''éducation européens."]'),
('frances', 'bachillerato', '{2}', '["Émile Zola a écrit Germinal en 1885 après''avoir visité plusieurs mines du Nord.","Le roman raconte la grève désespérée de mineurs contre des conditions de travail inhumaines.","Zola a documenté minutieusement la réalité sociale pour donner du poids à son récit.","L''oeuvre fait partie de la grande série romanesque des Rougon-Macquart.","Germinal est devenu un symbole littéraire de la lutte pour les droits ouvriers."]'),
('frances', 'bachillerato', '{2}', '["Le philosophe Michel Foucault a étudié les rapports entre savoir et pouvoir.","Son livre Surveiller et punir analyse l''évolution historique du système carcéral occidental.","Il a montré comment les institutions disciplinent les corps et les esprits.","Ses travaux ont profondément influencé les sciences humaines et sociales du XXe siècle.","Il est mort en 1984 mais son œuvre continue d''inspirer les chercheurs actuels."]'),
('frances', 'bachillerato', '{2}', '["Une équipe d''historiens a réexaminé les archives de la Seconde Guerre mondiale.","Ils ont découvert des documents inédits sur la Résistance dans le sud de la France.","Leurs analyses ont remis en question certaines interprétations traditionnelles de cette période.","Ils ont publié les résultats de leurs recherches dans un ouvrage très remarqué.","Le livre a relancé le débat historiographique sur le rôle des civils pendant l''Occupation."]'),
('frances', 'bachillerato', '{2}', '["Marguerite Duras a publié L''Amant en 1984 à l''âge de soixante-dix ans.","Le roman s''inspire de son adolescence en Indochine française pendant les années trente.","Il raconte la liaison passionnée d''une jeune Française avec un riche homme chinois.","Le livre a obtenu le prix Goncourt et connu un succès''international immédiat.","Duras a marqué la littérature française par son style minimaliste et poétique unique."]'),
('frances', 'bachillerato', '{2}', '["Un économiste a analysé les inégalités salariales en France au XXIe siècle.","Il a rassemblé des données statistiques sur des décennies entières d''évolution sociale.","Son livre est devenu une référence incontournable dans le débat public actuel.","Il a démontré l''accroissement constant des écarts entre les plus riches et les plus pauvres.","Ses propositions ont influencé plusieurs réformes fiscales en France et en Europe."]'),
('frances', 'bachillerato', '{2}', '["Charles Baudelaire a publié Les Fleurs du mal en 1857 à Paris.","Le recueil a immédiatement provoqué un scandale et plusieurs poèmes ont été censurés.","Baudelaire explore les thèmes de la beauté du mal et de la modernité urbaine.","Son œuvre a profondément influencé la poésie symboliste et moderne européenne.","Il est mort prématurément à quarante-six ans en laissant une œuvre considérable."]'),
('frances', 'bachillerato', '{2}', '["Une ingénieure a conçu un nouveau système de panneaux solaires plus efficaces.","Elle a utilisé des matériaux innovants pour augmenter le rendement énergétique des cellules.","Son prototype a été testé dans plusieurs régions aux climats très différents.","Les résultats ont dépassé toutes les attentes initiales de son équipe de recherche.","Plusieurs entreprises internationales ont acheté la licence de cette technologie révolutionnaire."]'),
('frances', 'bachillerato', '{2}', '["Molière a écrit Le Tartuffe en 1664 sous le règne de Louis XIV.","La pièce dénonce l''hypocrisie religieuse et la manipulation des consciences vulnérables.","Elle a été immédiatement interdite après les protestations des autorités''ecclésiastiques.","Molière a dû modifier la pièce et attendre cinq ans avant sa représentation publique.","Aujourd''hui Le Tartuffe est considéré comme un chef-d œuvre du théâtre classique français."]'),
('frances', 'bachillerato', '{2}', '["Une climatologue a publié une étude alarmante sur le recul des glaciers alpins.","Elle a comparé des photographies prises à un siècle d''intervalle dans les mêmes lieux.","Les images montraient une réduction spectaculaire de la masse glaciaire ces dernières décennies.","Son rapport a été utilisé par les organisations internationales pour sensibiliser le public.","Elle plaide pour des mesures urgentes contre le réchauffement climatique mondial."]'),
('frances', 'bachillerato', '{2}', '["Annie Ernaux a publié La Place en 1983 un récit autobiographique sur son père.","Elle a développé un style sobre qu''elle-même appelle écriture plate et neutre.","Ses livres explorent les thèmes de la mémoire de la classe sociale et de la femme.","Elle a reçu le prix Nobel de littérature en 2022 pour l''ensemble de son œuvre.","Elle est devenue la première écrivaine française à recevoir cette distinction prestigieuse."]'),
('frances', 'bachillerato', '{2}', '["Un sociologue a étudié l''évolution de la famille française depuis les années cinquante.","Il a analysé les statistiques démographiques et les enquêtes sociologiques disponibles.","Ses recherches ont révélé une transformation profonde des structures familiales traditionnelles.","Son livre a suscité de nombreuses discussions dans les médias et les universités.","Ses conclusions sont régulièrement citées dans les débats politiques sur la famille."]'),
('frances', 'bachillerato', '{2}', '["André Gide a publié Les Faux-monnayeurs en 1925 considéré comme son chef-d œuvre.","Le roman expérimente une structure narrative novatrice pour son époque.","Gide met en scène un romancier qui écrit lui-même un roman dans le roman.","L''oeuvre explore les thèmes de l''adolescence de la création et de la vérité.","Gide a reçu le prix Nobel de littérature en 1947 pour son audace stylistique."]'),
('frances', 'bachillerato', '{2}', '["Un médecin a mené un essai clinique sur un nouveau traitement contre le cancer.","Il a sélectionné des centaines de patients volontaires dans plusieurs hôpitaux français.","L''étude a duré quatre ans et a comporté de nombreuses étapes scientifiques rigoureuses.","Les résultats ont montré une efficacité prometteuse avec peu d''effets secondaires.","Le traitement a été approuvé par les autorités sanitaires européennes l''année suivante."]'),
('frances', 'bachillerato', '{2}', '["Voltaire a publié Candide en 1759 sous un pseudonyme pour éviter la censure royale.","Le conte philosophique critique l''optimisme de Leibniz et les superstitions de son époque.","Le héros parcourt le monde et découvre la cruauté humaine sous toutes ses formes.","Voltaire utilise l''ironie et l''humour pour défendre la tolérance et la raison.","Cette œuvre reste l''un des textes les plus lus de la littérature des Lumières."]'),
('frances', 'bachillerato', '{2}', '["Une linguiste a étudié l''évolution de la langue française dans les nouveaux médias.","Elle a analysé des millions de messages échangés sur les plateformes sociales.","Ses recherches ont identifié des tendances grammaticales et lexicales totalement nouvelles.","Elle a publié ses résultats dans une revue universitaire de référence internationale.","Son travail contribue à mieux comprendre comment les langues évoluent à l''ère numérique."]'),
('frances', 'bachillerato', '{2}', '["Le poète Paul Verlaine est né à Metz en 1844 dans une famille bourgeoise.","Il a publié ses premiers poèmes très jeune et fréquenté les cercles littéraires parisiens.","Sa rencontre avec Arthur Rimbaud a profondément marqué sa vie et son œuvre poétique.","Il a connu une existence tourmentée entre prison maladie et création artistique intense.","Sa poésie musicale et mélancolique a inspiré de nombreux compositeurs de son époque."]'),
('frances', 'bachillerato', '{2}', '["Une philosophe contemporaine a publié un essai sur l''éthique de l''intelligence artificielle.","Elle a analysé les enjeux moraux des décisions automatisées dans la santé et la justice.","Elle a interrogé des ingénieurs des juristes et des patients à travers ses recherches.","Son ouvrage propose un cadre éthique pour le développement responsable de ces technologies.","Le livre est devenu une référence dans les débats académiques et politiques actuels."]'),
('frances', 'bachillerato', '{2}', '["Honoré de Balzac a entrepris l''immense projet de La Comédie humaine vers 1830.","Il voulait peindre la société française de son époque dans toute sa complexité.","Il a écrit plus de quatre-vingt-dix romans interconnectés''en seulement deux décennies.","Ses personnages reviennent d''un livre à l''autre formant un univers cohérent.","Cette œuvre monumentale est considérée comme une fresque inégalée du XIXe siècle."]'),
('frances', 'bachillerato', '{2}', '["Un anthropologue a vécu pendant deux ans dans une communauté isolée de Polynésie.","Il a étudié les rites traditionnels et les structures sociales de ce peuple.","Il a appris la langue locale pour mieux comprendre leur vision du monde.","Son livre publié au retour a apporté une contribution majeure à l''ethnologie moderne.","Il continue à défendre la préservation des cultures menacées par la mondialisation actuelle."]'),
('frances', 'bachillerato', '{2}', '["Stendhal a publié Le Rouge et le Noir en 1830 sous son nom de plume.","Le roman raconte l''ascension sociale et la chute de Julien Sorel jeune ambitieux.","Stendhal explore la psychologie de son héros avec une finesse exceptionnelle pour l''époque.","L''oeuvre dépeint la société française sous la Restauration avec un regard critique aigu.","Le roman est aujourd''hui considéré comme un chef-d œuvre du réalisme français."]'),
('frances', 'bachillerato', '{2}', '["Une historienne a publié un livre sur le rôle des femmes dans la Résistance.","Elle a recueilli les témoignages oraux de dizaines de survivantes pendant des années.","Son ouvrage a redonné une visibilité à des héroïnes longtemps oubliées par l''histoire officielle.","Le livre a obtenu un prix littéraire et a été traduit dans plusieurs langues.","Il est désormais utilisé dans les programmes scolaires pour enseigner cette période."]'),
('frances', 'bachillerato', '{2}', '["Patrick Modiano a publié de nombreux romans explorant la mémoire et l''identité.","Son écriture mélange enquête journalistique et fiction sur l''Occupation parisienne.","Il puise souvent dans les archives et les annuaires pour reconstruire le passé.","Il a reçu le prix Nobel de littérature en 2014 pour l''ensemble de son œuvre.","Ses livres traduits dans le monde entier continuent à fasciner les nouveaux lecteurs."]'),
('frances', 'bachillerato', '{2}', '["Un chercheur en biologie a découvert une nouvelle molécule active contre certaines bactéries.","Il a isolé cette substance dans des plantes médicinales utilisées traditionnellement en Afrique.","Ses tests en laboratoire ont confirmé l''efficacité de la molécule contre des souches résistantes.","Il a publié ses résultats dans une revue scientifique internationalement reconnue.","Sa découverte ouvre des perspectives prometteuses pour développer de nouveaux antibiotiques."]'),
('frances', 'bachillerato', '{2}', '["Gustave Flaubert a passé cinq années à écrire Madame Bovary publié en 1857.","Le roman raconte la vie d''Emma Bovary épouse insatisfaite et rêveuse incurable.","Flaubert recherchait sans cesse le mot juste pour décrire la médiocrité provinciale.","Le livre a été poursuivi en justice pour outrage aux bonnes mœurs publiques.","Madame Bovary est considéré comme un chef-d œuvre fondateur du réalisme littéraire."]'),
('frances', 'bachillerato', '{2}', '["Une équipe de neuroscientifiques a étudié les effets de la méditation sur le cerveau.","Elle a réalisé des examens d''imagerie sur des centaines de méditants expérimentés.","Les images ont révélé des modifications structurelles dans plusieurs zones cérébrales spécifiques.","Les résultats confirment scientifiquement les bienfaits psychologiques rapportés depuis longtemps.","L''étude a influencé la médecine et la psychologie clinique contemporaines occidentales."]'),
('frances', 'bachillerato', '{2}', '["Le sociologue Pierre Bourdieu a développé le concept de capital culturel.","Il a montré comment les inégalités sociales se reproduisent à travers l''école.","Son ouvrage La Distinction analyse les goûts culturels selon les classes sociales.","Ses travaux ont profondément renouvelé la sociologie française et internationale.","Bourdieu reste l''un des penseurs les plus cités des sciences sociales contemporaines."]'),
('frances', 'bachillerato', '{2}', '["Le candidat commence son exposé oral en formulant clairement sa problématique de départ.","Il développe ensuite ses arguments en s''appuyant sur des exemples littéraires précis.","Il anticipe les objections possibles et les réfute avec une argumentation rigoureuse.","Il conclut son exposé en proposant une ouverture vers d''autres œuvres ou auteurs.","Le jury le félicite pour la clarté la précision et la qualité de son analyse."]'),
('frances', 'bachillerato', '{2}', '["Guy de Maupassant a publié Boule de Suif en 1880 dans un recueil collectif.","La nouvelle se déroule pendant la guerre franco-prussienne de 1870 et 1871.","Elle dépeint avec ironie l''hypocrisie des bourgeois face à une prostituée généreuse.","Maupassant a écrit plus de trois cents nouvelles avant sa mort prématurée.","Il est considéré comme l''un des maîtres de la nouvelle française réaliste."]'),
('frances', 'bachillerato', '{2}', '["Une géographe a étudié les migrations climatiques dans les régions tropicales.","Elle a analysé les déplacements de populations causés par la sécheresse et les inondations.","Son travail combine des données satellitaires des entretiens et des modèles mathématiques.","Elle a publié un rapport à l''attention des Nations Unies sur ce phénomène mondial.","Ses recommandations ont contribué à l''élaboration de politiques d''adaptation au changement climatique."]'),
('frances', 'bachillerato', '{2}', '["Le philosophe Albert Camus a publié La Peste en 1947 dans le contexte d''après-guerre.","Le roman raconte une épidémie qui frappe la ville d''Oran en Algérie.","Les personnages réagissent différemment face à la mort et à l''absurdité du fléau.","L''oeuvre est souvent lue comme une allégorie de la résistance contre le totalitarisme.","Camus y développe une éthique de la solidarité humaine face à l''adversité."]'),
('frances', 'bachillerato', '{2}', '["Un économiste a publié une analyse sur l''avenir du travail à l''ère numérique.","Il a étudié l''impact de l''automatisation sur des dizaines de secteurs professionnels.","Ses prévisions montrent une transformation profonde de l''emploi dans les prochaines décennies.","Il propose des politiques de formation continue pour aider les travailleurs à s''adapter.","Son livre est devenu une référence dans les débats sur les politiques publiques économiques."]'),
('frances', 'bachillerato', '{2}', '["Le philosophe Jean-Jacques Rousseau a publié Du contrat social en 1762.","Il y développe sa théorie de la souveraineté populaire et de la volonté générale.","L''ouvrage a profondément influencé les révolutionnaires français et américains du XVIIIe siècle.","Rousseau y défend l''idée que les hommes naissent libres mais sont enchaînés.","Son œuvre reste une référence majeure de la philosophie politique moderne occidentale."]'),
('frances', 'bachillerato', '{2}', '["Une astrophysicienne a participé à une mission internationale d''observation des trous noirs.","Elle a coordonné les données récoltées par plusieurs télescopes répartis sur la planète.","Son équipe a publié la première image directe d''un trou noir en 2019.","La photographie a fait la une des journaux scientifiques du monde entier.","Cette découverte a confirmé plusieurs prédictions de la théorie de la relativité générale."]'),
('frances', 'bachillerato', '{2}', '["Marcel Pagnol a publié Manon des Sources en 1963 inspiré de son enfance provençale.","Le roman raconte la vengeance d''une jeune fille contre des paysans cruels.","Pagnol mêle la beauté du paysage provençal à un drame humain intense.","L''oeuvre a été adaptée au cinéma avec un grand succès''international en 1986.","Pagnol reste l''un des écrivains et cinéastes les plus aimés de Provence."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('valenciano', 'bachillerato', '{1}', '["Vicent Andrés''Estellés va nàixer a Burjassot el 1924 en una família humil.","Va treballar com a periodista al diari Las Provincias durant moltes dècades.","La seua poesia uneix la vida quotidiana amb la denúncia social i política.","El llibre Mural del País Valencià és''una de les seues obres més''ambicioses.","Estellés''és considerat el gran poeta valencià del segle XX."]'),
('valenciano', 'bachillerato', '{1}', '["Una jove escriptora va decidir publicar el seu primer llibre de contes en valencià.","Va enviar el manuscrit a diverses editorials abans que una el va acceptar.","El llibre va rebre crítiques molt positives en la premsa cultural especialitzada.","L''any següent va guanyar un premi literari important convocat per la Generalitat.","Avui dia és''una de les autores joves més reconegudes en llengua catalana."]'),
('valenciano', 'bachillerato', '{1}', '["Les Falles de València se celebren cada any al voltant del 19 de març.","Els artistes fallers treballen durant mesos en la construcció dels grans monuments efímers.","Durant la setmana fallera la ciutat s''ompli de música pólvora i festa popular.","La nit del 19 al 20 de març totes les falles cremen en la cremà.","Aquesta festa va ser declarada Patrimoni Immaterial de la Humanitat per la UNESCO."]'),
('valenciano', 'bachillerato', '{1}', '["Un grup d''estudiants va decidir restaurar una alqueria abandonada del seu poble.","Van obtenir permís de l''ajuntament i van demanar ajuda als veïns interessats.","Durant els caps de setmana van treballar en la neteja i les reparacions necessàries.","Van convertir l''alqueria en un centre cultural per a tot el poble.","El projecte va rebre un premi al patrimoni rural de la Comunitat Valenciana."]'),
('valenciano', 'bachillerato', '{1}', '["Mercè Rodoreda va nàixer a Barcelona l''any 1908 en una família modesta.","Va començar a escriure des de molt jove en revistes i diaris locals.","Va haver d''exiliar-se a França després de la Guerra Civil espanyola.","La seua novel·la La plaça del Diamant publicada en 1962 és la més coneguda.","Rodoreda és''una de les escriptores més''importants en llengua catalana del segle XX."]'),
('valenciano', 'bachillerato', '{1}', '["Una jove cuinera va obrir un restaurant tradicional al centre històric de Castelló.","Volia recuperar les receptes antigues de la cuina valenciana de la seua àvia.","Utilitzava ingredients de proximitat comprats directament als llauradors de la zona.","La premsa gastronòmica va destacar la qualitat i autenticitat dels seus plats.","En pocs anys el restaurant es va convertir en una referència gastronòmica regional."]'),
('valenciano', 'bachillerato', '{1}', '["L''Albufera de València és''un parc natural situat al sud de la ciutat.","És''un dels aiguamolls més''importants de la Mediterrània occidental europea.","Centenars d''espècies d''ocells visiten aquest indret durant les seues migracions.","El parc també alberga els camps d''arròs''on es cultiva l''ingredient principal de la paella.","La protecció ambiental garanteix la conservació d''aquest ecosistema únic per al futur."]'),
('valenciano', 'bachillerato', '{1}', '["Un estudiant universitari va començar a fer voluntariat en una entitat social.","Ajudava xiquets immigrants amb les seues tasques escolars cada setmana.","A poc a poc va aprendre nocions bàsiques de diversos idiomes per comunicar-se.","Va organitzar activitats lúdiques per fomentar la integració dels xiquets nouvinguts.","L''experiència el va portar a estudiar treball social com a futura professió."]'),
('valenciano', 'bachillerato', '{1}', '["Joan Lluís Vives va nàixer a València l''any 1492 en una família jueva conversa.","Va estudiar a la Universitat de París''on va destacar per la seua intel·ligència extraordinària.","Va escriure obres en llatí sobre filosofia educació i drets humans fonamentals.","És considerat un dels pares de la pedagogia moderna europea pel seu pensament innovador.","Vives va morir a Bruges l''any 1540 deixant un llegat intel·lectual immens."]'),
('valenciano', 'bachillerato', '{1}', '["Una científica valenciana va investigar les propietats medicinals de plantes mediterrànies.","Va recollir mostres en diferents indrets de la Comunitat Valenciana durant anys.","Els seus experiments van revelar compostos amb potencial farmacològic interessant.","Va publicar els resultats en una revista científica internacional molt prestigiosa.","La seua investigació podria contribuir al desenvolupament de nous medicaments naturals."]'),
('valenciano', 'bachillerato', '{1}', '["La paella valenciana és''el plat més''emblemàtic de la cuina valenciana tradicional.","S''elabora amb arròs pollastre conill verdures i condiments característics de la regió.","Es cuina en una paella plana sobre foc de llenya per donar-li sabor autèntic.","Cada família valenciana sol tindre la seua pròpia recepta transmesa de generació en generació.","Avui dia la paella és coneguda i valorada en tot el món sencer."]'),
('valenciano', 'bachillerato', '{1}', '["Un jove pintor valencià va començar a exposar les seues obres en galeries locals.","El seu estil combinava la tradició mediterrània amb tècniques modernes molt expressives.","Un crític d''art important va escriure un article elogiós sobre el seu treball.","Galeries de Madrid i Barcelona li van proposar exposicions individuals més grans.","Avui les seues pintures es venen en subhastes internacionals a preus elevats."]'),
('valenciano', 'bachillerato', '{1}', '["La Llotja de la Seda de València és''un edifici gòtic construït''al segle XV.","Va ser el centre del comerç i la prosperitat econòmica de la ciutat de València.","La seua arquitectura monumental simbolitza la importància del comerç de la seda valenciana.","Va ser declarada Patrimoni de la Humanitat per la UNESCO en l''any 1996.","Avui és''un dels monuments més visitats del centre històric de València."]'),
('valenciano', 'bachillerato', '{1}', '["Una professora va organitzar un projecte de teatre amb els seus alumnes de secundària.","Volia ajudar-los a guanyar confiança i a millorar la seua expressió oral en valencià.","Durant el curs van escriure col·lectivament una obra inspirada en llegendes valencianes.","La representació final es va fer davant les famílies i la resta del centre.","L''experiència va transformar l''actitud de molts alumnes envers la llengua i la cultura."]'),
('valenciano', 'bachillerato', '{1}', '["L''horta valenciana és''un sistema agrícola tradicional únic al món sencer.","Va ser desenvolupada pels musulmans durant la seua presència a la península Ibèrica.","Un complex sistema de séquies distribueix l''aigua entre les diferents parcel·les agrícoles.","El Tribunal de les Aigües regula els conflictes des de fa més de mil anys.","Aquesta institució mil·lenària ha estat reconeguda per la UNESCO com a patrimoni immaterial."]'),
('valenciano', 'bachillerato', '{1}', '["Un grup de joves músics va formar una banda per recuperar instruments tradicionals.","Tocaven dolçaina tabal i altres instruments característics de la música popular valenciana.","Van actuar en festes patronals i esdeveniments culturals per tota la Comunitat Valenciana.","La seua música va atraure especialment al públic jove interessat en les tradicions.","Han enregistrat diversos discs i han actuat en festivals internacionals de música tradicional."]'),
('valenciano', 'bachillerato', '{1}', '["Salvador Espriu va nàixer a Santa Coloma de Farners l''any 1913.","Va estudiar Dret i Filosofia a la Universitat de Barcelona amb molt bones notes.","La seua obra poètica reflexiona sobre la història i la identitat dels pobles ibèrics.","El llibre La pell de brau publicat en 1960 és la seua obra més coneguda.","Espriu és considerat un dels grans poetes catalans del segle XX."]'),
('valenciano', 'bachillerato', '{1}', '["Una bióloga marina valenciana va estudiar les espècies del Mediterrani occidental.","Va realitzar immersions per documentar la vida submarina durant molts anys consecutius.","Va observar canvis preocupants causats pel canvi climàtic i la contaminació marina.","Els seus informes van alertar les autoritats sobre la necessitat de més protecció.","Va impulsar la creació de noves àrees marines protegides al llarg del litoral."]'),
('valenciano', 'bachillerato', '{1}', '["La Ciutat de les Arts i les Ciències és''un complex arquitectònic modern de València.","Va ser dissenyada pels arquitectes Santiago Calatrava i Félix Candela als anys noranta.","Inclou un palau de les arts un planetari un museu de ciències i un oceanogràfic.","S''ha convertit en una de les principals atraccions turístiques de la ciutat de València.","La seua arquitectura futurista contrasta amb el centre històric tradicional valencià."]'),
('valenciano', 'bachillerato', '{1}', '["Un jove enginyer valencià va desenvolupar un sistema per estalviar aigua de reg.","El sistema utilitzava sensors que mesuraven la humitat del sòl''en temps real.","Va provar el prototip en diversos camps de tarongers de la província de València.","Els resultats van mostrar un estalvi notable d''aigua sense pèrdua de productivitat.","Va patentar la seua invenció i va crear una empresa per comercialitzar el sistema."]'),
('valenciano', 'bachillerato', '{1}', '["La Catedral de València va començar a construir-se en l''any 1262.","Combina diversos estils arquitectònics com el romànic gòtic renaixentista i barroc.","Segons la tradició catòlica conserva el Sant Calze utilitzat en l Última Cena.","La seua torre principal anomenada el Micalet és''un símbol de la ciutat.","Cada any milers de visitants entren a la catedral per admirar el seu art."]'),
('valenciano', 'bachillerato', '{1}', '["Un periodista valencià va investigar un cas de corrupció en una empresa pública.","Va contactar amb diverses fonts internes i va recopilar documents confidencials.","Els seus articles publicats al diari local van provocar una gran controvèrsia política.","Diverses autoritats van haver de dimitir a causa de les revelacions del seu treball.","El periodista va rebre un premi pel seu valor i la seua tasca democràtica."]'),
('valenciano', 'bachillerato', '{1}', '["Una mestra rural va organitzar activitats per acostar els seus alumnes a la natura.","Cada setmana els portava a visitar diferents espais naturals propers al col·legi.","Els xiquets van aprendre a identificar plantes ocells i petits mamífers locals.","Van crear un hort escolar on cultivaven verdures de temporada de manera sostenible.","Aquesta experiència va despertar en molts alumnes una vocació científica i ambiental."]'),
('valenciano', 'bachillerato', '{1}', '["El Misteri d''Elx és''una representació teatral religiosa medieval que perdura encara avui.","Se celebra cada any als dies 14 i 15 d''agost a la basílica d''Elx.","La seua música i text en llatí i valencià es mantenen pràcticament inalterats.","Va ser declarat Patrimoni de la Humanitat per la UNESCO en l''any 2001.","Aquesta tradició és única al món''i atrau visitants de molts països."]'),
('valenciano', 'bachillerato', '{1}', '["Un fotògraf valencià va dedicar deu anys a documentar la vida als pobles abandonats.","Va recórrer comarques rurals on quedaven només''unes poques persones grans.","Les seues fotografies mostraven la dignitat i la solitud d''aquestes vides oblidades.","Va publicar un llibre amb les imatges més''impressionants del seu treball pacient.","L''obra va contribuir a sensibilitzar la societat sobre el problema de la despoblació."]'),
('valenciano', 'bachillerato', '{1}', '["Una jove enginyera informàtica va crear una aplicació mòbil per aprendre valencià.","L''aplicació utilitzava jocs i activitats interactives per fer divertit l''aprenentatge.","En pocs mesos va aconseguir milers de descàrregues a tot el territori valencià.","Diverses escoles van adoptar l''aplicació com a recurs complementari per al curs.","La Generalitat Valenciana li va atorgar un reconeixement per la seua iniciativa innovadora."]'),
('valenciano', 'bachillerato', '{1}', '["Sant Vicent Ferrer va nàixer a València l''any 1350 en una família burgesa.","Va ingressar en l''orde dels dominicans als disset anys d''edat aproximadament.","Va recórrer Europa predicant i actuant com a mediador en conflictes polítics.","Va participar en el Compromís de Casp que va decidir la successió de la Corona d''Aragó.","Va ser canonitzat per l''Església catòlica i és''el patró de la ciutat de València."]'),
('valenciano', 'bachillerato', '{1}', '["Un grup d''arquitectes valencians va proposar la rehabilitació d''un barri històric.","Volien preservar les façanes tradicionals mentre modernitzaven els interiors dels edificis.","El projecte incloïa zones verdes per a les famílies i carrers per a vianants.","L''ajuntament va aprovar la proposta després de consultar amb els veïns afectats.","Les obres van transformar el barri en un dels més''atractius de la ciutat."]'),
('valenciano', 'bachillerato', '{1}', '["La Renaixença valenciana va sorgir al segle XIX com a moviment cultural i lingüístic.","Va impulsar la recuperació del valencià com a llengua literària després de segles.","Constantí Llombart va fundar Lo Rat Penat per defensar i promoure la llengua valenciana.","Es van organitzar els Jocs Florals seguint el model dels que es feien a Catalunya.","Aquest moviment va sentar les bases per al desenvolupament cultural valencià posterior."]'),
('valenciano', 'bachillerato', '{1}', '["Una pedagoga valenciana va desenvolupar un mètode innovador per ensenyar a llegir.","El mètode combinava jocs activitats sensorials i lectures adaptades a cada edat.","Va aplicar el mètode a diverses escoles de la província amb molt bons resultats.","Els xiquets van aprendre a llegir més ràpidament i amb major comprensió lectora.","El seu mètode va ser publicat en un llibre i adoptat per moltes escoles valencianes."]'),
('valenciano', 'bachillerato', '{1}', '["Les comarques del nord del País Valencià destaquen pel seu paisatge muntanyós''espectacular.","El Penyagolosa és la muntanya més''emblemàtica de la província de Castelló.","Cada any milers de pelegrins fan el camí dels peregrins fins a aquest cim.","La zona també alberga pobles històrics amb una rica tradició cultural i gastronòmica.","És''un destí ideal per a les persones que busquen turisme rural i natural."]'),
('valenciano', 'bachillerato', '{1}', '["Un grup de voluntaris va organitzar una neteja de platges de la costa valenciana.","Van convocar la jornada a través de les xarxes socials i la premsa local.","Centenars de persones de totes les edats van participar en la iniciativa solidària.","Van recollir tones de plàstics i altres deixalles deixades per turistes i bany.","La jornada va sensibilitzar els assistents sobre la importància de la conservació marina."]'),
('valenciano', 'bachillerato', '{1}', '["Isabel de Villena va nàixer a València l''any 1430 com a Elionor Manuel d''Aragó.","Va ingressar al monestir de la Trinitat sent encara jove de manera definitiva.","Va escriure la Vita Christi una de les primeres obres en prosa valenciana.","La seua obra destaca per donar una visió femenina dels esdeveniments evangèlics.","És considerada la primera escriptora coneguda en llengua catalana medieval."]'),
('valenciano', 'bachillerato', '{1}', '["Un jove cineasta valencià va rodar el seu primer documental sobre l''albufera.","Va passar un any sencer filmant les diferents estacions i la fauna del lloc.","El documental mostrava la bellesa fràgil d''aquest ecosistema mediterrani únic.","Va guanyar un premi en un festival internacional de cinema de naturalesa.","La seua obra va ajudar a donar visibilitat a la importància de protegir l''albufera."]'),
('valenciano', 'bachillerato', '{1}', '["El comerç de la seda va ser una activitat clau a la València del segle XV.","Els teixidors valencians produïen les sedes més''apreciades del Mediterrani occidental.","La Llotja era el centre on es negociaven els grans contractes comercials de seda.","Aquest comerç va portar prosperitat i va finançar nombroses obres artístiques rellevants.","Avui dia el Col·legi de l''Art Major de la Seda manté viva aquesta tradició."]'),
('valenciano', 'bachillerato', '{1}', '["Una nutricionista valenciana va estudiar els beneficis de la dieta mediterrània tradicional.","Va comparar la salut de persones que la seguien amb les que no la practicaven.","Els resultats van confirmar els efectes positius d''aquesta dieta sobre el cor.","Va publicar les seues conclusions en una revista mèdica de gran prestigi internacional.","Les seues recomanacions van ser incorporades a les guies oficials de salut pública."]'),
('valenciano', 'bachillerato', '{1}', '["El Palau de la Música de València va ser inaugurat l''any 1987.","Està situat al costat dels jardins del Túria al cor de la ciutat.","Acull regularment concerts de música clàssica jazz i música popular contemporània.","La sala principal té una excel·lent acústica reconeguda per músics internacionals importants.","Cada temporada presenta una programació variada que atrau públic de tota la regió."]'),
('valenciano', 'bachillerato', '{1}', '["Un emprenedor valencià va crear una marca de cosmètics naturals amb productes locals.","Utilitzava tarongers oliveres i altres plantes característiques del paisatge mediterrani valencià.","Els seus productes van tindre molt èxit entre els consumidors interessats en la sostenibilitat.","Va començar a exportar a diversos països europeus en pocs anys d''activitat.","La seua empresa dóna feina a desenes de persones a la província de València."]'),
('valenciano', 'bachillerato', '{1}', '["Una arqueòloga valenciana va dirigir l''excavació d''un jaciment ibèric a la província de Castelló.","Van descobrir restes de cases ceràmiques i objectes de la vida quotidiana.","Les troballes van proporcionar informació valuosa sobre la cultura ibèrica del segle V abans de Crist.","Els objectes recuperats es van enviar a un museu per a la seua conservació adequada.","L''excavació va contribuir significativament al coneixement de la història antiga del territori."]'),
('valenciano', 'bachillerato', '{1}', '["El Tribunal de les Aigües de València se reuneix cada dijous a la porta de la catedral.","És considerat la institució judicial més''antiga d''Europa encara en funcionament continu.","Resol els conflictes entre els llauradors per l ús de l''aigua de reg de l''horta.","Els seus membres són''els síndics elegits per cadascuna de les huit séquies tradicionals.","La UNESCO va declarar aquesta institució Patrimoni Immaterial de la Humanitat l''any 2009."]'),
('valenciano', 'bachillerato', '{1}', '["Una jove dissenyadora valenciana va crear una col·lecció de moda inspirada en l''horta.","Va utilitzar teixits naturals i estampats amb motius vegetals típicament mediterranis.","La col·lecció es va presentar en una passarel·la important de moda a Madrid.","Diverses revistes especialitzades van destacar l''originalitat i la qualitat dels seus dissenys.","Avui en dia ven les seues creacions en botigues de tot Europa."]'),
('valenciano', 'bachillerato', '{1}', '["Joan Roís de Corella va ser un escriptor valencià del segle XV molt destacat.","Va escriure obres en prosa i en vers d''una gran refinament estilístic.","La seua Tragèdia de Caldesa és''una obra mestra de la literatura medieval.","Va influir profundament en altres escriptors valencians del Segle d''Or de les lletres.","Avui en dia és considerat un dels autors clau de la literatura catalana medieval."]'),
('valenciano', 'bachillerato', '{1}', '["Una empresa valenciana va desenvolupar un sistema de plaques solars més''eficient.","Els enginyers van treballar durant anys per millorar el rendiment energètic dels panells.","El nou sistema podia generar més''electricitat amb menys superfície ocupada.","L''empresa va obtindre contractes importants per instal·lar les plaques en diverses regions.","La seua innovació va contribuir al desenvolupament de les energies renovables a Espanya."]'),
('valenciano', 'bachillerato', '{1}', '["Un escriptor valencià va publicar la seua primera novel·la després de molts anys d''esforç.","La història estava ambientada a la València del segle XIX i barrejava ficció i realitat.","La novel·la va ser molt ben rebuda per la crítica i el públic lector.","Va guanyar un premi literari important convocat per una editorial de Barcelona.","L''èxit el va animar a dedicar-se professionalment a l''escriptura literària."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('valenciano', 'bachillerato', '{2}', '["Joanot Martorell va començar a escriure el Tirant lo Blanc cap a l''any 1460.","La novel·la combina elements de cavalleria amb un realisme sorprenent per a l''època.","Els personatges presenten una psicologia complexa i humana lluny dels tòpics medievals.","Cervantes va elogiar el Tirant en el Quixot com el millor llibre del món.","Aquesta obra és considerada la primera novel·la moderna de la literatura europea."]'),
('valenciano', 'bachillerato', '{2}', '["Ausiàs March va nàixer a Gandia al voltant de l''any 1397 en una família noble.","Va trencar amb la tradició trobadoresca usant el català en lloc del provençal.","La seua poesia explora amb profunditat els temes de l''amor el dolor i la mort.","Els Cants de mort dedicats a la seua esposa són d''una intensitat extraordinària.","March és considerat el primer gran poeta de la literatura catalana medieval moderna."]'),
('valenciano', 'bachillerato', '{2}', '["Un crític literari valencià va publicar un assaig sobre la novel·la contemporània.","Va analitzar les obres dels escriptors valencians més''importants de les últimes dècades.","El llibre va aportar noves perspectives sobre l''evolució de la narrativa en valencià.","Va ser presentat en diverses universitats i centres culturals de la regió.","La seua obra es va convertir en una referència obligada per als estudiants de filologia."]'),
('valenciano', 'bachillerato', '{2}', '["Joan Fuster va nàixer a Sueca l''any 1922 en una família tradicional valenciana.","Va estudiar Dret a la Universitat de València però es va dedicar a l''assaig.","Nosaltres els valencians publicat el 1962 va sacsejar la societat valenciana de l''època.","Fuster defensava la unitat lingüística catalana i la necessitat de normalitzar el valencià.","La seua influència intel·lectual continua marcant el pensament contemporani del País Valencià."]'),
('valenciano', 'bachillerato', '{2}', '["L''estudiant comença el seu comentari de text identificant l''autor i el context històric.","A continuació analitza l''estructura del text i els recursos retòrics utilitzats per l''autor.","En la tercera part interpreta el contingut relacionant-lo amb altres obres literàries.","Conclou el comentari amb una valoració personal argumentada sobre l''obra analitzada.","El professor felicita la qualitat la rigorositat i la profunditat de la seua anàlisi."]'),
('valenciano', 'bachillerato', '{2}', '["Enric Valor va dedicar la seua vida a recollir les rondalles populars valencianes.","Va recórrer pobles i comarques per recollir històries de la tradició oral popular.","Va publicar diversos volums de rondalles adaptades amb un valencià literari excel·lent.","També va escriure obres gramaticals que van ajudar a fixar l''estàndard escrit.","Valor és recordat com un dels grans defensors de la cultura i la llengua valencianes."]'),
('valenciano', 'bachillerato', '{2}', '["Una historiadora valenciana va escriure un llibre sobre la guerra de Successió.","Va consultar arxius municipals i nacionals per documentar el conflicte amb rigor.","El llibre analitzava l''impacte de la batalla d''Almansa sobre el País Valencià.","La seua investigació va aportar dades inèdites sobre la repressió posterior.","L''obra va ser molt ben rebuda pels especialistes i pel públic interessat."]'),
('valenciano', 'bachillerato', '{2}', '["Manuel Sanchis Guarner va ser un filòleg i escriptor valencià nascut en 1911.","Va estudiar la història i la dialectologia de la llengua catalana del territori valencià.","La seua obra Gramàtica valenciana va contribuir a la normativització del valencià.","També va escriure La ciutat de València una història completa de la capital.","És considerat un dels grans intel·lectuals valencians del segle XX i referent."]'),
('valenciano', 'bachillerato', '{2}', '["Una poeta jove valenciana va publicar el seu primer poemari en una editorial petita.","Els seus poemes exploraven temes com la identitat el cos i el desig contemporani.","La crítica especialitzada va destacar la frescor i l''originalitat de la seua veu.","Va guanyar un premi de poesia jove convocat per la Generalitat Valenciana.","Avui és''una de les veus més prometedores de la poesia catalana actual."]'),
('valenciano', 'bachillerato', '{2}', '["Vicent Andrés''Estellés va publicar Llibre de Meravelles en 1971 com a obra mestra.","El llibre és''un homenatge a Ramon Llull i al seu Llibre de meravelles medieval.","Estellés combina records personals amb la denúncia social i la celebració del País Valencià.","La seua poesia va influir profundament en la generació posterior d''escriptors valencians.","Aquesta obra és considerada una de les més''importants de la poesia catalana moderna."]'),
('valenciano', 'bachillerato', '{2}', '["Una sociòloga valenciana va estudiar l''evolució de la família al País Valencià.","Va analitzar dades estadístiques i va realitzar entrevistes en diferents comarques.","La seua investigació va revelar canvis profunds en les estructures familiars tradicionals.","Va publicar un llibre amb les seues conclusions que va generar molt de debat.","Les seues anàlisis són citades habitualment en els estudis sobre transformació social."]'),
('valenciano', 'bachillerato', '{2}', '["Mercè Rodoreda va escriure La plaça del Diamant durant el seu exili a Ginebra.","La novel·la narra la vida de Colometa una dona barcelonina durant la Guerra Civil.","La protagonista pateix les conseqüències del conflicte i la postguerra amb resignació.","L''estil simbòlic i poètic de Rodoreda dóna profunditat a una història aparentment simple.","La novel·la és considerada una obra mestra de la literatura catalana del segle XX."]'),
('valenciano', 'bachillerato', '{2}', '["Un investigador valencià va publicar un assaig sobre la història de la premsa local.","Va analitzar l''evolució dels diaris i revistes en valencià des del segle XIX.","El seu treball mostra la importància de la premsa per a la pervivència de la llengua.","Va consultar centenars de capçaleres conservades en biblioteques i arxius regionals.","L''assaig ha esdevingut una referència fonamental per als estudiosos del periodisme valencià."]'),
('valenciano', 'bachillerato', '{2}', '["Pere March va ser un poeta valencià del segle XIV oncle d''Ausiàs March famós.","Va escriure poemes en català sobre temes morals filosòfics i religiosos profunds.","La seua obra reflecteix la transició entre la poesia trobadoresca i una nova sensibilitat.","Va exercir càrrecs administratius al servei dels reis de la Corona d''Aragó.","És considerat un precursor important del seu nebot Ausiàs March en la poesia catalana."]'),
('valenciano', 'bachillerato', '{2}', '["Una dramaturga valenciana va estrenar una obra de teatre sobre la dona contemporània.","L''obra va ser representada en diversos teatres del País Valencià amb gran èxit.","La crítica va elogiar la profunditat psicològica dels personatges femenins creats.","L''obra va guanyar un premi al festival internacional de teatre de Sitges.","Avui en dia és''una de les dramaturgues més reconegudes en llengua catalana actual."]'),
('valenciano', 'bachillerato', '{2}', '["Bernat Fenollar va ser un poeta valencià del segle XV vinculat a Ausiàs March.","Va participar en el famós debat literari Lo procés de les olives amb altres autors.","La seua poesia destaca pel sentit de l''humor i la sàtira social aguda.","Va formar part del cercle d''intel·lectuals que van fer de València un centre literari.","Avui és''estudiat com una figura clau del Segle d''Or de les lletres catalanes."]'),
('valenciano', 'bachillerato', '{2}', '["Un lingüista valencià va publicar un estudi sobre l''evolució del valencià col·loquial.","Va recollir testimonis orals en diverses comarques durant més d''una dècada.","El seu treball documenta canvis importants en el lèxic i la pronúncia actuals.","Va publicar les seues conclusions en una revista universitària de gran prestigi.","La investigació aporta dades valuoses per als futurs estudis sobre la sociolingüística catalana."]'),
('valenciano', 'bachillerato', '{2}', '["Carles Salvador va ser un mestre i escriptor valencià nascut en 1893.","Va treballar incansablement per la introducció del valencià a l''ensenyament durant la República.","Va escriure manuals i materials didàctics per ensenyar la llengua als xiquets.","La repressió franquista va impedir la continuïtat de la seua obra pedagògica innovadora.","Avui és recordat com un pioner de l''ensenyament del valencià a les escoles."]'),
('valenciano', 'bachillerato', '{2}', '["Una escriptora valenciana va publicar una novel·la històrica ambientada a la València medieval.","Va investigar durant anys en arxius i biblioteques per documentar correctament l''època.","La novel·la va combinar rigor històric amb una narrativa àgil i atractiva.","Va guanyar un premi literari important i va ser traduïda a diverses llengües europees.","Avui és''una de les escriptores més llegides en llengua catalana contemporània."]'),
('valenciano', 'bachillerato', '{2}', '["Constantí Llombart va fundar la societat Lo Rat Penat l''any 1878 a València.","L''objectiu de l''associació era promoure i defensar la llengua i cultura valencianes.","Va organitzar els Jocs Florals seguint el model dels que se celebraven a Barcelona.","Llombart va dedicar tota la seua vida a la recuperació de la llengua valenciana.","La seua obra va impulsar la Renaixença valenciana del segle XIX i posterior."]'),
('valenciano', 'bachillerato', '{2}', '["Un crític cinematogràfic valencià va publicar un assaig sobre el cinema en català.","Va analitzar l''evolució de la producció audiovisual des de la transició democràtica.","El seu llibre destacava les dificultats i els èxits del cinema en llengua minoritzada.","Va incloure entrevistes amb directors actors i productors valencians més rellevants.","L''assaig és''una referència essencial per entendre el panorama audiovisual català actual."]'),
('valenciano', 'bachillerato', '{2}', '["Maria Beneyto va ser una poeta valenciana nascuda a la ciutat de València en 1925.","Va publicar el seu primer llibre de poemes a finals dels anys quaranta.","La seua poesia explora temes íntims com l''amor la maternitat i la identitat femenina.","Va escriure tant en castellà com en valencià al llarg de tota la seua trajectòria.","Beneyto és recordada com una de les veus poètiques més personals del segle XX."]'),
('valenciano', 'bachillerato', '{2}', '["Una historiadora de l''art va publicar un estudi sobre els pintors valencians del segle XIX.","Va analitzar l''obra de Joaquim Sorolla i d''altres mestres importants de l''època.","El llibre destaca la influència del paisatge mediterrani en l''estil dels pintors.","Va col·laborar amb diversos museus per a una exposició dedicada al tema.","La seua investigació ha contribuït''a difondre la importància de la pintura valenciana."]'),
('valenciano', 'bachillerato', '{2}', '["Bernat Metge va ser un escriptor català del segle XIV considerat humanista pioner.","La seua obra Lo somni està influïda per autors clàssics i italians del Renaixement.","En aquest diàleg defensa la racionalitat enfront de les supersticions del seu temps.","Metge va exercir càrrecs administratius a la cort dels reis de la Corona d''Aragó.","És considerat un dels primers prosistes en llengua catalana medieval moderna."]'),
('valenciano', 'bachillerato', '{2}', '["Un filòsof valencià va publicar un assaig sobre l''ètica en l''era digital.","Va analitzar els reptes morals plantejats per les tecnologies emergents contemporànies.","El llibre va ser molt ben rebut tant pels especialistes com pel públic general.","Va participar en conferències i debats internacionals sobre tecnologia i societat actual.","Les seues reflexions han influït''en el debat acadèmic sobre l''ètica de la tecnologia."]'),
('valenciano', 'bachillerato', '{2}', '["Carmelina Sánchez Cutillas va ser una escriptora valenciana nascuda a Madrid en 1921.","La seua novel·la Matèria de Bretanya és la seua obra més coneguda i estimada.","En aquesta obra recrea la infància en un poble valencià amb prosa poètica.","El llibre ha esdevingut un clàssic contemporani de la literatura en llengua catalana.","Sánchez Cutillas va ser una de les primeres veus femenines del seu temps."]'),
('valenciano', 'bachillerato', '{2}', '["Un investigador valencià va publicar un estudi sobre la literatura infantil en valencià.","Va analitzar les principals obres i autors d''aquest gènere durant les últimes dècades.","El seu treball destaca la importància de la literatura per a fomentar l ús del valencià.","Va proposar criteris pedagògics per seleccionar obres adequades per a cada edat.","L''estudi és consultat per docents i bibliotecaris de tot el territori valencià."]'),
('valenciano', 'bachillerato', '{2}', '["Roís de Corella va escriure la Tragèdia de Caldesa al segle XV en València.","L''obra narra la dolorosa traïció amorosa que pateix el narrador-protagonista del relat.","Corella combina la prosa refinada amb intenses descripcions psicològiques i emocionals.","El seu estil va influir en altres escriptors del Segle d''Or valencià posterior.","Aquesta breu obra és considerada una joia de la prosa medieval catalana culta."]'),
('valenciano', 'bachillerato', '{2}', '["Una novel·lista valenciana va publicar una obra sobre la guerra civil al País Valencià.","Va recollir testimonis de supervivents i descendents per documentar els fets reals.","La novel·la combinava personatges de ficció amb esdeveniments històrics rigorosament documentats.","El llibre va ser ben rebut tant per la crítica com pels lectors interessats.","Va contribuir a la recuperació de la memòria històrica del territori valencià."]'),
('valenciano', 'bachillerato', '{2}', '["Vicent Ventura va ser un periodista i escriptor valencià nascut en 1924.","Va col·laborar amb diversos diaris i revistes durant la dictadura franquista.","Va defensar incansablement els valors democràtics i la cultura valenciana en la seua obra.","Va participar activament en la fundació d''institucions culturals al País Valencià.","És recordat com un referent del periodisme compromès''i la cultura valenciana moderna."]'),
('valenciano', 'bachillerato', '{2}', '["Una crítica literària va analitzar l''obra poètica de Vicent Andrés''Estellés''en profunditat.","Va publicar un assaig que destacava la dimensió èpica i social de la seua poesia.","Va relacionar Estellés''amb altres poetes mediterranis com Salvatore Quasimodo o Pavese.","El seu estudi va aportar noves claus per llegir l''obra d''aquest poeta valencià.","L''assaig és consultat habitualment per estudiants i investigadors universitaris de literatura."]'),
('valenciano', 'bachillerato', '{2}', '["Anselm Turmeda va ser un frare mallorquí del segle XIV que es va convertir a l''islam.","Va viure a Tunis on va exercir càrrecs importants sota el sultà del moment.","Va escriure obres en català àrab i llatí amb gran erudició i originalitat.","La seua Disputa de l''ase és''una sàtira ingeniosa contra els humans pretensiosos.","Turmeda és''una figura singular del segle XIV per la seua trajectòria intercultural."]'),
('valenciano', 'bachillerato', '{2}', '["Un assagista valencià va publicar un estudi sobre la identitat cultural del País Valencià.","Va dialogar amb les tesis de Joan Fuster matisant alguns dels seus plantejaments.","El llibre va generar un important debat intel·lectual i polític en la societat valenciana.","Va participar en nombroses conferències universitats i centres culturals per defensar les seues idees.","L''obra és considerada una de les contribucions més''importants al pensament valencià recent."]'),
('valenciano', 'bachillerato', '{2}', '["L''examinant comença la seua redacció amb una introducció clara que presenta el tema.","Desenvolupa els arguments principals organitzats en paràgrafs ben estructurats i coherents.","Utilitza connectors discursius variats per garantir la cohesió del text.","Inclou exemples concrets i referències per donar pes als seus arguments.","Conclou amb una síntesi efectiva que reprèn les idees principals exposades anteriorment."]'),
('valenciano', 'bachillerato', '{2}', '["Joan Roís de Corella va viure a la València del segle XV en plena efervescència cultural.","Va escriure obres en prosa i en vers amb un refinament estilístic excepcional.","La seua Tragèdia de Caldesa explora els turments de l''amor traït''amb intensitat.","Va influir profundament en altres escriptors del Segle d''Or valencià contemporani.","Avui és''estudiat com un dels grans prosistes de la literatura catalana medieval."]'),
('valenciano', 'bachillerato', '{2}', '["Una jove escriptora va guanyar el Premi Joanot Martorell amb la seua segona novel·la.","L''obra narrava la història d''una família valenciana al llarg de tres generacions.","La crítica va destacar la qualitat narrativa i l''autenticitat dels personatges creats.","La novel·la va ser traduïda al castellà i a altres llengües europees ràpidament.","Avui forma part de la nova generació d''escriptors en llengua catalana."]'),
('valenciano', 'bachillerato', '{2}', '["Francesc Eiximenis va ser un franciscà gironí del segle XIV que va viure a València.","Va escriure Lo Crestià una enciclopèdia moral en valencià de gran extensió.","La seua obra Regiment de la cosa pública oferia consells als governants de l''època.","Va combinar erudició religiosa amb observacions sobre la societat valenciana del seu temps.","Eiximenis és considerat un dels grans escriptors en prosa medieval catalana."]'),
('valenciano', 'bachillerato', '{2}', '["Una professora universitària va publicar un estudi sobre l''obra de Mercè Rodoreda.","Va analitzar els símbols recurrents i les estructures narratives de les seues novel·les.","El seu treball aporta noves interpretacions sobre la dimensió simbòlica de la seua obra.","Va presentar les seues conclusions en congressos internacionals de literatura comparada.","L''estudi és considerat una contribució important als estudis rodoredians actuals."]'),
('valenciano', 'bachillerato', '{2}', '["Manuel de Pedrolo va ser un escriptor català del segle XX molt prolífic.","Va escriure novel·les contes obres de teatre i assajos amb un compromís lingüístic constant.","La seua novel·la Mecanoscrit del segon origen és la més llegida i traduïda.","Pedrolo va experimentar amb diversos gèneres incloent la novel·la negra i la ciència-ficció.","És considerat un dels grans renovadors de la literatura catalana contemporània."]'),
('valenciano', 'bachillerato', '{2}', '["Un lingüista valencià va publicar un diccionari etimològic del valencià actual.","Va treballar durant més de deu anys en aquesta obra de referència erudita.","El diccionari recull l''origen i l''evolució de milers de paraules valencianes contemporànies.","Va consultar fonts antigues i modernes per documentar cada entrada amb rigor.","L''obra ha esdevingut una eina imprescindible per als estudis de filologia catalana."]'),
('valenciano', 'bachillerato', '{2}', '["Salvador Espriu va publicar La pell de brau l''any 1960 en plena dictadura.","El llibre és''una reflexió poètica sobre les diferents cultures i pobles ibèrics.","Espriu apel·la a la convivència i la tolerància entre els pobles d''Espanya.","L''obra va ser censurada parcialment però va circular clandestinament entre els intel·lectuals.","Avui és considerada un dels grans testimonis poètics de la resistència cultural catalana."]'),
('valenciano', 'bachillerato', '{2}', '["Una historiadora valenciana va publicar un estudi sobre la dona en la societat medieval.","Va analitzar documents notarials judicials i religiosos del Regne de València.","La seua investigació mostra la diversitat de rols femenins lluny dels tòpics tradicionals.","El llibre va aportar noves dades sobre la història social i de gènere medieval.","Va ser molt ben rebut pels especialistes i va guanyar un premi acadèmic important."]'),
('valenciano', 'bachillerato', '{2}', '["Jordi de Sant Jordi va ser un poeta valencià del segle XV vinculat a la cort.","Va servir el rei Alfons el Magnànim en diverses campanyes militars al Mediterrani.","Va escriure poemes amorosos amb una sensibilitat refinada i un estil molt elaborat.","La seua obra és considerada una continuació de la millor tradició trobadoresca catalana.","Va morir jove deixant un llegat poètic breu però d''una qualitat excepcional."]'),
('valenciano', 'bachillerato', '{2}', '["Una novel·lista valenciana va guanyar el Premi Sant Jordi de novel·la l''any passat.","La seua obra explorava els conflictes generacionals dins d''una família contemporània.","La crítica va destacar la finesa psicològica i la qualitat literària de l''estil.","La novel·la va ser traduïda al castellà i a diverses llengües estrangeres.","Avui és considerada una de les autores més''importants de la literatura catalana actual."]'),
('valenciano', 'bachillerato', '{2}', '["Ramon Llull va ser un filòsof i escriptor mallorquí del segle XIII molt rellevant.","Va escriure obres en català àrab i llatí amb una producció literària enorme.","Va desenvolupar un mètode lògic anomenat Ars Magna per dialogar entre religions.","La seua obra Blaquerna és considerada una de les primeres novel·les europees.","Llull és''el fundador de la prosa literària catalana medieval i un pensador europeu."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ed-fisica', 'bachillerato', '{1}', '["Un equipo de fútbol comienza la pretemporada con un test físico inicial.","El preparador físico diseña un plan progresivo de fuerza resistencia y velocidad.","Durante seis semanas los jugadores combinan entrenamientos en el gimnasio y en el campo.","Antes del primer partido oficial se realiza una evaluación final del rendimiento.","Los resultados muestran mejoras significativas en todas las cualidades físicas básicas medidas."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un alumno desea mejorar su capacidad cardiovascular para la carrera del instituto.","Su profesor le explica los principios del entrenamiento aeróbico continuo y por intervalos.","Comienza con sesiones suaves de treinta minutos tres veces por semana.","Tras un mes incorpora intervalos de mayor intensidad para estimular el sistema cardiovascular.","Al cabo de tres meses sus pruebas de resistencia mejoran de manera notable."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor introduce los conceptos básicos del calentamiento deportivo en clase teórica.","Explica que el calentamiento prepara el cuerpo evitando lesiones y mejorando el rendimiento.","Los alumnos aprenden a estructurar un calentamiento general y otro específico.","Practican distintos ejercicios de movilidad articular activación muscular y técnica deportiva.","Al final cada alumno diseña su propio calentamiento personalizado para su deporte favorito."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una estudiante decide preparar una prueba de acceso a un grado de ciencias del deporte.","Investiga las pruebas físicas exigidas y diseña un plan de entrenamiento detallado.","Trabaja durante meses fuerza salto velocidad y flexibilidad de manera equilibrada.","Realiza pruebas simulacro para controlar su progreso y ajustar el entrenamiento.","El día del examen consigue superar todos los mínimos exigidos con buena marca."]'),
('ed-fisica', 'bachillerato', '{1}', '["En clase se organiza un torneo de bádminton entre los alumnos del curso.","El profesor explica las reglas básicas y la técnica de los golpes principales.","Los alumnos practican el saque el clear el drop y el smash durante varias sesiones.","Después se forman parejas y comienza el torneo con eliminatorias sucesivas.","La final se disputa al final del trimestre con público formado por compañeros."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un grupo de estudiantes prepara una salida de senderismo por la sierra cercana.","Estudian el mapa la ruta el desnivel y la duración''estimada del recorrido.","Preparan el material adecuado calzado mochila agua comida y ropa de abrigo.","El día de la salida realizan la ruta a buen ritmo respetando los descansos.","Al regresar comparten la experiencia y reflexionan sobre los beneficios del senderismo."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un atleta presenta dolor en el tobillo después de un entrenamiento intenso.","Acude al fisioterapeuta para evaluar la lesión''y recibir el tratamiento adecuado.","El especialista diagnostica un esguince leve y recomienda reposo hielo compresión''y elevación.","Durante dos semanas sigue el tratamiento y realiza ejercicios suaves de recuperación.","Tras la recuperación vuelve gradualmente al entrenamiento sin sufrir nuevas molestias."]'),
('ed-fisica', 'bachillerato', '{1}', '["La profesora propone un proyecto sobre los valores del deporte en clase de bachillerato.","Cada grupo investiga un aspecto como el respeto el esfuerzo o el trabajo en equipo.","Realizan entrevistas a deportistas locales y consultan libros y documentales sobre el tema.","Preparan presentaciones digitales con vídeos imágenes y testimonios recogidos durante la investigación.","Las exposiciones generan un interesante debate sobre la educación''en valores a través del deporte."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un alumno con asma quiere participar en las clases de educación física sin problemas.","Habla con el profesor para explicar su situación''y los cuidados necesarios.","El profesor adapta los ejercicios y le indica cómo controlar su respiración durante el esfuerzo.","Aprende a usar correctamente el inhalador antes y durante la actividad si es necesario.","Gracias a la adaptación participa con normalidad y mejora su condición física general."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un grupo de alumnos prepara una coreografía para el festival de fin de curso.","Eligen una canción moderna y diseñan los pasos combinando ritmo y expresión corporal.","Ensayan varias semanas perfeccionando la sincronización''y los movimientos del grupo.","La profesora les ayuda a mejorar la postura y la coordinación''entre los integrantes.","El día del festival presentan la coreografía ante toda la comunidad educativa con éxito."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un estudiante interesado en el yoga investiga sus orígenes y beneficios para la salud.","Asiste a clases para aprender las posturas básicas y las técnicas de respiración.","Practica diariamente en casa siguiendo las indicaciones de su profesor de yoga.","Tras varios meses nota mejoras en su flexibilidad equilibrio y manejo del estrés.","Decide compartir su experiencia con sus compañeros mediante una pequeña presentación didáctica."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor organiza una sesión sobre los beneficios del ejercicio para la salud mental.","Explica cómo la actividad física libera endorfinas que mejoran el estado de ánimo.","Comparte estudios científicos que relacionan deporte regular con menor ansiedad y depresión.","Los alumnos comparten sus propias experiencias positivas con la actividad física personal.","Se anima a todos a integrar el ejercicio en su rutina diaria como hábito saludable."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un equipo de baloncesto femenino se prepara para un torneo intercentros importante.","La entrenadora diseña sesiones de táctica defensa y ataque durante varias semanas previas.","Las jugadoras mejoran su comunicación''y coordinación trabajando juntas en cada ejercicio.","En el torneo aplican las estrategias aprendidas y ganan varios partidos consecutivos.","Llegan a la final donde luchan con esfuerzo aunque finalmente acaban en segunda posición."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un alumno quiere mejorar su técnica de natación de cara a una competición''escolar.","Se inscribe en un curso intensivo donde un entrenador analiza sus puntos débiles.","Trabaja la respiración''el movimiento de brazos y la patada de manera específica.","Repite los ejercicios durante semanas hasta automatizar la técnica correcta del estilo.","En la competición logra rebajar sus tiempos personales y queda entre los primeros."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una clase de bachillerato organiza una jornada solidaria deportiva con otros centros.","Los alumnos planifican actividades como carrera popular partidos de fútbol y voleibol.","Cada participante aporta una pequeña inscripción destinada a una organización benéfica local.","El día del evento más de doscientos alumnos participan en las distintas pruebas.","La jornada combina deporte solidaridad y convivencia entre estudiantes de diferentes centros."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor enseña los principios básicos del entrenamiento de la flexibilidad en clase.","Explica los métodos estático dinámico activo y pasivo con ejemplos prácticos.","Los alumnos prueban cada método durante varias sesiones para identificar sus ventajas.","Aprenden a incorporar estiramientos adecuados al inicio y al final de cada sesión.","Comprueban cómo su flexibilidad mejora gradualmente con la práctica regular y constante."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna quiere mejorar su salto vertical para jugar mejor al voleibol.","El profesor le explica los principios del entrenamiento pliométrico y le diseña ejercicios.","Realiza saltos al cajón multisaltos y sentadillas explosivas tres días por semana.","Tras dos meses comprueba que su altura de salto ha aumentado varios centímetros.","Esta mejora le permite rematar con más fuerza durante los partidos del equipo."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor introduce los conceptos de fuerza resistencia y velocidad como cualidades físicas básicas.","Explica cómo cada cualidad se desarrolla con métodos específicos y entrenamientos diferentes.","Realiza pruebas iniciales para evaluar el nivel de cada alumno en cada cualidad.","Diseña un plan de entrenamiento personalizado para mejorar las cualidades menos desarrolladas.","Al final del trimestre repite las pruebas para comprobar los progresos individuales obtenidos."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un estudiante decide entrenar para subir a un pico de tres mil metros.","Investiga las exigencias físicas y empieza a caminar largas distancias todas las semanas.","Incorpora ejercicios de fuerza para fortalecer las piernas y la espalda gradualmente.","Realiza varias salidas a montañas más bajas para acostumbrarse al desnivel y altura.","El día de la cumbre alcanza la cima sintiendo gran satisfacción personal por su esfuerzo."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna participa en un proyecto sobre alimentación''y rendimiento deportivo.","Investiga los nutrientes necesarios para los deportistas y los momentos clave para consumirlos.","Diseña un menú equilibrado para deportistas adolescentes basado en sus investigaciones.","Presenta su trabajo en clase con tablas gráficos y ejemplos prácticos para sus compañeros.","El proyecto recibe la felicitación del profesor por su rigor y aplicación práctica."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un grupo de alumnos descubre el ultimate frisbee como nuevo deporte alternativo divertido.","El profesor explica las reglas básicas centradas en el juego limpio y respetuoso.","Practican los lanzamientos básicos y las recepciones durante varias clases consecutivas.","Forman equipos mixtos y disputan partidos aplicando las reglas del autoarbitraje deportivo.","Disfrutan de un deporte nuevo que combina técnica táctica y valores positivos."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un alumno se siente desmotivado en las clases de educación física al inicio del curso.","Habla con la profesora para expresar sus dudas y buscar actividades más''adecuadas.","La profesora le propone descubrir deportes alternativos que no haya practicado antes.","Prueba escalada deportiva tiro con arco y orientación durante diferentes sesiones del trimestre.","Encuentra una nueva pasión por la escalada y se inscribe en un club local."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor organiza una sesión sobre prevención de lesiones deportivas en clase teórica.","Explica los factores de riesgo y las medidas básicas para evitar lesiones comunes.","Muestra ejemplos de calentamientos estiramientos y ejercicios de fortalecimiento preventivo.","Los alumnos diseñan en grupos un protocolo de prevención para su deporte favorito.","Las exposiciones permiten compartir conocimientos prácticos entre todos los compañeros del aula."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna quiere mejorar su técnica de carrera de cara a la prueba de mil metros.","Su profesor le explica la importancia de la zancada respiración''y el ritmo constante.","Trabaja durante semanas la técnica con ejercicios específicos y series controladas.","Realiza pruebas regulares para medir su progreso y ajustar el entrenamiento.","Consigue mejorar su marca personal en más de quince segundos en pocas semanas."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor introduce el concepto de actividad física saludable durante toda la vida.","Explica cómo la práctica regular previene enfermedades y mejora la calidad de vida.","Los alumnos investigan recomendaciones de la Organización Mundial de la Salud para diferentes edades.","Diseñan un plan personal de actividad física para mantener a lo largo del curso.","Reflexionan sobre la importancia de adquirir hábitos saludables desde la juventud."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una clase de bachillerato organiza un partido amistoso de fútbol con un colegio vecino.","Antes del partido los alumnos preparan el campo y revisan el material necesario.","Durante el encuentro aplican las normas del juego limpio y respetan al rival.","Tras el partido comparten una merienda y conversan con los jugadores del otro equipo.","La experiencia fortalece los valores deportivos y la convivencia entre estudiantes de centros diferentes."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor introduce el ajedrez como actividad complementaria en las clases de educación física.","Explica las relaciones entre el deporte mental y el rendimiento físico de los alumnos.","Los alumnos aprenden las reglas básicas y juegan partidas durante varias sesiones consecutivas.","Organizan un pequeño torneo interno con eliminatorias y final entre los mejores clasificados.","Descubren cómo la concentración''estratégica también forma parte del concepto amplio del deporte."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna investiga la historia del deporte femenino para un trabajo de clase.","Descubre los obstáculos que enfrentaron las mujeres para acceder a la práctica deportiva.","Selecciona varias deportistas pioneras y elabora una presentación con fotos y datos relevantes.","Su trabajo es elogiado por el profesor y compartido con el resto del grupo.","La investigación despierta en sus compañeras un mayor interés por las atletas históricas."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor diseña una unidad didáctica sobre los deportes de raqueta tradicionales.","Los alumnos descubren tenis bádminton pádel y tenis de mesa en sesiones diferentes.","Aprenden las reglas básicas y las técnicas fundamentales de cada uno de estos deportes.","Comparan las similitudes y diferencias entre las distintas modalidades practicadas en clase.","Al final eligen su deporte de raqueta favorito para profundizar en él durante el trimestre."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un grupo de estudiantes organiza una jornada de juegos populares tradicionales en el patio.","Investigan juegos antiguos como la rayuela el pañuelo y el corro para presentarlos.","Preparan los materiales necesarios y explican las reglas a sus compañeros del centro.","Durante la jornada todos los alumnos participan y descubren juegos olvidados con entusiasmo.","La actividad reivindica el valor cultural y educativo de los juegos populares tradicionales."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna decide preparar una oposición''a bombera y necesita superar pruebas físicas.","Investiga los requisitos y diseña un plan de entrenamiento específico para cada prueba.","Trabaja fuerza resistencia natación''y trepa varias horas semanales durante muchos meses.","Realiza pruebas simulacro periódicas para evaluar su progreso y ajustar el entrenamiento.","El día del examen logra superar todas las pruebas con marcas excelentes."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor presenta la unidad didáctica sobre actividades en el medio natural.","Explica los principios básicos de la orientación con mapa y brújula tradicional.","Los alumnos practican en el patio del centro con balizas y mapas adaptados.","Después realizan una salida a un parque cercano para aplicar lo aprendido en clase.","La actividad combina ejercicio físico capacidad de orientación''y disfrute al aire libre."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un alumno quiere mejorar su fuerza de tren superior para escalar mejor en su club.","Diseña un plan que incluye dominadas flexiones y ejercicios con suspensión gradual.","Entrena tres veces por semana durante dos meses con progresión controlada y planificada.","Comprueba que su rendimiento en escalada mejora notablemente tras este entrenamiento dirigido.","Comparte su experiencia con compañeros interesados en empezar a practicar escalada deportiva."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una clase organiza un proyecto sobre los Juegos Olímpicos antiguos y modernos.","Los alumnos investigan en grupos diferentes aspectos como historia deportes valores y curiosidades.","Cada grupo prepara una presentación creativa para compartir con el resto de compañeros.","Las exposiciones incluyen vídeos imágenes y demostraciones prácticas de algunos deportes olímpicos.","El proyecto culmina con un debate sobre los valores olímpicos en la sociedad actual."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor explica cómo realizar correctamente la maniobra de reanimación cardiopulmonar básica.","Muestra los pasos a seguir desde la valoración''inicial hasta las compresiones torácicas.","Los alumnos practican en parejas con maniquíes simulando situaciones de emergencia reales.","Aprenden también''el uso del desfibrilador externo automático y sus indicaciones básicas.","Esta formación práctica puede salvar vidas en situaciones de parada cardíaca repentina."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna interesada en el atletismo participa en una competición regional de salto.","Antes del evento sigue un plan específico de entrenamiento técnico y físico durante meses.","En la competición consigue saltar su mejor marca personal en salto de longitud.","Queda en tercera posición''y obtiene una medalla por su excelente actuación deportiva.","Su entrenadora la felicita y la anima a seguir progresando en esta especialidad."]'),
('ed-fisica', 'bachillerato', '{1}', '["Un grupo de estudiantes propone organizar un club deportivo extraescolar en el centro.","Hablan con la dirección''y obtienen permiso para utilizar las instalaciones por las tardes.","Cada miembro propone actividades diferentes como fútbol baloncesto y otros deportes alternativos.","Establecen un calendario semanal y se distribuyen las responsabilidades de organización del club.","En pocos meses el club cuenta con una treintena de socios entusiastas y comprometidos."]'),
('ed-fisica', 'bachillerato', '{1}', '["El profesor introduce el concepto de condición física relacionada con la salud.","Explica los componentes principales y cómo se evalúan mediante pruebas estandarizadas.","Los alumnos realizan una batería de pruebas para conocer su nivel inicial actual.","Cada uno establece objetivos personales realistas para mejorar durante el trimestre académico.","Al final del trimestre repiten las pruebas para comprobar los progresos individuales obtenidos."]'),
('ed-fisica', 'bachillerato', '{1}', '["Una alumna investiga las diferencias entre deporte recreativo deporte educativo y alto rendimiento.","Lee artículos consulta documentales y entrevista a deportistas de diferentes niveles competitivos.","Sintetiza la información''en un trabajo escrito con conclusiones claras y bien argumentadas.","Presenta su trabajo en clase generando un interesante debate entre sus compañeros del aula.","El profesor felicita la calidad del análisis y la riqueza de las fuentes consultadas."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ed-fisica', 'bachillerato', '{2}', '["Un atleta de élite planifica su temporada alrededor de un campeonato internacional importante.","Su entrenador diseña una periodización con fases de acumulación''intensificación''y competición.","Durante los meses previos trabaja específicamente la fuerza explosiva y la velocidad máxima.","En la fase precompetitiva ajusta la intensidad para llegar en el momento óptimo.","Consigue su mejor marca personal en la competición''y queda en el podio internacional."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante prepara la prueba de acceso al grado de ciencias del deporte.","Investiga los baremos físicos exigidos para acceder al grado universitario.","Diseña un plan de entrenamiento específico que aborda cada una de las pruebas requeridas.","Durante el curso entrena fuerza resistencia salto velocidad y técnica deportiva.","En el examen final supera todos los mínimos exigidos y obtiene la plaza universitaria."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor explica los principales métodos de entrenamiento de la fuerza máxima.","Detalla las cargas porcentajes y repeticiones recomendadas para cada objetivo específico.","Los alumnos diseñan rutinas adaptadas a sus capacidades y objetivos personales.","Aplican el plan en el gimnasio durante varias semanas con supervisión técnica adecuada.","Al final del periodo evalúan los progresos comparando con los datos iniciales registrados."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna quiere preparar una media maratón como reto personal de fin de curso.","Su profesor le diseña un plan de entrenamiento progresivo de doce semanas.","Combina rodajes largos series intervalos y sesiones de recuperación''activa cuidadosamente equilibradas.","Cuida la alimentación''y el descanso para optimizar la adaptación''al entrenamiento.","El día de la prueba completa la distancia con el tiempo objetivo que se había marcado."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de alumnos investiga los beneficios del ejercicio en personas mayores.","Visitan una residencia donde realizan un programa de actividad física adaptada con los residentes.","Diseñan ejercicios sencillos para mejorar la movilidad fuerza y equilibrio en personas mayores.","Comprueban cómo la actividad regular mejora el estado de ánimo y la autonomía.","La experiencia les hace valorar la importancia del ejercicio para envejecer con calidad."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor introduce los conceptos básicos de fisiología del ejercicio para el bachillerato.","Explica cómo el cuerpo responde y se adapta al esfuerzo físico continuado.","Detalla los sistemas energéticos aeróbico anaeróbico láctico y aláctico con ejemplos prácticos.","Los alumnos identifican qué sistema utiliza cada deporte según su intensidad y duración.","Esta base teórica les ayuda a entender mejor el diseño del entrenamiento deportivo."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante desarrolla un proyecto de investigación sobre el dopaje en el deporte profesional.","Lee artículos científicos y consulta el código mundial antidopaje vigente actualmente.","Analiza casos famosos de dopaje y sus consecuencias deportivas legales y personales.","Reflexiona sobre los valores éticos del deporte y las presiones que sufren los deportistas.","Presenta sus conclusiones en clase generando un interesante debate sobre ética deportiva."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un equipo de balonmano se prepara para los campeonatos autonómicos universitarios.","El entrenador combina sesiones técnicas tácticas físicas y partidos amistosos durante semanas.","Los jugadores mejoran su comunicación coordinación''y nivel competitivo trabajando en equipo.","En el campeonato superan las primeras rondas con buenas actuaciones colectivas.","Llegan a semifinales donde caen ante el campeón defensor pero con buena imagen."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor introduce los principios del entrenamiento integrado en deportes colectivos.","Explica cómo combinar técnica táctica condición física y estrategia en una misma sesión.","Diseña ejercicios específicos donde los alumnos trabajan varios aspectos simultáneamente.","Los alumnos comprueban la eficacia de esta metodología comparada con el entrenamiento analítico.","Aprenden a planificar sesiones más completas y motivadoras para sus futuros equipos."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna investiga los efectos del calentamiento sobre el rendimiento deportivo posterior.","Diseña un experimento donde compara diferentes tipos de calentamiento con sus compañeras.","Mide variables como salto vertical sprint y agilidad después de cada protocolo.","Analiza los datos obtenidos y los presenta en un informe detallado y científico.","Sus conclusiones sugieren que el calentamiento dinámico mejora más''el rendimiento explosivo."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un profesor explica las claves de la planificación deportiva a largo plazo.","Detalla los conceptos de macrociclo mesociclo y microciclo en la organización del entrenamiento.","Los alumnos diseñan una planificación''anual para un deporte de su elección.","Cada plan incluye objetivos volúmenes intensidades y métodos de entrenamiento específicos.","Las planificaciones son evaluadas por el profesor que sugiere mejoras y ajustes técnicos."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante quiere preparar un triatlón sprint como reto personal de fin de curso.","Investiga las distancias y diseña un plan que combina natación ciclismo y carrera.","Entrena seis días por semana cuidando alimentación descanso y técnica de cada disciplina.","Realiza simulacros para acostumbrarse a las transiciones entre las diferentes modalidades.","El día del triatlón completa la prueba en el tiempo objetivo y celebra su logro."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor organiza una unidad didáctica sobre primeros auxilios para situaciones deportivas.","Los alumnos aprenden a actuar ante esguinces fracturas hemorragias y pérdidas de conocimiento.","Practican en parejas las técnicas básicas con simulaciones de situaciones reales del deporte.","Aprenden también''a usar el desfibrilador externo automático en una parada cardíaca.","La formación les prepara para responder eficazmente ante posibles emergencias deportivas habituales."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna investiga la relación''entre actividad física y salud mental adolescente.","Lee estudios científicos y entrevista a psicólogos deportivos especializados en jóvenes.","Sintetiza la información''en un trabajo que destaca los beneficios del ejercicio regular.","Presenta sus conclusiones en una jornada del centro sobre bienestar y juventud.","Su trabajo es premiado y compartido con otros institutos como recurso educativo valioso."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de estudiantes diseña un proyecto comunitario para fomentar la actividad física.","Identifican las necesidades del barrio y proponen actividades para distintas edades.","Organizan caminatas semanales clases gratuitas de yoga y partidos abiertos en el parque.","La iniciativa cuenta con el apoyo del ayuntamiento y de varios comercios locales.","En pocos meses participan más de cien personas en las distintas actividades organizadas."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor explica las bases del entrenamiento de la flexibilidad para diferentes deportes.","Detalla los métodos estático activo dinámico balístico y de facilitación neuromuscular.","Los alumnos prueban cada método y analizan sus ventajas y aplicaciones específicas.","Diseñan rutinas adaptadas a su deporte preferido y las practican durante varias semanas.","Comprueban cómo su flexibilidad mejora gracias a la práctica regular y planificada."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna decide convertirse en monitora de actividades deportivas para niños pequeños.","Realiza un curso específico durante varios meses combinando teoría y prácticas reales.","Aprende metodología pedagogía y seguridad para trabajar con grupos infantiles.","Realiza prácticas en una escuela deportiva supervisada por profesionales experimentados.","Al obtener el título consigue su primer trabajo como monitora en el club local."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un profesor organiza una salida de varios días por la sierra para el bachillerato.","Los alumnos preparan el material la ruta y la logística con la guía del docente.","Aprenden a montar tiendas cocinar al aire libre y orientarse con mapa y brújula.","Durante los días en la montaña realizan rutas de senderismo y actividades de cooperación.","La experiencia fortalece la convivencia y crea un fuerte vínculo entre los participantes."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante investiga el papel del entrenamiento mental en el rendimiento deportivo.","Lee libros de psicología deportiva y entrevista a deportistas locales sobre el tema.","Aprende técnicas como visualización''autodiálogo y control de la activación mental.","Aplica las técnicas a su propio entrenamiento de atletismo durante varios meses.","Comprueba que su rendimiento mejora gracias al trabajo psicológico junto al físico."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de estudiantes organiza un torneo benéfico de baloncesto en el instituto.","Convocan a diferentes equipos de varios centros educativos del entorno cercano.","La inscripción se destina íntegramente a una organización local que ayuda a familias necesitadas.","El día del torneo participan más de cien jugadores en una jornada deportiva festiva.","La iniciativa combina deporte solidaridad y valores positivos en un ambiente muy agradable."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor introduce el concepto de rendimiento deportivo y sus factores condicionantes.","Explica los aspectos físicos técnicos tácticos psicológicos y contextuales del rendimiento.","Los alumnos analizan cómo cada factor influye en distintos deportes con ejemplos concretos.","Diseñan programas de mejora integrales para mejorar el rendimiento en su deporte preferido.","Esta visión global les ayuda a comprender la complejidad del deporte de alto nivel."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna investiga las salidas profesionales relacionadas con la actividad física y el deporte.","Consulta planes de estudios universitarios y entrevista a profesionales de varios sectores.","Conoce salidas como entrenador fisioterapeuta nutricionista deportivo profesor o gestor.","Sintetiza la información''en una guía útil que comparte con sus compañeros de bachillerato.","Decide finalmente estudiar ciencias del deporte por la riqueza de las salidas profesionales."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un equipo de fútbol se prepara para una temporada intensa con muchas competiciones simultáneas.","El cuerpo técnico planifica entrenamientos partidos y descansos para evitar el agotamiento.","Los jugadores cuidan especialmente la alimentación''el sueño y la hidratación para rendir.","Durante la temporada el equipo logra clasificarse para varias fases finales importantes.","La buena planificación''es la clave del éxito y permite mantener el rendimiento."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor explica los principios del entrenamiento concurrente combinando fuerza y resistencia.","Detalla los efectos sobre la adaptación''y las posibles interferencias entre ambas cualidades.","Los alumnos diseñan rutinas que respetan los tiempos adecuados entre los dos tipos de trabajo.","Aplican el plan durante varias semanas y registran sus progresos en una hoja de seguimiento.","Comprueban que la combinación correcta mejora ambas cualidades sin perjudicar ninguna."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante interesada en la danza investiga sus beneficios físicos psicológicos y sociales.","Visita varias escuelas de danza de su ciudad y entrevista a profesores y bailarines.","Sintetiza la información''en un trabajo que aborda la danza como actividad física integral.","Su exposición''incluye demostraciones prácticas de varios estilos como ballet hiphop y contemporáneo.","Sus compañeros descubren la danza como una forma artística y deportiva muy completa."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de estudiantes diseña un proyecto interdisciplinar sobre deporte y medio ambiente.","Investigan el impacto ambiental de las grandes competiciones y los eventos deportivos masivos.","Proponen medidas para reducir la huella ecológica de la práctica deportiva habitual.","Realizan una limpieza de un sendero local como acción concreta y simbólica del proyecto.","La iniciativa les hace tomar conciencia de la responsabilidad ambiental de los deportistas."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor presenta las técnicas básicas del entrenamiento funcional para la vida diaria.","Explica cómo mejorar fuerza equilibrio coordinación''y movilidad con ejercicios prácticos.","Los alumnos diseñan circuitos funcionales utilizando material sencillo y movimientos naturales.","Aplican los circuitos durante varias semanas notando mejoras en su condición física general.","Aprenden que el entrenamiento funcional es muy útil para mantenerse en forma toda la vida."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna investiga la historia del olimpismo desde sus orígenes hasta la actualidad.","Estudia los Juegos Olímpicos antiguos y su revival moderno en el siglo XIX.","Analiza los valores olímpicos y su evolución''a lo largo de las distintas ediciones.","Presenta su trabajo con vídeos imágenes y datos estadísticos sobre los Juegos.","La exposición despierta el interés de sus compañeros por el movimiento olímpico mundial."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un profesor diseña una unidad didáctica sobre los juegos cooperativos en el aula.","Explica cómo estos juegos fomentan valores como la solidaridad la inclusión''y el trabajo en equipo.","Los alumnos practican varios juegos cooperativos analizando sus dinámicas y aprendizajes.","Reflexionan sobre las diferencias entre la cooperación''y la competición''en el deporte.","La unidad les muestra otra manera de entender el juego más''allá de la rivalidad."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante prepara una memoria final sobre su evolución deportiva durante el bachillerato.","Recopila datos de pruebas físicas registros de entrenamientos y reflexiones personales.","Analiza sus progresos identificando los aspectos en los que más''ha mejorado durante los dos años.","Establece nuevos objetivos para el futuro relacionados con la actividad física en su vida.","Su memoria final muestra una madurez deportiva y un compromiso saludable claros."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de estudiantes organiza una jornada deportiva inclusiva con personas con discapacidad.","Contactan con asociaciones locales y diseñan actividades adaptadas para todos los participantes.","Practican deportes adaptados como goalball boccia y baloncesto en silla de ruedas.","La jornada permite a los estudiantes vivir el deporte desde una perspectiva inclusiva.","Los participantes con discapacidad disfrutan compartiendo su experiencia y enseñando técnicas adaptadas."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor explica los principios del entrenamiento interválico de alta intensidad o HIIT.","Detalla los protocolos más conocidos como el método Tabata o las series cortas intensas.","Los alumnos diseñan sesiones HIIT adaptadas a su nivel físico y objetivos personales.","Aplican las sesiones durante varias semanas notando mejoras en su capacidad cardiovascular.","Comprueban la eficiencia de este método que requiere poco tiempo pero exige gran intensidad."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna investiga el papel del descanso en la recuperación''y mejora deportiva.","Lee artículos científicos sobre fisiología del sueño y sus efectos sobre el rendimiento.","Aprende sobre el descanso activo el descanso pasivo y el sueño profundo reparador.","Sintetiza la información''en una guía práctica para deportistas amateur y profesionales.","Sus compañeros descubren la importancia del descanso como parte esencial del entrenamiento."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de estudiantes desarrolla un proyecto sobre nutrición''específica del deportista.","Consultan con un nutricionista profesional para conocer las necesidades de cada disciplina.","Diseñan menús semanales para diferentes deportes adaptando los aportes energéticos necesarios.","Comparten sus propuestas con los equipos deportivos del centro educativo durante varias sesiones.","Algunos compañeros adoptan los menús''y notan mejoras en su rendimiento y recuperación."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor introduce el concepto de prevención de lesiones a través del entrenamiento propioceptivo.","Explica el papel de los receptores articulares y musculares en el control del movimiento.","Los alumnos practican ejercicios sobre superficies inestables como bosus y plataformas.","Aprenden a integrar el trabajo propioceptivo en sus rutinas habituales de entrenamiento.","Comprueban que mejora el equilibrio reduce el riesgo de lesiones y aumenta el rendimiento."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una alumna prepara una prueba específica para entrar en un cuerpo de seguridad.","Investiga los baremos exigidos y diseña un entrenamiento para superar cada prueba física.","Trabaja durante meses fuerza resistencia velocidad agilidad y técnica de natación.","Realiza simulacros frecuentes para evaluar su progreso y ajustar el entrenamiento personalizado.","En el examen oficial supera todas las pruebas con marcas excelentes y obtiene plaza."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor organiza una unidad didáctica sobre los deportes de combate como disciplinas educativas.","Los alumnos descubren judo karate taekwondo y otras artes marciales en sesiones específicas.","Aprenden los valores tradicionales como el respeto la disciplina y el autocontrol personal.","Practican técnicas básicas con seguridad y bajo la supervisión de un experto invitado.","Descubren un mundo nuevo que combina deporte filosofía y desarrollo personal integral."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante investiga las diferencias fisiológicas entre hombres y mujeres en el deporte.","Lee estudios científicos sobre composición corporal capacidad pulmonar y fuerza máxima.","Analiza cómo estas diferencias influyen en el rendimiento de cada disciplina deportiva concreta.","Presenta sus conclusiones generando un interesante debate sobre equidad e inclusión deportiva.","El profesor felicita el rigor de su trabajo y la calidad de su exposición."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor presenta una unidad didáctica sobre la actividad física en la era digital.","Analiza cómo las nuevas tecnologías han transformado el entrenamiento y el seguimiento deportivo.","Los alumnos investigan apps wearables y programas de entrenamiento online disponibles.","Diseñan un plan personal usando herramientas digitales y comparten resultados con sus compañeros.","Reflexionan sobre las ventajas y los riesgos de la digitalización''en el ámbito deportivo."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una clase prepara un proyecto sobre los efectos del sedentarismo en la salud juvenil.","Investigan datos estadísticos sobre el aumento del sedentarismo en adolescentes europeos actuales.","Proponen estrategias para reducir el tiempo de pantalla y aumentar la actividad física diaria.","Aplican las estrategias en su propia rutina durante varias semanas con compromiso real.","Comprueban mejoras en su forma física y en su estado de ánimo general."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un equipo de voleibol se prepara para los campeonatos universitarios autonómicos importantes.","La entrenadora trabaja durante meses la técnica táctica y la condición física específica.","Las jugadoras participan en partidos amistosos para mejorar la competición real bajo presión.","En el campeonato superan las primeras rondas y llegan hasta la final emocionante.","Logran proclamarse campeonas tras un partido reñido y muy emocionante para el público."]'),
('ed-fisica', 'bachillerato', '{2}', '["El profesor explica las claves de la planificación del entrenamiento deportivo a largo plazo.","Detalla los principios de individualización progresión continuidad variedad y especificidad del entrenamiento.","Los alumnos diseñan un plan anual para un deporte de su elección personal.","Cada plan incluye objetivos específicos volúmenes intensidades y métodos detallados de entrenamiento.","El profesor evalúa los planes y propone mejoras para optimizar la planificación deportiva."]'),
('ed-fisica', 'bachillerato', '{2}', '["Una estudiante investiga la influencia del deporte en la educación''en valores adolescentes.","Lee artículos sobre pedagogía deportiva y entrevista a entrenadores y profesores experimentados.","Sintetiza la información''en un trabajo que destaca el potencial educativo del deporte.","Presenta sus conclusiones en una jornada del centro sobre educación''y valores en bachillerato.","Su trabajo es premiado y compartido con otros centros educativos como recurso valioso."]'),
('ed-fisica', 'bachillerato', '{2}', '["Un grupo de estudiantes organiza un proyecto sobre actividad física y prevención de enfermedades.","Investigan cómo el ejercicio regular previene problemas como obesidad diabetes e hipertensión.","Diseñan una campaña informativa con folletos pósteres y charlas para el centro educativo.","La campaña sensibiliza a los compañeros sobre la importancia de mantenerse activo siempre.","La iniciativa recibe el apoyo del centro de salud local y de los padres."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('economia', 'bachillerato', '{1}', '["Una familia recibe sus ingresos mensuales a través de los salarios de sus miembros.","Destina parte del dinero a cubrir necesidades básicas como alimentación vivienda y transporte.","El resto se reparte entre ahorro pago de préstamos y consumo discrecional.","Cuando el ingreso aumenta la familia puede ahorrar más''o invertir en bienes duraderos.","Un buen presupuesto familiar permite afrontar imprevistos y planificar metas a largo plazo."]'),
('economia', 'bachillerato', '{1}', '["Una empresa identifica una oportunidad para introducir un nuevo producto en el mercado.","Realiza estudios de viabilidad económica análisis de costes y previsión de ventas.","Diseña una estrategia de marketing y fija el precio inicial del producto.","Lanza el producto al mercado y monitoriza la respuesta de los consumidores.","Tras unos meses ajusta su estrategia según los resultados obtenidos en las ventas."]'),
('economia', 'bachillerato', '{1}', '["El gobierno detecta un aumento preocupante del desempleo en varias regiones del país.","Aplica una política fiscal expansiva aumentando el gasto público y reduciendo impuestos.","Las empresas reciben más pedidos y comienzan a contratar nuevos trabajadores.","La actividad económica se reactiva y las familias recuperan capacidad de consumo gradual.","Los indicadores macroeconómicos mejoran y la confianza del país regresa progresivamente."]'),
('economia', 'bachillerato', '{1}', '["Un agricultor decide diversificar su producción para reducir riesgos económicos personales.","Analiza qué cultivos demanda el mercado local y nacional antes de decidir.","Combina cultivos tradicionales con otros más rentables y de demanda creciente.","Invierte en tecnología de riego eficiente para mejorar el rendimiento de las cosechas.","Sus ingresos aumentan y consigue estabilidad económica frente a las fluctuaciones del mercado."]'),
('economia', 'bachillerato', '{1}', '["Un consumidor planea comprar un coche nuevo y necesita financiarlo a través de préstamo.","Compara las ofertas de varios bancos analizando intereses comisiones y plazos disponibles.","Elige el préstamo que mejor se adapta a sus ingresos y capacidad de pago.","Firma el contrato tras comprobar todos los términos y condiciones de la operación.","Durante los siguientes años cumple con los pagos puntualmente sin retrasos."]'),
('economia', 'bachillerato', '{1}', '["El banco central observa una inflación creciente que preocupa a la economía nacional.","Decide subir los tipos de interés para frenar el consumo y la concesión de crédito.","Las empresas y familias reducen sus solicitudes de préstamos por el coste mayor.","La demanda interna baja y los precios comienzan gradualmente a estabilizarse.","La política monetaria contractiva consigue controlar la inflación tras varios meses sostenidos."]'),
('economia', 'bachillerato', '{1}', '["Un emprendedor joven decide montar una pequeña tienda online en su ciudad.","Calcula los costes de inversión''inicial el local virtual y los productos a vender.","Solicita un microcrédito a una entidad especializada en apoyo al emprendimiento juvenil.","Obtiene la financiación''y abre la tienda en menos de un mes.","Las primeras ventas confirman que su modelo de negocio funciona y puede crecer."]'),
('economia', 'bachillerato', '{1}', '["Una empresa exportadora analiza los efectos del tipo de cambio en sus ventas.","Cuando el euro se aprecia sus productos se encarecen para clientes extranjeros.","Las ventas internacionales descienden y los beneficios se ven reducidos significativamente.","La empresa decide contratar coberturas financieras para protegerse del riesgo cambiario.","Esta estrategia le permite mantener márgenes estables a pesar de las fluctuaciones."]'),
('economia', 'bachillerato', '{1}', '["Un consumidor decide ahorrar para alcanzar un objetivo a medio plazo importante.","Establece un presupuesto mensual identificando gastos prescindibles que puede recortar.","Domicilia un porcentaje fijo de su nómina hacia una cuenta de ahorro específica.","Después de dos años consigue reunir la cantidad necesaria para su proyecto personal.","La constancia y la disciplina financiera le permiten cumplir su objetivo sin problemas."]'),
('economia', 'bachillerato', '{1}', '["El estado decide aumentar la inversión''en infraestructuras para impulsar el desarrollo.","Construye nuevas carreteras vías ferroviarias y centros tecnológicos en varias regiones.","Las empresas se benefician al reducir costes logísticos y mejorar la conectividad regional.","El empleo aumenta tanto en obras como en sectores beneficiados por la inversión.","La economía crece y el país mejora su competitividad internacional a largo plazo."]'),
('economia', 'bachillerato', '{1}', '["Una empresa familiar tradicional debe modernizarse para competir con grandes cadenas comerciales.","Analiza sus puntos fuertes y débiles antes de implementar cualquier cambio importante.","Invierte en formación digital del personal y en nuevos canales de venta online.","Mantiene su trato personalizado con los clientes habituales del negocio familiar.","Logra adaptarse a los nuevos tiempos sin perder su esencia ni su clientela."]'),
('economia', 'bachillerato', '{1}', '["Un trabajador autónomo gestiona personalmente su contabilidad y obligaciones fiscales mensuales.","Lleva un registro detallado de ingresos gastos y facturas emitidas durante el año.","Cada trimestre presenta las declaraciones de IVA y los pagos fraccionados de IRPF.","Al cierre del ejercicio realiza la declaración''anual y calcula el resultado final.","Esta gestión rigurosa le permite cumplir con sus obligaciones y planificar su negocio."]'),
('economia', 'bachillerato', '{1}', '["Una cooperativa de trabajadores decide ampliar su negocio para crecer en el mercado.","Los socios se reúnen en asamblea para debatir las opciones de inversión disponibles.","Tras varias propuestas votan por la apertura de una segunda sede en otra ciudad.","Aportan fondos propios y solicitan financiación''a una entidad de banca ética.","La nueva sede comienza a funcionar y aporta beneficios a todos los socios."]'),
('economia', 'bachillerato', '{1}', '["El gobierno introduce un nuevo impuesto sobre productos perjudiciales para la salud.","Las empresas afectadas suben los precios trasladando parte del impuesto a los consumidores.","La demanda de estos productos disminuye gracias al efecto disuasorio del precio mayor.","El estado recauda fondos adicionales que destina a programas sanitarios públicos.","La medida combina objetivos recaudatorios con beneficios para la salud pública nacional."]'),
('economia', 'bachillerato', '{1}', '["Un estudiante recibe una herencia inesperada y decide invertir parte del dinero.","Acude a un asesor financiero para conocer las opciones disponibles según su perfil.","El asesor le recomienda una cartera diversificada con bajo riesgo y rentabilidad moderada.","Decide invertir parte en fondos de renta fija y otra parte en renta variable.","A largo plazo su inversión crece mientras mantiene un fondo de emergencia disponible."]'),
('economia', 'bachillerato', '{1}', '["Una empresa decide aplicar criterios sostenibles en toda su cadena de producción.","Reduce el consumo energético reciclando materiales y utilizando proveedores locales.","Inicialmente los costes aumentan ligeramente por la inversión''en nuevas tecnologías.","Sin embargo los consumidores valoran positivamente el compromiso ambiental y aumentan las ventas.","A medio plazo la empresa mejora su rentabilidad y su reputación''en el mercado."]'),
('economia', 'bachillerato', '{1}', '["El precio del petróleo aumenta significativamente a nivel internacional por motivos geopolíticos.","Las empresas españolas que dependen del crudo ven crecer sus costes de producción.","El transporte y la energía se encarecen afectando a multitud de sectores económicos.","Los precios al consumidor aumentan generando inflación''y pérdida de poder adquisitivo.","El gobierno toma medidas para amortiguar el impacto sobre las familias más vulnerables."]'),
('economia', 'bachillerato', '{1}', '["Una asociación de consumidores detecta prácticas comerciales abusivas en una gran cadena.","Recopila pruebas y testimonios de afectados antes de presentar la denuncia formal.","Las autoridades de consumo investigan el caso y verifican las irregularidades reportadas.","La empresa recibe una sanción''económica y se ve obligada a cambiar sus prácticas.","La acción de la asociación protege los derechos de los consumidores en el mercado."]'),
('economia', 'bachillerato', '{1}', '["Un país''en desarrollo recibe inversión''extranjera directa para construir nuevas fábricas.","Las multinacionales se benefician de mano de obra más''económica y recursos disponibles.","El país receptor genera empleo y transfiere tecnología desde las empresas extranjeras.","Sin embargo surge el riesgo de dependencia externa y de impactos ambientales locales.","El gobierno regula la inversión para garantizar beneficios mutuos y sostenibles."]'),
('economia', 'bachillerato', '{1}', '["Una pareja joven decide comprar su primera vivienda en lugar de seguir alquilando.","Calcula su capacidad de endeudamiento basándose en los ingresos familiares mensuales.","Compara hipotecas de varios bancos analizando tipos plazos y comisiones aplicables.","Elige una hipoteca a tipo fijo para mayor seguridad ante cambios económicos futuros.","Firma la operación''y comienza una nueva etapa con su propia vivienda."]'),
('economia', 'bachillerato', '{1}', '["El banco central observa una recesión''en la economía y decide actuar con rapidez.","Reduce los tipos de interés para estimular el consumo y la inversión privada.","Los créditos se vuelven más baratos y las empresas comienzan a invertir nuevamente.","Las familias también''aprovechan para comprar bienes duraderos y solicitar préstamos.","La actividad económica se recupera tras varios trimestres de aplicación de la política."]'),
('economia', 'bachillerato', '{1}', '["Una empresa decide contratar a personal con discapacidad para diversificar su plantilla.","Adapta los puestos de trabajo y proporciona la formación''específica necesaria.","Recibe ayudas y bonificaciones del estado por incorporar colectivos vulnerables al empleo.","Los nuevos trabajadores se integran perfectamente y aportan valor a la organización.","La empresa demuestra que la inclusión laboral es rentable y socialmente responsable."]'),
('economia', 'bachillerato', '{1}', '["Un consumidor descubre las ventajas del consumo colaborativo en plataformas digitales recientes.","Empieza a alquilar su coche cuando no lo usa para reducir gastos.","También comparte herramientas con vecinos y participa en grupos de intercambio local.","Estas prácticas le permiten reducir gastos y consumir de forma más sostenible.","La economía colaborativa se convierte en una alternativa atractiva al consumo tradicional."]'),
('economia', 'bachillerato', '{1}', '["Un país sufre una crisis financiera que paraliza el sistema bancario nacional.","Las familias retiran sus depósitos por miedo a perder sus ahorros bancarios.","Las empresas no pueden acceder al crédito y comienzan a despedir trabajadores.","El gobierno interviene rescatando bancos y garantizando los depósitos para restaurar la confianza.","Tras meses de medidas la economía se estabiliza y comienza una lenta recuperación."]'),
('economia', 'bachillerato', '{1}', '["Una start-up tecnológica busca financiación para crecer y expandirse internacionalmente.","Presenta su proyecto a inversores especializados en empresas innovadoras durante varios meses.","Tras varias rondas de negociación consigue captar el capital necesario para crecer.","Con los fondos contrata a más''ingenieros y abre oficinas en otras ciudades europeas.","La empresa multiplica su facturación''y se consolida como líder en su sector."]'),
('economia', 'bachillerato', '{1}', '["Un país miembro de la Unión''Europea recibe fondos para impulsar su transición''ecológica.","El gobierno diseña un plan de inversiones en energías renovables y eficiencia energética.","Empresas y administraciones se benefician de las ayudas europeas para sus proyectos.","La economía verde crece generando nuevos empleos y reduciendo emisiones contaminantes.","El país''avanza hacia el cumplimiento de los objetivos climáticos europeos del año 2030."]'),
('economia', 'bachillerato', '{1}', '["Una empresa familiar atraviesa dificultades por la entrada de competidores extranjeros más grandes.","Los responsables analizan la situación''y deciden innovar en sus productos tradicionales.","Invierten en investigación''y desarrollo para crear referencias diferenciadas y de mayor calidad.","Lanzan los nuevos productos al mercado obteniendo una buena acogida del público.","La empresa recupera cuota de mercado y asegura su continuidad para futuras generaciones."]'),
('economia', 'bachillerato', '{1}', '["Un trabajador es despedido tras varios años en la misma empresa industrial.","Recibe una indemnización''y comienza el cobro de la prestación por desempleo.","Aprovecha el tiempo para reciclarse profesionalmente con cursos online gratuitos disponibles.","Tras varios meses encuentra un nuevo empleo en un sector con mayor demanda.","La protección del estado y su esfuerzo personal le permiten reincorporarse al mercado."]'),
('economia', 'bachillerato', '{1}', '["Una empresa detecta que sus competidores aplican prácticas desleales en el mercado.","Recopila pruebas y consulta con su departamento jurídico antes de presentar denuncia formal.","Las autoridades de competencia inician una investigación sobre las prácticas detectadas.","Tras varios meses confirman las infracciones e imponen sanciones a las empresas implicadas.","El mercado se reequilibra y todas las empresas vuelven a competir en igualdad."]'),
('economia', 'bachillerato', '{1}', '["Un país''experimenta un crecimiento económico sostenido durante varios años seguidos.","El PIB aumenta el desempleo se reduce y los salarios crecen gradualmente.","Las familias mejoran su capacidad adquisitiva y aumentan el consumo de bienes duraderos.","Sin embargo aparecen señales de sobrecalentamiento e incremento moderado de la inflación.","El banco central interviene moderadamente para evitar una posible burbuja económica."]'),
('economia', 'bachillerato', '{1}', '["Una empresa decide implementar una política de teletrabajo para sus empleados oficinistas.","Analiza los costes ahorros y beneficios potenciales de esta nueva modalidad laboral.","Proporciona equipamiento informático y formación''específica a los trabajadores afectados por el cambio.","Los empleados ganan calidad de vida y la empresa reduce gastos en oficinas.","La productividad se mantiene o mejora tras varios meses de adaptación gradual."]'),
('economia', 'bachillerato', '{1}', '["Un consumidor se interesa por el comercio justo y su impacto social positivo.","Investiga qué productos llevan certificación''y dónde puede adquirirlos en su ciudad.","Comienza a comprar café cacao y artesanía con sello de comercio justo.","Aunque pague algo más sabe que beneficia directamente a productores de países en desarrollo.","Su consumo responsable contribuye a un comercio internacional más''equitativo y sostenible."]'),
('economia', 'bachillerato', '{1}', '["Una empresa decide expandirse a un mercado internacional para crecer de manera estratégica.","Realiza un estudio del país''objetivo analizando cultura legislación''y competencia local.","Adapta sus productos a los gustos y necesidades de los nuevos consumidores extranjeros.","Establece alianzas con socios locales para facilitar la entrada al mercado nuevo.","Las primeras ventas confirman el éxito de la estrategia de internacionalización''emprendida."]'),
('economia', 'bachillerato', '{1}', '["Un grupo de pequeños productores decide unirse formando una cooperativa agrícola.","Comparten infraestructuras costes de transporte y canales de comercialización conjuntos.","Esta unión les permite negociar mejores precios con grandes distribuidores comerciales.","Sus márgenes mejoran significativamente y pueden invertir en modernizar sus explotaciones.","La cooperativa demuestra el poder de la unión frente a la fragmentación del sector."]'),
('economia', 'bachillerato', '{1}', '["El gobierno aprueba una reforma del sistema de pensiones para garantizar su sostenibilidad.","Modifica la edad de jubilación los años cotizados y la fórmula de cálculo.","La medida genera debate entre sindicatos empresarios y diferentes generaciones de trabajadores.","Tras meses de negociación se aprueba un acuerdo que combina ajustes y compensaciones.","La reforma aspira a garantizar pensiones dignas para las generaciones futuras."]'),
('economia', 'bachillerato', '{1}', '["Una empresa observa cómo cambia la demanda de sus productos por nuevos hábitos sociales.","Analiza los datos y detecta una tendencia hacia el consumo más saludable y sostenible.","Decide reformular sus referencias eliminando ingredientes artificiales y reduciendo el envase plástico.","Las nuevas versiones reciben buena acogida por los consumidores conscientes del cambio.","Las ventas crecen significativamente y la empresa refuerza su imagen de marca responsable."]'),
('economia', 'bachillerato', '{1}', '["Un país firma un tratado de libre comercio con otra región''económica importante.","Las empresas exportadoras se preparan para aprovechar las nuevas oportunidades del mercado.","Algunos sectores ven aumentar sus ventas mientras otros sufren mayor competencia exterior.","El gobierno aplica medidas de apoyo para ayudar a los sectores más vulnerables.","A medio plazo el saldo comercial mejora y la economía crece gracias al comercio."]'),
('economia', 'bachillerato', '{1}', '["Un usuario decide invertir en un fondo indexado con un horizonte de largo plazo.","Investiga los costes la rentabilidad histórica y la composición del fondo elegido.","Realiza aportaciones periódicas mensuales para aprovechar el efecto del interés compuesto.","A lo largo de los años su capital crece de forma constante y diversificada.","La estrategia paciente y disciplinada le permite alcanzar sus objetivos financieros personales."]'),
('economia', 'bachillerato', '{1}', '["Una empresa decide invertir en formación continua para todos sus empleados.","Diseña un plan anual con cursos técnicos idiomas y habilidades digitales para todos.","Los trabajadores se sienten valorados y mejoran su desempeño profesional notablemente.","La empresa gana en productividad innovación''y capacidad de adaptarse al cambio constante.","El retorno de la inversión''en formación se ve reflejado en mejores resultados económicos."]'),
('economia', 'bachillerato', '{1}', '["El estado decide impulsar el emprendimiento juvenil con un programa específico nacional.","Ofrece formación financiación blanda y asesoramiento a jóvenes con ideas innovadoras.","Cientos de jóvenes presentan proyectos en sectores variados desde tecnología hasta agricultura.","Los más prometedores reciben apoyo integral para convertir sus ideas en empresas reales.","Algunos de estos proyectos crecen y crean empleo en sus territorios de origen."]'),
('economia', 'bachillerato', '{1}', '["Una empresa textil revisa su cadena de suministro tras detectar prácticas laborales inadecuadas.","Visita los talleres de sus proveedores y exige mejoras en condiciones de trabajo.","Algunos proveedores incumplidores son sustituidos por otros con mejores estándares éticos.","La empresa comunica los cambios a sus clientes para reforzar su compromiso responsable.","Las ventas aumentan gracias al reconocimiento del compromiso social de la marca."]'),
('economia', 'bachillerato', '{1}', '["Un país''atraviesa una etapa de envejecimiento demográfico con consecuencias económicas importantes.","La población''activa disminuye mientras crece el número de personas dependientes y mayores.","El gasto en pensiones y sanidad aumenta poniendo presión sobre las cuentas públicas.","El gobierno fomenta la inmigración cualificada y la natalidad mediante incentivos económicos.","Estas medidas buscan garantizar la sostenibilidad del modelo económico y social."]'),
('economia', 'bachillerato', '{1}', '["Una empresa decide medir su huella de carbono y reducirla progresivamente cada año.","Analiza todas sus actividades identificando las fuentes principales de emisiones contaminantes.","Implementa medidas como movilidad sostenible energías renovables y eficiencia energética.","Cada año publica un informe de sostenibilidad mostrando los progresos conseguidos.","Su compromiso ambiental atrae a clientes e inversores conscientes del cambio climático."]'),
('economia', 'bachillerato', '{1}', '["Un grupo de consumidores se organiza para comprar directamente a productores locales.","Se ponen en contacto con agricultores ganaderos y panaderos de la comarca cercana.","Realizan pedidos colectivos semanales que recogen en un punto común del barrio.","Los productores reciben mejores precios y los consumidores pagan menos por productos frescos.","La iniciativa fortalece la economía local y reduce la huella ecológica del consumo."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('economia-empresa', 'bachillerato', '{2}', '["Un empresario detecta una oportunidad de negocio analizando las tendencias del mercado actual.","Realiza un estudio de viabilidad económica y diseña su modelo de negocio detallado.","Elige la forma jurídica más''adecuada y formaliza la constitución de la sociedad.","Solicita financiación bancaria y contrata a los primeros empleados para iniciar la actividad.","La empresa abre sus puertas y comienza a operar en su sector elegido."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento financiero recopila todas las facturas de ingresos y gastos del trimestre.","Registra cada operación''en el libro diario respetando el principio de partida doble.","Al cierre del periodo elabora el balance de situación''y la cuenta de resultados.","Calcula los principales ratios financieros para evaluar la situación de la empresa.","Presenta el informe a la dirección para apoyar la toma de decisiones estratégicas."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa estudia la posibilidad de invertir en nueva maquinaria para aumentar producción.","Calcula los flujos de caja esperados durante los próximos cinco años de actividad.","Aplica el criterio del VAN descontando los flujos al tipo de interés''adecuado.","Compara el VAN con el de otras alternativas de inversión disponibles para la empresa.","Decide invertir porque el proyecto presenta el mayor VAN positivo entre todas las opciones."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de recursos humanos planifica una nueva campaña de selección de personal.","Define los perfiles necesarios y publica las ofertas en portales de empleo digitales.","Recibe centenares de currículums y los filtra según los criterios de cada puesto.","Realiza entrevistas pruebas técnicas y dinámicas de grupo con los candidatos finalistas.","Selecciona a los mejores y formaliza los contratos con los nuevos trabajadores."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de marketing diseña una nueva campaña para lanzar un producto innovador.","Analiza el mercado objetivo segmentando a los consumidores por sus características demográficas.","Define la propuesta de valor el precio el canal de distribución''y la comunicación.","Lanza la campaña en redes sociales televisión''y puntos de venta físicos.","Los resultados superan las expectativas y las ventas crecen significativamente en pocos meses."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una pyme analiza su estructura de costes para identificar áreas de mejora rentable.","Distingue claramente entre costes fijos costes variables y costes mixtos del negocio.","Calcula el umbral de rentabilidad para conocer el punto muerto de equilibrio.","Identifica que necesita aumentar las ventas un quince por ciento para ganar dinero.","Diseña una estrategia comercial agresiva que le permite alcanzar el objetivo trazado."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa familiar quiere profesionalizar su gestión tras tres generaciones en el negocio.","Contrata a un gerente externo experimentado para liderar la transformación''organizativa interna.","Implementa nuevos procesos de control y un sistema informático integrado de gestión.","Los empleados reciben formación para adaptarse a la nueva cultura empresarial.","En dos años la empresa duplica sus beneficios manteniendo sus valores familiares originales."]'),
('economia-empresa', 'bachillerato', '{2}', '["El director financiero analiza la liquidez de la empresa ante un próximo vencimiento.","Calcula el ratio de tesorería y el fondo de maniobra disponible para el pago.","Detecta que la empresa necesita financiación''adicional para cumplir con todas sus obligaciones.","Negocia una línea de crédito con su banco habitual con condiciones favorables.","La empresa cubre sus necesidades de liquidez y mantiene su solvencia financiera."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide implementar un sistema de control de calidad total en sus procesos.","Forma a todos los empleados en metodologías como las cinco eses y mejora continua.","Establece indicadores específicos para medir la calidad en cada fase del proceso productivo.","Detecta y corrige progresivamente todas las fuentes de defectos y desperdicios encontradas.","La satisfacción de los clientes aumenta y las devoluciones disminuyen drásticamente."]'),
('economia-empresa', 'bachillerato', '{2}', '["El consejo de administración''estudia una propuesta de fusión con un competidor.","Los analistas estudian las sinergias potenciales y los riesgos de la operación''empresarial.","Las dos empresas negocian los términos del intercambio accionarial y la nueva estructura.","Tras meses de negociación se firma el acuerdo y se obtiene la autorización regulatoria.","La nueva empresa fusionada gana cuota de mercado y eficiencia en sus operaciones."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa exportadora analiza el riesgo de tipo de cambio en sus operaciones internacionales.","Estudia los mercados donde opera y la evolución prevista de las divisas extranjeras.","Decide contratar un seguro de cambio para cubrir los cobros futuros en dólares.","Esta cobertura le permite asegurar un precio estable independientemente de las fluctuaciones del mercado.","La empresa estabiliza sus márgenes y reduce significativamente la incertidumbre financiera."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una start-up tecnológica busca financiación para escalar su modelo de negocio rápidamente.","Prepara un plan de negocio detallado con proyecciones financieras a cinco años.","Presenta el proyecto a varios fondos de capital riesgo especializados en su sector.","Tras varias rondas de negociación consigue captar tres millones de euros de inversión.","Con la nueva financiación contrata talento abre nuevos mercados y multiplica su facturación."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de producción detecta cuellos de botella que ralentizan la fabricación diaria.","Analiza el flujo del proceso identificando las fases que generan retrasos significativos.","Propone reorganizar la cadena introduciendo nuevos equipos en los puntos críticos detectados.","La inversión''es aprobada tras analizar el retorno esperado de la mejora.","Tras la implementación la producción''aumenta un veinte por ciento sin más costes."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide externalizar parte de sus servicios para centrarse en su actividad principal.","Identifica las áreas que pueden ser realizadas más''eficientemente por proveedores especializados.","Selecciona los proveedores tras un proceso de licitación riguroso y transparente.","Firma los contratos con cláusulas claras de calidad servicio y confidencialidad estricta.","La externalización le permite reducir costes y mejorar la eficiencia operativa global."]'),
('economia-empresa', 'bachillerato', '{2}', '["Un emprendedor presenta su proyecto a un programa de aceleración''empresarial muy reconocido.","Es seleccionado entre cientos de candidatos por la calidad innovadora de su propuesta.","Durante seis meses recibe formación''intensiva mentoría y acceso a una red de inversores.","Al final del programa presenta su proyecto en un evento ante decenas de inversores.","Consigue una ronda de financiación que le permite lanzar su producto al mercado."]'),
('economia-empresa', 'bachillerato', '{2}', '["El director comercial analiza la cartera de clientes para optimizar la estrategia comercial.","Aplica el análisis ABC clasificando los clientes según su volumen de facturación.","Detecta que un veinte por ciento de clientes genera el ochenta por ciento de los ingresos.","Diseña planes de fidelización''específicos para los clientes más rentables del negocio.","La estrategia mejora la retención de clientes clave y aumenta la facturación global."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide implementar una política de responsabilidad social corporativa integral.","Identifica los grupos de interés clave clientes empleados proveedores comunidad y administración.","Diseña acciones específicas para cada grupo incluyendo formación voluntariado y mecenazgo cultural.","Publica anualmente un informe de sostenibilidad siguiendo los estándares internacionales reconocidos.","La empresa mejora su reputación''atrae talento y refuerza la lealtad de sus clientes."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de I más D presenta un nuevo producto disruptivo al mercado.","La empresa solicita la patente para proteger la innovación de la competencia internacional.","Diseña una estrategia de lanzamiento global con campañas en varios países simultáneamente.","Las primeras ventas superan ampliamente las previsiones más''optimistas iniciales.","En pocos años la innovación se convierte en líder del mercado mundial."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa familiar afronta el reto de la sucesión generacional con preparación cuidadosa.","El fundador comienza a transferir gradualmente las responsabilidades a sus dos hijos.","Diseñan un protocolo familiar que regula la incorporación de los miembros y el reparto de poderes.","Los herederos reciben formación''específica en gestión''empresarial durante varios años.","La sucesión se completa sin conflictos y la empresa continúa creciendo bajo nueva dirección."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de logística optimiza la cadena de suministro con tecnología avanzada.","Implementa un sistema de gestión de inventarios en tiempo real basado en sensores.","Reduce los stocks innecesarios y mejora la disponibilidad de productos para los clientes.","Negocia con proveedores entregas justo a tiempo para minimizar los costes de almacén.","La optimización logística reduce costes y mejora el servicio al cliente."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa estudia la posibilidad de cotizar en bolsa para captar nuevos recursos.","Contrata asesores financieros para preparar el proceso de salida al mercado bursátil.","Cumple con todos los requisitos legales y de transparencia exigidos por el regulador.","El día de la salida a bolsa las acciones se sobresuscriben varias veces.","La empresa capta los fondos necesarios para sus planes de expansión''internacional."]'),
('economia-empresa', 'bachillerato', '{2}', '["El director de operaciones analiza el rendimiento de cada planta de producción.","Compara indicadores como productividad calidad costes y plazos de entrega entre todas.","Identifica las mejores prácticas y las extiende al resto de plantas del grupo.","Implementa programas de mejora continua con la participación''activa de los trabajadores.","En un año todas las plantas alcanzan los niveles de las mejores del grupo."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa lanza un programa de fidelización de clientes con tarjeta personalizada.","Cada compra acumula puntos canjeables por descuentos productos o experiencias exclusivas.","Los clientes se sienten valorados y aumentan la frecuencia de sus compras.","La empresa obtiene datos valiosos sobre los hábitos de consumo de sus clientes.","Esta información permite personalizar las ofertas y aumentar las ventas significativamente."]'),
('economia-empresa', 'bachillerato', '{2}', '["El responsable financiero analiza diferentes alternativas para financiar una nueva inversión''importante.","Compara financiación propia ampliación de capital préstamo bancario y emisión de obligaciones.","Calcula el coste medio ponderado del capital para cada opción financiera disponible.","Selecciona la combinación óptima que minimiza el coste y mantiene la estructura financiera.","La empresa obtiene los fondos necesarios al menor coste posible para el proyecto."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa estudia entrar en un nuevo país realizando un análisis estratégico completo.","Aplica el análisis PESTEL evaluando los factores políticos económicos sociales tecnológicos.","Estudia también la competencia las cinco fuerzas de Porter del nuevo mercado.","Decide entrar mediante una alianza con un socio local que conoce el mercado.","Tras dos años la empresa consolida su presencia y expande su modelo de negocio."]'),
('economia-empresa', 'bachillerato', '{2}', '["El consejo de administración''aprueba un plan estratégico para los próximos cinco años.","Define la visión la misión''y los valores que guiarán''a toda la organización.","Establece objetivos cuantitativos claros para cada área funcional de la empresa.","Comunica el plan a todos los empleados para asegurar su implicación con los objetivos.","El seguimiento periódico permite ajustar la estrategia ante los cambios del mercado."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide implementar el método just in time en su línea de producción.","Trabaja con proveedores cercanos que pueden entregar materiales en el momento exacto.","Reduce drásticamente los inventarios de materias primas y productos en curso.","La empresa libera espacio en su almacén''y reduce los costes financieros asociados.","La eficiencia mejora notablemente y la flexibilidad ante cambios de demanda aumenta."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de marketing analiza el ciclo de vida de cada uno de los productos.","Identifica productos en fase de lanzamiento crecimiento madurez y declive del ciclo.","Diseña estrategias específicas para cada fase del ciclo de vida del producto.","Decide retirar productos en declive y lanzar nuevas referencias para mantener la cartera.","La gestión''activa de la cartera permite mantener un crecimiento sostenido en ventas."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa lanza una OPA hostil sobre un competidor para ganar cuota de mercado.","Ofrece a los accionistas del objetivo un precio superior al cotizado en bolsa.","La dirección del competidor intenta frenar la operación con varias medidas defensivas.","Tras meses de negociaciones y ofertas mejoradas la OPA es finalmente aceptada.","La nueva entidad se convierte en el líder del sector con mayor capacidad competitiva."]'),
('economia-empresa', 'bachillerato', '{2}', '["El director de operaciones implementa un sistema ERP integrado en toda la empresa.","El sistema unifica la información de finanzas producción ventas compras y recursos humanos.","Los empleados reciben formación''intensiva durante varios meses para usar el nuevo sistema.","La integración mejora la coordinación''entre departamentos y la toma de decisiones.","La empresa gana eficiencia transparencia y capacidad de respuesta a los cambios del mercado."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide implementar políticas de igualdad de género en todos sus niveles.","Realiza un diagnóstico previo identificando las brechas existentes en su organización.","Diseña medidas específicas como cuotas en directivos formación''y conciliación laboral.","Comunica los compromisos y el plan de acción''a todas las personas trabajadoras.","En tres años consigue una representación''equilibrada en todos los niveles jerárquicos."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento financiero estudia la conveniencia de adelantar el cobro de facturas.","Compara el coste del descuento comercial con el del descuento bancario disponible.","Calcula la TAE de cada opción para hacer una comparación''homogénea correcta.","Selecciona la opción más''económica para mejorar la liquidez sin perjudicar la rentabilidad.","La empresa optimiza su gestión de tesorería y dispone de fondos para nuevas inversiones."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa analiza el impacto del comercio electrónico en su modelo de negocio tradicional.","Decide lanzar su propia tienda online complementando los canales físicos existentes.","Diseña una estrategia omnicanal donde los clientes pueden comprar y devolver donde quieran.","Forma a los empleados en las nuevas tecnologías y procesos digitales necesarios.","Las ventas online crecen rápidamente y compensan el descenso en algunos canales físicos."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento de calidad detecta una oportunidad para certificarse en normas ISO.","Estudia los requisitos de las normas y diseña un plan de implementación detallado.","Documenta todos los procesos y forma al personal en los nuevos procedimientos requeridos.","Tras una auditoría externa rigurosa obtiene la certificación deseada con éxito.","La certificación''abre nuevas oportunidades comerciales con clientes que la exigen."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa lanza un plan de incentivos para mejorar la motivación de sus empleados.","Diseña objetivos individuales y colectivos vinculados a una retribución variable atractiva.","Comunica el plan claramente para que todos comprendan los criterios de aplicación.","Los empleados se implican más''en los objetivos y la productividad aumenta significativamente.","La empresa consigue mejores resultados y los empleados se benefician de mayores ingresos."]'),
('economia-empresa', 'bachillerato', '{2}', '["El consejo de administración debate la conveniencia de repartir dividendos este ejercicio.","Analiza los resultados las necesidades de inversión''y las expectativas de los accionistas.","Decide repartir un dividendo moderado manteniendo reservas para futuras oportunidades de crecimiento.","Comunica la decisión''al mercado justificando claramente los criterios aplicados a la propuesta.","Los accionistas valoran positivamente el equilibrio entre retribución''y reinversión''empresarial."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide adoptar la metodología agile para gestionar sus proyectos internos.","Forma equipos multidisciplinares que trabajan en ciclos cortos llamados sprints semanales.","Cada sprint termina con una revisión de lo conseguido y planificación del siguiente.","La nueva metodología acelera el desarrollo y permite responder a cambios con rapidez.","La empresa reduce significativamente los tiempos de lanzamiento de nuevos productos al mercado."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa estudia el impacto de aplicar inteligencia artificial en sus procesos productivos.","Identifica varias áreas donde el aprendizaje automático puede aportar mejoras significativas.","Realiza pruebas piloto en una línea de producción midiendo los resultados obtenidos.","Los resultados confirman mejoras en eficiencia calidad y reducción de defectos detectados.","La empresa decide extender la inteligencia artificial a todas sus instalaciones productivas."]'),
('economia-empresa', 'bachillerato', '{2}', '["El director general presenta los resultados anuales a la junta general de accionistas.","Expone los principales hitos logros y dificultades del ejercicio que termina.","Presenta el plan estratégico para el próximo año con los objetivos cuantitativos previstos.","Responde a las preguntas de los accionistas sobre la evolución del negocio.","La junta aprueba las cuentas el reparto de dividendos y la gestión del consejo."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa identifica un competidor desleal que copia sus productos sin autorización.","Recopila pruebas y consulta con su departamento jurídico antes de presentar denuncia.","Inicia acciones legales por violación de patentes y competencia desleal en los tribunales.","Tras un proceso judicial favorable consigue una indemnización significativa por daños sufridos.","La sentencia sienta un precedente y disuade a otros competidores de prácticas similares."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa decide implantar el teletrabajo de forma permanente para sus empleados.","Analiza los costes ahorros y beneficios potenciales de esta modalidad laboral nueva.","Proporciona equipamiento informático y formación''en herramientas digitales colaborativas a todos.","Establece protocolos de comunicación seguimiento y evaluación del desempeño remoto.","La productividad se mantiene y la satisfacción de los empleados aumenta considerablemente."]'),
('economia-empresa', 'bachillerato', '{2}', '["El departamento financiero detecta un problema grave de morosidad entre sus clientes.","Analiza las causas y refuerza el proceso de evaluación crediticia para nuevos clientes.","Implementa una política de cobro más''estricta con avisos automáticos y recargos por demora.","Negocia planes de pago con los clientes con dificultades para evitar pérdidas mayores.","En seis meses la empresa reduce significativamente sus impagados y mejora la liquidez."]'),
('economia-empresa', 'bachillerato', '{2}', '["Una empresa familiar decide internacionalizarse aprovechando las oportunidades del mercado europeo.","Realiza un estudio de los países objetivo analizando demanda regulación''y competencia local.","Elige tres mercados prioritarios y diseña una estrategia de entrada para cada uno.","Adapta sus productos y su comunicación''a las particularidades culturales de cada país.","En cinco años el cuarenta por ciento de su facturación procede de mercados internacionales."]'),
('economia-empresa', 'bachillerato', '{2}', '["El responsable de recursos humanos diseña un plan de carrera para los empleados clave.","Identifica el potencial de cada persona y define un itinerario formativo personalizado.","Cada empleado conoce las oportunidades de promoción''interna y los requisitos necesarios.","La empresa retiene talento y los empleados se sienten valorados y comprometidos.","La rotación de personal disminuye y mejora el clima laboral en toda la organización."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('geografia', 'bachillerato', '{2}', '["La Península Ibérica presenta una gran variedad de unidades de relieve interior y litoral.","La Meseta Central es la unidad más''extensa con una altitud media elevada característica.","Los sistemas Cantábrico Pirineo Ibérico y Bético rodean o atraviesan la Meseta.","Las depresiones del Ebro y del Guadalquivir se sitúan entre la Meseta y los Béticos.","Esta diversidad de relieve condiciona el clima la hidrografía y los usos agrícolas."]'),
('geografia', 'bachillerato', '{2}', '["El clima oceánico predomina en la franja norte peninsular con lluvias abundantes anuales.","Los inviernos son suaves y los veranos frescos por la influencia atlántica constante.","La vegetación natural está formada por bosques caducifolios de robles y hayas.","La actividad agraria se basa en la ganadería bovina y los cultivos de huerta.","La población se distribuye en numerosos núcleos rurales y ciudades de tamaño medio."]'),
('geografia', 'bachillerato', '{2}', '["El clima mediterráneo afecta a la mayor parte del territorio peninsular y baleárico.","Los inviernos son suaves y los veranos calurosos y secos con lluvias irregulares.","La vegetación natural está formada por encinas alcornoques y matorrales mediterráneos.","La agricultura mediterránea combina cereales olivos viñedos y cultivos de regadío.","La presión turística sobre el litoral genera importantes problemas ambientales y urbanísticos."]'),
('geografia', 'bachillerato', '{2}', '["La España vaciada es un fenómeno demográfico que afecta a amplias áreas rurales interiores.","El éxodo rural de los años sesenta despobló muchos municipios de manera intensa.","La población restante presenta un envejecimiento alarmante y una baja natalidad.","Los servicios públicos se han reducido provocando aún más despoblación gradual.","Las administraciones buscan soluciones para revitalizar estos territorios mediante incentivos fiscales y digitalización."]'),
('geografia', 'bachillerato', '{2}', '["La industrialización''española se concentró históricamente en Cataluña País Vasco y Madrid.","Estas regiones desarrollaron sectores como textil siderurgia química y automoción durante decenios.","La crisis de los años setenta y ochenta provocó una profunda reconversión''industrial.","Muchas fábricas obsoletas cerraron generando paro y problemas sociales graves.","La nueva industria apuesta por la innovación tecnológica y los sectores de mayor valor añadido."]'),
('geografia', 'bachillerato', '{2}', '["La pesca española ha sufrido una profunda transformación durante las últimas décadas.","La flota se ha reducido por las cuotas europeas y el agotamiento caladeros tradicionales.","Los puertos pesqueros han diversificado sus actividades hacia el turismo y la acuicultura.","La acuicultura ha crecido como alternativa sostenible para abastecer el consumo de pescado.","España continúa siendo uno de los mayores consumidores de pescado del mundo entero."]'),
('geografia', 'bachillerato', '{2}', '["El sector servicios emplea actualmente a más del setenta por ciento de la población''activa española.","El turismo es uno de los pilares económicos más''importantes con millones de visitantes anuales.","El comercio el transporte y los servicios financieros generan también''un volumen considerable.","La administración pública educación''y sanidad ocupan a millones de empleados públicos.","Esta terciarización refleja la evolución de la economía española hacia modelos avanzados."]'),
('geografia', 'bachillerato', '{2}', '["La red de transporte español ha experimentado una modernización''extraordinaria desde 1986.","La construcción de autovías ha conectado todas las capitales provinciales con la capital.","La red de alta velocidad ferroviaria es una de las más''extensas del mundo.","Los grandes puertos y aeropuertos han ampliado su capacidad para responder a la demanda.","Esta inversión''en infraestructuras ha mejorado la cohesión territorial y la competitividad económica."]'),
('geografia', 'bachillerato', '{2}', '["El sistema urbano español está jerarquizado con Madrid y Barcelona como ciudades principales.","Las metrópolis regionales como Valencia Sevilla Bilbao y Zaragoza articulan amplios territorios.","Las ciudades medias cumplen funciones de capitalidad provincial y servicios para áreas rurales.","El crecimiento metropolitano genera problemas de movilidad vivienda y sostenibilidad ambiental.","La planificación''urbana busca un equilibrio entre desarrollo económico y calidad de vida."]'),
('geografia', 'bachillerato', '{2}', '["Las comunidades autónomas son la principal forma de organización política territorial española.","La Constitución de 1978 reconoció el derecho a la autonomía de las nacionalidades y regiones.","Cada comunidad cuenta con su parlamento gobierno y un estatuto de autonomía propio.","Las competencias incluyen sanidad educación''urbanismo y desarrollo económico territorial.","Este modelo descentralizado ha permitido una gestión más cercana a las necesidades ciudadanas."]'),
('geografia', 'bachillerato', '{2}', '["El cambio climático afecta especialmente al sureste peninsular con sequías cada vez más graves.","Las temperaturas medias anuales han aumentado significativamente durante las últimas décadas.","La desertificación''amenaza amplias zonas agrícolas tradicionalmente productivas en el sur.","Los recursos hídricos se ven cada vez más comprometidos por la falta de lluvia.","Las administraciones impulsan medidas de adaptación''y reducción de emisiones contaminantes."]'),
('geografia', 'bachillerato', '{2}', '["La agricultura de regadío española es una de las más''eficientes y modernas del mundo.","Se ha extendido especialmente en el levante y el sureste mediterráneos en las últimas décadas.","Los cultivos de invernadero generan exportaciones millonarias hacia los mercados europeos.","Sin embargo el consumo de agua es muy elevado generando problemas de sostenibilidad.","Las nuevas técnicas de riego eficiente buscan reducir el impacto ambiental sin perder productividad."]'),
('geografia', 'bachillerato', '{2}', '["La energía renovable ha experimentado un crecimiento espectacular en España durante este siglo.","La energía eólica y la fotovoltaica son las tecnologías que más''han crecido en el país.","España es uno de los países líderes mundiales en producción de energía solar.","La transición''energética es una prioridad para reducir la dependencia de combustibles fósiles.","El objetivo es alcanzar la neutralidad climática para el año 2050 según la legislación."]'),
('geografia', 'bachillerato', '{2}', '["La población''española ha experimentado un fuerte envejecimiento durante las últimas décadas.","La esperanza de vida ha aumentado siendo una de las más''altas del mundo.","La natalidad ha descendido a niveles muy bajos por debajo del reemplazo generacional.","La inmigración''ha compensado parcialmente este descenso pero no resuelve el problema demográfico.","El envejecimiento plantea retos para el sistema de pensiones y la sanidad pública."]'),
('geografia', 'bachillerato', '{2}', '["Los espacios naturales protegidos cubren aproximadamente el treinta por ciento del territorio español.","Existen quince parques nacionales que protegen los ecosistemas más representativos del país.","Los parques naturales y reservas completan la red de espacios protegidos peninsulares e insulares.","La Red Natura 2000 europea protege también''amplias zonas con especies amenazadas.","La gestión de estos espacios busca compatibilizar conservación''y desarrollo socioeconómico local."]'),
('geografia', 'bachillerato', '{2}', '["Las cuencas hidrográficas españolas se reparten entre dos vertientes principales atlántica y mediterránea.","La vertiente atlántica recoge la mayor parte del agua peninsular con caudales abundantes.","La vertiente mediterránea presenta caudales irregulares con grandes diferencias estacionales y problemas de sequía.","Los grandes ríos como Duero Tajo Guadiana y Ebro vertebran amplias cuencas.","La gestión''hidráulica es estratégica para el abastecimiento agrícola urbano e industrial nacional."]'),
('geografia', 'bachillerato', '{2}', '["La vivienda es uno de los problemas socioeconómicos más''importantes de la sociedad española.","Los precios han crecido por encima de los salarios especialmente en las grandes ciudades.","Los jóvenes encuentran serias dificultades para emanciparse y acceder a una vivienda propia.","El mercado del alquiler ha experimentado tensiones especialmente en zonas turísticas masificadas.","Las administraciones impulsan medidas de vivienda pública y protección del derecho constitucional."]'),
('geografia', 'bachillerato', '{2}', '["Las islas Canarias presentan una geografía singular por su origen volcánico y aislamiento.","El clima subtropical permite un cultivo agrícola diverso y atrae turismo durante todo el año.","La economía depende fuertemente del turismo y de las importaciones desde la península.","La biodiversidad endémica es excepcional con especies únicas que necesitan protección''especial.","La presión demográfica y turística genera retos importantes para la sostenibilidad insular ambiental."]'),
('geografia', 'bachillerato', '{2}', '["La inmigración''ha transformado profundamente la sociedad española desde finales del siglo XX.","Llegaron primero personas procedentes de Marruecos seguidas por latinoamericanos del este europeo y otros países.","Su llegada rejuveneció la pirámide poblacional y aportó mano de obra a sectores clave.","La integración''ha sido en general satisfactoria con desafíos puntuales en ciertas zonas.","La inmigración seguirá siendo necesaria para mantener la población''activa en las próximas décadas."]'),
('geografia', 'bachillerato', '{2}', '["España ingresó en la Comunidad Económica Europea en el año 1986.","Esta entrada supuso una profunda transformación''económica social y política del país.","Los fondos estructurales europeos financiaron infraestructuras esenciales para la modernización del territorio.","La adhesión''al euro en 2002 completó el proceso de integración monetaria europea.","Hoy España es uno de los países más''europeístas e implicados en el proyecto comunitario."]'),
('geografia', 'bachillerato', '{2}', '["La industria turística española se inició en los años sesenta con el auge del sol y playa.","Las costas mediterráneas y baleáricas se convirtieron en destinos de masas durante las décadas siguientes.","El crecimiento generó desarrollo económico pero también problemas ambientales y urbanísticos graves.","En los últimos años se busca diversificar el modelo hacia turismo cultural rural y de naturaleza.","La sostenibilidad y la calidad son ahora los grandes retos del sector turístico nacional."]'),
('geografia', 'bachillerato', '{2}', '["La pesca en España se ha visto afectada por la sobreexplotación de los caladeros.","Las cuotas pesqueras europeas han limitado las capturas para garantizar la sostenibilidad biológica.","Muchos pescadores han tenido que abandonar la actividad o reconvertirse profesionalmente.","La acuicultura ha crecido como alternativa para abastecer la demanda creciente de pescado.","La gestión sostenible es esencial para preservar los recursos marinos para futuras generaciones."]'),
('geografia', 'bachillerato', '{2}', '["Las desigualdades regionales son una característica histórica del territorio español.","Las regiones del norte y noreste presentan rentas per cápita superiores a la media nacional.","Andalucía Extremadura y Castilla La Mancha tienen indicadores económicos por debajo de la media.","Las políticas de cohesión''europeas han ayudado a reducir las brechas territoriales.","Sin embargo persisten desigualdades estructurales que requieren políticas específicas y sostenidas."]'),
('geografia', 'bachillerato', '{2}', '["Las áreas metropolitanas españolas concentran una gran parte de la población''y la actividad económica.","Madrid y Barcelona superan los cinco millones de habitantes en sus áreas metropolitanas.","Estas ciudades atraen flujos constantes de población migración''y capitales.","Generan también''importantes problemas de movilidad contaminación''y vivienda asequible.","La planificación metropolitana es esencial para garantizar la sostenibilidad y la calidad de vida."]'),
('geografia', 'bachillerato', '{2}', '["El sistema portuario español es uno de los más''importantes y desarrollados de Europa.","Los grandes puertos como Algeciras Valencia y Barcelona mueven millones de toneladas anuales.","Su localización''estratégica los convierte en plataformas logísticas para toda Europa occidental.","La inversión''en infraestructuras portuarias mejora la competitividad de las exportaciones nacionales.","Los puertos generan empleo y son clave para la economía del país''en el comercio exterior."]'),
('geografia', 'bachillerato', '{2}', '["La agricultura ecológica ha crecido significativamente en España durante las últimas décadas.","España es uno de los países europeos con mayor superficie cultivada en producción''ecológica.","Los productos ecológicos se exportan principalmente a mercados europeos con alta demanda.","La agricultura ecológica contribuye a la sostenibilidad ambiental y la biodiversidad rural.","Las administraciones impulsan ayudas y formación para fomentar este modelo agrícola sostenible."]'),
('geografia', 'bachillerato', '{2}', '["La movilidad sostenible es uno de los principales retos urbanos en las ciudades españolas.","El uso del coche privado genera contaminación congestión''y problemas de salud pública.","Los ayuntamientos impulsan el transporte público bicicletas y zonas peatonales urbanas.","La electrificación del parque automovilístico avanza con incentivos a vehículos eléctricos.","El objetivo es reducir las emisiones y mejorar la calidad del aire en las ciudades."]'),
('geografia', 'bachillerato', '{2}', '["El comercio exterior español ha crecido significativamente desde la entrada en la Unión''Europea.","Las exportaciones a la zona euro representan la mayor parte del intercambio comercial.","Los principales productos exportados son automóviles maquinaria y productos agroalimentarios mediterráneos.","La balanza comercial mejora gracias al impulso de las exportaciones y al turismo internacional.","España es hoy una de las economías más''abiertas y exportadoras de la Unión''Europea."]'),
('geografia', 'bachillerato', '{2}', '["Los espacios rurales españoles han experimentado profundas transformaciones desde el siglo XX.","La mecanización del campo redujo drásticamente la mano de obra agrícola necesaria.","Muchos pequeños municipios perdieron población''y servicios públicos básicos durante este proceso.","El turismo rural y los nuevos pobladores han revitalizado algunos territorios rurales recientemente.","El reto es mantener la población''y los servicios para garantizar la cohesión territorial nacional."]'),
('geografia', 'bachillerato', '{2}', '["La desigualdad social en España se mide a través del índice de Gini y otros indicadores.","Las crisis económicas han incrementado la pobreza y la exclusión social en los últimos años.","Las administraciones aplican políticas sociales para reducir las desigualdades y proteger los más vulnerables.","La educación''y el empleo de calidad son las palancas principales para la inclusión social.","La cohesión social es esencial para garantizar la estabilidad democrática y económica del país."]'),
('geografia', 'bachillerato', '{2}', '["España es uno de los países con mayor diversidad biológica de Europa occidental.","Su posición geográfica entre Europa y África explica esta riqueza única en el continente.","Numerosos endemismos vegetales y animales se concentran en zonas montañosas e islas oceánicas.","La conservación de esta biodiversidad es un compromiso esencial para el futuro ambiental.","Las áreas protegidas y los planes de recuperación de especies son herramientas clave para conservar."]'),
('geografia', 'bachillerato', '{2}', '["Las relaciones entre España y la Unión''Europea son intensas en todos los ámbitos.","España es uno de los principales beneficiarios de los fondos europeos para el desarrollo.","Participa activamente en la política agrícola común''y en la política de cohesión''europea.","Comparte con sus socios europeos los grandes retos del cambio climático y la seguridad.","La pertenencia europea ha sido un factor clave para la modernización''y prosperidad española."]'),
('geografia', 'bachillerato', '{2}', '["La industria automovilística es uno de los sectores más''importantes de la economía española.","España es el segundo productor europeo de vehículos por detrás de Alemania.","Las grandes marcas internacionales tienen plantas en varias regiones del país.","El sector está afrontando la transición''hacia los vehículos eléctricos e híbridos del futuro.","La competitividad y la innovación son claves para mantener su posición''en el mercado europeo."]'),
('geografia', 'bachillerato', '{2}', '["La gestión del agua en España es un asunto estratégico debido a su escasez relativa.","Los planes hidrológicos regulan los usos del agua entre cuencas y sectores económicos diversos.","Las infraestructuras como embalses canales y trasvases distribuyen el recurso por todo el país.","Los conflictos por el agua son habituales entre regiones agricultores y ecologistas conservacionistas.","La eficiencia el ahorro y la reutilización son las claves para garantizar la sostenibilidad."]'),
('geografia', 'bachillerato', '{2}', '["Las costas españolas suman casi ocho mil kilómetros entre la península y los archipiélagos.","Presentan una gran diversidad geomorfológica con playas acantilados deltas y zonas húmedas naturales.","La presión turística y urbanística ha alterado profundamente muchos tramos del litoral español.","La Ley de Costas pretende proteger el dominio público marítimo terrestre del país.","La gestión''integrada del litoral es esencial para conservar este patrimonio natural y económico."]'),
('geografia', 'bachillerato', '{2}', '["Los flujos migratorios internos en España han cambiado significativamente desde los años sesenta.","El éxodo rural llevó a millones de personas hacia las grandes ciudades industriales del norte.","En las últimas décadas algunos territorios rurales atraen nuevos residentes en busca de calidad.","La España vaciada se intenta revitalizar con incentivos al teletrabajo y nuevos pobladores.","La distribución''equilibrada de la población''es un objetivo estratégico de las políticas territoriales."]'),
('geografia', 'bachillerato', '{2}', '["La arquitectura y el patrimonio histórico son recursos turísticos y culturales de gran valor.","España cuenta con casi cincuenta bienes inscritos como Patrimonio de la Humanidad por la UNESCO.","Ciudades como Toledo Salamanca Córdoba y Granada atraen millones de visitantes cada año.","La conservación de este patrimonio requiere inversión''y políticas de gestión sostenible.","El turismo cultural diversifica la oferta turística y reduce la dependencia del turismo de sol."]'),
('geografia', 'bachillerato', '{2}', '["El sector primario español emplea actualmente menos del cinco por ciento de la población''activa.","Sin embargo sigue siendo estratégico por su contribución''a la seguridad alimentaria nacional.","La modernización tecnológica ha aumentado significativamente la productividad agrícola y ganadera del país.","Las exportaciones agroalimentarias son un pilar importante de la balanza comercial española.","El relevo generacional en el campo es uno de los grandes retos del sector agrícola actual."]'),
('geografia', 'bachillerato', '{2}', '["La globalización''ha transformado la economía y la sociedad española durante las últimas décadas.","Las empresas españolas se han internacionalizado especialmente en América Latina y la Unión''Europea.","Los flujos comerciales financieros y migratorios conectan España con el resto del mundo.","La cultura española se difunde globalmente a través de la lengua el cine y la música.","España es hoy una potencia media plenamente integrada en la economía global y europea."]'),
('geografia', 'bachillerato', '{2}', '["La transición''ecológica es uno de los grandes retos del siglo XXI para España.","Implica reducir las emisiones contaminantes y avanzar hacia un modelo económico sostenible.","Las energías renovables la movilidad eléctrica y la economía circular son piezas fundamentales.","Los fondos europeos Next Generation están financiando proyectos clave de transición''ecológica.","Los objetivos climáticos europeos para 2050 marcan el horizonte de esta transformación profunda."]'),
('geografia', 'bachillerato', '{2}', '["Las áreas industriales españolas se concentran en torno a las grandes ciudades y los puertos.","El triángulo formado por Madrid Cataluña y País Vasco concentra gran parte del peso industrial.","Las nuevas industrias se localizan también''en parques tecnológicos y polígonos especializados modernos.","La industria 4.0 incorpora robotización digitalización''e inteligencia artificial en los procesos productivos.","La competitividad industrial requiere inversión''en innovación formación''e infraestructuras avanzadas."]'),
('geografia', 'bachillerato', '{2}', '["El relieve español es uno de los más''elevados de Europa con una altitud media notable.","La Meseta Central tiene una altitud media superior a los seiscientos metros sobre el nivel del mar.","Las grandes cordilleras periféricas superan los tres mil metros en varios puntos clave.","Esta elevación''influye en el clima la hidrografía y los usos económicos del territorio.","La diversidad orográfica es un rasgo distintivo de la geografía peninsular y archipiélago."]'),
('geografia', 'bachillerato', '{2}', '["La estructura productiva española se ha terciarizado durante las últimas décadas siguiendo la tendencia europea.","El sector servicios genera más del setenta por ciento del PIB y del empleo nacional.","La industria mantiene un peso importante aunque inferior al de otros países europeos avanzados.","La construcción''es un sector cíclico que ha vivido grandes auges y crisis recientes.","El equilibrio entre sectores es importante para garantizar una economía resiliente y diversificada."]'),
('geografia', 'bachillerato', '{2}', '["Las grandes infraestructuras de transporte han transformado la geografía española en pocas décadas.","La red de autovías conecta todas las capitales con la capital del estado.","La alta velocidad ferroviaria es la segunda más''extensa del mundo después de China.","Los aeropuertos internacionales como Madrid y Barcelona son hubs importantes para el continente.","Esta inversión''ha mejorado la cohesión territorial y la competitividad económica del país."]'),
('geografia', 'bachillerato', '{2}', '["El reto demográfico es uno de los más''importantes a los que se enfrenta España.","El envejecimiento la baja natalidad y la despoblación rural son sus tres dimensiones principales.","El gobierno ha creado un ministerio específico para abordar estos desafíos territoriales.","Las medidas combinan apoyo a la natalidad inmigración''y desarrollo rural sostenible.","Resolver estos retos es esencial para garantizar el bienestar y la cohesión social futura."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('dibujo-tecnico', 'bachillerato', '{1}', '["Se elige el formato adecuado para el dibujo según las dimensiones de la pieza.","Se prepara el material trazando la caja de delimitación''y el cajetín''informativo.","Se dibuja la pieza con los instrumentos tradicionales como escuadra cartabón''y compás.","Se rotulan las cotas y los datos siguiendo las normas técnicas de representación.","Finalmente se revisa el plano para detectar posibles errores antes de la entrega."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica la circunferencia que se debe dividir en partes iguales.","Se traza el diámetro horizontal y se marcan los puntos correspondientes a cada división.","Se utilizan las construcciones geométricas adecuadas para cada número de divisiones.","Se unen los puntos obtenidos para formar el polígono regular inscrito en la circunferencia.","Se repasan las líneas con el grosor adecuado y se eliminan las líneas auxiliares."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se traza una recta y se marca un punto exterior a ella.","Se mide la distancia del punto a la recta utilizando el compás''o la escuadra.","Se prolonga la perpendicular hasta obtener un punto simétrico al original.","Se comprueba que ambos puntos están''a la misma distancia de la recta.","Esta construcción''es la base de muchas construcciones geométricas en el plano."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se estudia la pieza para identificar los planos básicos que la componen geométricamente.","Se elige la vista principal que mejor representa las características de la pieza.","Se obtienen las demás vistas necesarias respetando la disposición normalizada europea.","Se trazan las proyecciones cuidando la correspondencia exacta entre todas las vistas.","Se revisa el resultado final para verificar la coherencia entre las distintas proyecciones."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se traza una recta tangente a una circunferencia desde un punto exterior.","Se construye el segmento que une el punto exterior con el centro del círculo.","Se traza la circunferencia auxiliar con diámetro igual a este segmento construido.","Se obtienen los dos puntos de intersección con la circunferencia original como puntos de tangencia.","Se trazan las dos rectas tangentes desde el punto exterior a estos puntos."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica la pieza tridimensional que se debe representar en el sistema diédrico.","Se sitúan los planos de proyección''horizontal vertical y de perfil correctamente orientados.","Se proyecta la pieza obteniendo planta alzado y vista lateral con las debidas correspondencias.","Se completan las vistas con líneas ocultas para mostrar los elementos no visibles.","Se acotan las dimensiones siguiendo las normas técnicas de representación gráfica."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica la representación de un cuerpo geométrico en perspectiva caballera.","Se eligen los ejes con un ángulo de cuarenta y cinco grados para el tercer eje.","Se aplica el coeficiente de reducción''al eje de profundidad para evitar deformaciones.","Se trazan las aristas del cuerpo respetando la dirección de cada eje correspondiente.","Se completa la representación marcando aristas vistas y ocultas de la forma adecuada."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica el polígono regular que se desea construir geométricamente con compás.","Se traza la circunferencia donde se inscribirá el polígono regular según''el problema.","Se aplica el método específico para el número de lados que tenga el polígono.","Se marcan los vértices uniéndolos sucesivamente para formar el polígono regular completo.","Se repasa el dibujo final eliminando las líneas auxiliares utilizadas durante el proceso."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se analiza un problema de tangencias entre rectas y circunferencias.","Se identifican los datos conocidos y las incógnitas que se deben resolver geométricamente.","Se aplica el método más''adecuado utilizando potencias arcos capaces o construcciones auxiliares.","Se obtienen los puntos de tangencia con precisión geométrica utilizando las herramientas básicas.","Se traza la solución final con el grosor correspondiente y se verifica el resultado."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica una elipse definida por sus ejes principales mayor y menor.","Se trazan los dos ejes perpendiculares marcando los vértices y los focos correspondientes.","Se construyen varios puntos de la elipse mediante el método de la afinidad ortogonal.","Se unen los puntos obtenidos con una curva suave utilizando la plantilla de curvas.","Se repasa la curva con el trazo adecuado verificando su simetría respecto a los ejes."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica una hipérbola con sus ejes y focos definidos en el enunciado.","Se trazan las dos asíntotas que pasan por los vértices del rectángulo auxiliar.","Se construyen varios puntos de la curva mediante el método específico de cada hipérbola.","Se unen los puntos suavemente respetando la simetría de la curva respecto a sus ejes.","Se completa el dibujo asegurando la correcta aproximación''a las asíntotas trazadas."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se traza un triángulo conocidos sus tres lados utilizando solo regla y compás.","Se dibuja el primer lado en su longitud exacta utilizando el compás como medida.","Se traza un arco con centro en el primer extremo y radio igual al segundo lado.","Se traza otro arco con centro en el segundo extremo y radio igual al tercer lado.","La intersección de los dos arcos es el tercer vértice del triángulo construido."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica el trazado de un enlace entre dos rectas mediante un arco de circunferencia.","Se calcula el centro del arco aplicando las propiedades de las tangencias.","Se trazan las dos paralelas a las rectas dadas a la distancia del radio del enlace.","Se obtiene el centro del arco en la intersección de las dos paralelas trazadas.","Se traza el arco de enlace que conecta suavemente las dos rectas iniciales del problema."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se aborda un problema de homotecia entre dos figuras semejantes en el plano.","Se identifica el centro de homotecia que es el punto de proyección de las figuras.","Se mide la razón de homotecia comparando segmentos correspondientes en ambas figuras.","Se obtienen los nuevos vértices de la figura homotética prolongando rectas desde el centro.","Se verifica que la nueva figura sea semejante a la original con la razón calculada."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se analiza una pieza con elementos curvos para representarla en el sistema diédrico.","Se identifican los círculos las elipses y otros elementos que aparecen en cada vista.","Se trazan las proyecciones con cuidado utilizando plantillas de curvas y compás.","Se mantienen las correspondencias exactas entre las vistas para asegurar la coherencia.","Se acotan los radios y diámetros siguiendo las normas específicas de cotación geométrica."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se traza un círculo y se quiere construir otro tangente exteriormente desde un punto.","Se aplica la propiedad de las tangentes que parten de un punto exterior común.","Se utiliza la potencia del punto para localizar el centro del nuevo círculo tangente.","Se traza el círculo con el radio adecuado verificando que sea efectivamente tangente.","Se comprueba el resultado utilizando la perpendicular en el punto de tangencia teórico."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se aborda la construcción de un óvalo regular conocida la longitud del eje mayor.","Se divide el eje mayor en tres partes iguales para situar los centros principales.","Se trazan los arcos con centro en los puntos extremos utilizando el radio adecuado.","Se completa el óvalo con dos arcos pequeños de enlace entre los anteriores.","Se verifica la suavidad y simetría del óvalo terminado respecto a sus ejes."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica una pieza compleja para representarla mediante diferentes vistas y secciones.","Se elige la vista principal que aporta más''información sobre la geometría general.","Se trazan las demás vistas auxiliares necesarias para completar la representación correcta.","Se realiza un corte para mostrar elementos interiores que no se ven desde fuera.","Se acotan todas las dimensiones y se rotulan las secciones según las normas técnicas."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se quiere obtener la verdadera magnitud de un segmento oblicuo en el sistema diédrico.","Se proyecta el segmento sobre los planos de proyección''horizontal y vertical.","Se aplica el método de abatimiento para girar el segmento hasta hacerlo paralelo a un plano.","Se obtiene la verdadera longitud midiendo en la proyección del segmento abatido.","Se comprueba el resultado utilizando un método alternativo como el cambio de planos."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se aborda un problema de potencia de un punto respecto a una circunferencia.","Se calcula la potencia midiendo el producto de las distancias a los puntos de intersección.","Se aplica la potencia para resolver problemas de tangencias o construcciones auxiliares varias.","Se verifica la solución comprobando que cumpla las condiciones del problema original.","Se completa el dibujo con las líneas necesarias para presentar la solución gráfica."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se analiza un sistema de tres planos secantes que se cortan en una recta.","Se identifican las tres rectas de intersección''entre cada par de planos.","Se demuestra que las tres rectas pasan por un mismo punto en el espacio.","Se representa la solución''en el sistema diédrico proyectando las rectas correspondientes.","Se verifica el resultado utilizando las propiedades geométricas del problema espacial."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se quiere construir una espiral logarítmica utilizando regla y compás únicamente.","Se traza un cuadrado base que servirá como punto de partida para la espiral.","Se divide el cuadrado en rectángulos áureos sucesivos siguiendo la proporción dorada.","Se trazan los arcos de cuarto de circunferencia inscritos en cada cuadrado obtenido.","La unión de todos los arcos forma la espiral logarítmica buscada con precisión."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica un problema de proporcionalidad entre dos segmentos en el plano.","Se aplica el teorema de Tales utilizando rectas paralelas y un haz de rectas concurrentes.","Se construye gráficamente la cuarta proporcional o la media proporcional según''el caso.","Se mide el segmento resultante para comprobar la solución del problema planteado.","Se presenta la solución final con el rotulado adecuado y las explicaciones pertinentes."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica la representación de una vivienda en planta a escala adecuada.","Se elige una escala que permita representar todos los elementos con suficiente detalle.","Se dibujan los muros las puertas las ventanas y el mobiliario siguiendo las normas.","Se rotulan las dimensiones y los nombres de cada estancia con el tamaño adecuado.","Se incluye una leyenda explicativa de los símbolos utilizados en el plano."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se inicia el estudio de las curvas cónicas con la definición geométrica de cada una.","Se traza una elipse a partir de sus dos focos y su distancia constante.","Se construye una parábola utilizando su foco y su directriz como elementos definitorios.","Se traza una hipérbola a partir de sus dos focos y la diferencia constante de distancias.","Se comparan las tres curvas para identificar sus propiedades comunes y diferenciales."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica una pieza con simetría de revolución para representarla en el plano.","Se elige el eje de simetría que servirá como referencia para todas las medidas.","Se dibuja la mitad del perfil de la pieza partiendo del eje de simetría.","Se completa la representación mediante la simetría axial respecto al eje establecido.","Se acotan los radios y las dimensiones siguiendo las convenciones para piezas de revolución."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica la construcción de una rosa de los vientos con divisiones precisas.","Se traza la circunferencia base y se marcan los cuatro puntos cardinales principales.","Se divide cada cuarto de circunferencia en partes iguales para los vientos secundarios.","Se unen los puntos formando los pétalos de la rosa con dimensiones proporcionales.","Se completa el dibujo añadiendo los rótulos de cada dirección con tipografía técnica."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se aborda un problema de intersección''entre una recta y un plano en el espacio.","Se proyectan los elementos en el sistema diédrico utilizando las dos vistas principales.","Se determina la intersección''utilizando un plano auxiliar que contenga la recta dada.","Se obtiene el punto de intersección''en cada una de las proyecciones del problema.","Se verifica la coherencia del resultado entre ambas proyecciones para confirmar la solución."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica un cuerpo prismático con bases pentagonales para representar su desarrollo.","Se calcula el perímetro de la base que servirá como longitud del rectángulo lateral.","Se traza el rectángulo correspondiente a la superficie lateral del prisma desarrollado.","Se añaden las dos bases pentagonales en los lados opuestos del rectángulo dibujado.","Se completa el desarrollo con líneas de doblez señaladas según la norma técnica."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se analiza un problema sobre la verdadera magnitud de un ángulo entre dos rectas.","Se proyectan las dos rectas en el sistema diédrico utilizando las vistas principales.","Se aplica el método de abatimiento para hacer paralelo el plano de las rectas a uno de proyección.","Se mide el ángulo en la proyección del plano abatido obteniendo la verdadera magnitud.","Se verifica el resultado mediante un método alternativo como el cambio de plano."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica el dibujo de una pieza con varios chaflanes y redondeos para acotar.","Se identifican los elementos a acotar y se eligen las cotas más relevantes para fabricación.","Se trazan las líneas de cota de manera ordenada evitando solapamientos y confusiones.","Se incluyen los símbolos correspondientes a chaflanes redondeos y radios según la norma.","Se revisa el plano para asegurar que todas las dimensiones necesarias estén presentes."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se inicia el estudio de las proyecciones axonométricas con sus tres tipos principales.","Se identifican las características de la perspectiva isométrica con sus ejes a 120 grados.","Se analiza la perspectiva dimétrica con dos ángulos iguales y uno diferente entre ejes.","Se estudia la perspectiva trimétrica con tres ángulos diferentes entre los ejes.","Se compara cuándo es más conveniente utilizar cada uno de los tres sistemas axonométricos."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se identifica un cuerpo geométrico cilíndrico para realizar un corte oblicuo.","Se determina la posición''exacta del plano de corte respecto al eje del cilindro.","Se obtiene la sección plana resultante utilizando el método de los puntos auxiliares.","Se proyecta la sección sobre uno de los planos para visualizar su verdadera forma.","Se completa el dibujo con las cotas necesarias para fabricar la pieza cortada."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se inicia un ejercicio sobre la geometría descriptiva en el sistema diédrico clásico.","Se sitúan los planos de proyección''y se identifican los elementos del problema.","Se aplican las reglas básicas de proyección para representar puntos rectas y planos.","Se resuelve el problema planteado utilizando construcciones auxiliares cuando sea necesario.","Se verifica el resultado comprobando la coherencia entre todas las proyecciones obtenidas."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica la realización de un boceto previo a un dibujo técnico definitivo.","Se traza el contorno general de la pieza a mano alzada con proporción''aproximada.","Se identifican los elementos principales y se anotan las medidas tomadas con un calibre.","Se toman las decisiones sobre las vistas necesarias para representar la pieza completamente.","El boceto sirve como referencia para realizar el dibujo definitivo con instrumentos."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se quiere obtener la sección plana de un cono mediante un plano oblicuo.","Se determina el tipo de cónica resultante según''el ángulo del plano respecto al eje.","Se construye la curva resultante punto por punto utilizando planos auxiliares horizontales.","Se proyecta la sección sobre el plano horizontal para visualizar su verdadera forma.","Se completa el dibujo con las cotas necesarias y la denominación de la cónica obtenida."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se introduce el concepto de escala como relación''entre el dibujo y la realidad.","Se eligen las escalas normalizadas para diferentes tipos de piezas y aplicaciones técnicas.","Se aprende a calcular las dimensiones reales a partir de las medidas del dibujo.","Se construye una escala gráfica para facilitar las mediciones directas en el plano.","Se aplican las escalas en ejercicios prácticos con piezas y planos arquitectónicos."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica la representación de un mecanismo simple en un plano de conjunto.","Se identifican las piezas individuales y sus relaciones funcionales en el conjunto.","Se elige la escala adecuada y la disposición de las vistas en el formato.","Se dibuja cada pieza con sus referencias numeradas para facilitar la identificación.","Se incluye una lista de despiece con las características de cada componente del mecanismo."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se aborda la construcción de un arco de circunferencia que pase por tres puntos dados.","Se trazan las mediatrices de los segmentos formados por los puntos dos a dos.","Se localiza el centro del arco en la intersección de las dos mediatrices trazadas.","Se mide la distancia del centro a uno de los puntos para obtener el radio.","Se traza el arco con el compás verificando que pasa por los tres puntos."]'),
('dibujo-tecnico', 'bachillerato', '{1}', '["Se planifica la representación''isométrica de una pieza con elementos circulares interiores.","Se trazan los ejes isométricos formando ángulos de 120 grados entre ellos.","Se dibuja el contorno general de la pieza utilizando las medidas reales sobre los ejes.","Se trazan los círculos como elipses isométricas utilizando el método de los cuatro centros.","Se completa la representación con líneas vistas y ocultas según corresponda al dibujo."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema complejo de tangencias entre tres circunferencias en el plano.","Se identifican los datos del problema y se eligen los métodos más''adecuados.","Se aplican las propiedades de potencias y centros radicales para localizar los centros.","Se trazan las soluciones posibles verificando que cumplan todas las condiciones de tangencia.","Se presenta el resultado final con todas las construcciones auxiliares necesarias."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se introduce el sistema de planos acotados como alternativa al sistema diédrico clásico.","Se aprende a representar puntos rectas y planos mediante una sola proyección''horizontal.","Se utilizan cotas numéricas para indicar las elevaciones de cada elemento representado.","Se resuelven problemas de intersección''y verdadera magnitud aplicando este sistema específico.","El sistema de planos acotados se aplica especialmente en topografía y arquitectura paisajística."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de una pieza compleja en perspectiva isométrica detallada.","Se eligen los ejes isométricos y se identifican los elementos principales de la pieza.","Se trazan las medidas reales sobre los ejes respetando las direcciones isométricas correctas.","Se dibujan los elementos curvos como elipses isométricas utilizando los métodos apropiados.","Se completa la perspectiva con líneas vistas y ocultas mostrando todos los detalles."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema avanzado de geometría proyectiva entre dos formas planas.","Se identifican los elementos correspondientes en cada forma y la relación proyectiva entre ellos.","Se aplica la propiedad fundamental que cuatro puntos definen una proyectividad única.","Se construyen los elementos buscados utilizando rectas conjugadas y haces proyectivos.","Se verifica la solución comprobando que cumpla las propiedades de la proyectividad."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un sólido de revolución para representarlo en perspectiva cónica frontal.","Se determinan el punto de vista y el plano del cuadro adecuados al problema.","Se proyectan los puntos clave del sólido obteniendo sus posiciones en perspectiva.","Se trazan las generatrices y las circunferencias paralelas con la deformación cónica.","Se completa el dibujo mostrando volumen y profundidad mediante el sombreado adecuado."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema de inversión geométrica para resolver una construcción compleja.","Se elige el centro y el radio de inversión más''adecuados para simplificar el problema.","Se transforman los elementos del problema mediante la inversión''obteniendo una figura más simple.","Se resuelve el problema en la figura transformada utilizando construcciones más sencillas.","Se aplica la inversión''inversa para obtener la solución''en la figura original."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación''arquitectónica de un edificio en perspectiva cónica oblicua.","Se eligen los puntos de fuga adecuados según la posición del observador deseado.","Se trazan las líneas de fuga principales para definir el volumen general del edificio.","Se añaden los detalles arquitectónicos respetando las proporciones y la perspectiva trazada.","Se completa el dibujo con sombras y materiales para dar realismo a la representación."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un problema avanzado de intersecciones entre superficies curvas en el espacio.","Se proyectan las superficies en el sistema diédrico utilizando las vistas necesarias.","Se construye la curva de intersección punto por punto mediante planos auxiliares estratégicos.","Se obtiene la verdadera forma de la curva proyectándola sobre uno de los planos.","Se completa el dibujo con las cotas y referencias necesarias para fabricar la pieza."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda la representación normalizada de roscas en planos técnicos industriales.","Se aprenden los símbolos y las convenciones para representar roscas exteriores e interiores.","Se diferencian los distintos tipos de roscas según''el sistema métrico americano o whitworth.","Se aplican las normas para acotar correctamente las roscas en planos de fabricación.","Se completa un ejercicio práctico representando una pieza con varios elementos roscados."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se introduce el dibujo asistido por ordenador como herramienta profesional moderna.","Se aprenden los comandos básicos para dibujar líneas círculos polígonos y curvas.","Se utilizan capas y bloques para organizar mejor la información del dibujo.","Se aplican las acotaciones automáticas siguiendo las normas técnicas establecidas internacionalmente.","Se imprime el plano final ajustando la escala y el formato del papel."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema de afinidad oblicua entre dos figuras planas en el plano.","Se identifica el eje de afinidad y la dirección de afinidad como elementos clave.","Se construyen los puntos correspondientes aplicando la propiedad fundamental de la afinidad.","Se obtiene la figura afín verificando que las rectas paralelas se mantienen paralelas.","Se aplica la afinidad para resolver problemas de transformación de cónicas."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un cuerpo poliédrico mediante su desarrollo plano.","Se identifican todas las caras del poliedro y sus relaciones de adyacencia.","Se trazan las caras una a una respetando las dimensiones reales y los ángulos.","Se añaden las pestañas necesarias para el ensamblaje del modelo tridimensional.","Se verifica que el desarrollo permite reconstruir correctamente el poliedro original."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda la representación de elementos normalizados como tornillos tuercas y arandelas.","Se aprenden las dimensiones estándar de cada elemento según las normas internacionales.","Se utilizan las representaciones simplificadas que evitan dibujar todos los detalles geométricos.","Se aplican las convenciones para acotar y referenciar estos elementos en los planos.","Se completa un plano de conjunto con varios elementos normalizados correctamente representados."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se introduce el concepto de tolerancias dimensionales en los planos de fabricación.","Se aprenden los símbolos y las convenciones para indicar las tolerancias en cada cota.","Se aplican las tolerancias generales y las específicas según las exigencias del diseño.","Se calculan los ajustes entre piezas que deben ensamblarse mediante interferencia o juego.","Se completa un plano técnico con todas las tolerancias necesarias para la fabricación."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica una pieza compleja con elementos curvos y rectos para acotarla correctamente.","Se eligen las cotas funcionales que son críticas para el correcto funcionamiento de la pieza.","Se añaden las cotas auxiliares necesarias para complementar la información dimensional.","Se evita el solapamiento y la duplicación de cotas en el plano final.","Se revisa el plano completo para asegurar que toda la geometría esté correctamente acotada."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica un proyecto de diseño industrial desde la idea inicial hasta el plano final.","Se realizan bocetos preliminares explorando diferentes alternativas de diseño y forma.","Se seleccionan las mejores ideas y se desarrollan en dibujos más detallados con medidas.","Se elabora el plano definitivo con todas las vistas cotas y especificaciones técnicas.","Se presenta el proyecto con una memoria explicativa y los planos correspondientes."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema avanzado de geometría descriptiva con superficies cuadráticas.","Se identifican las dos superficies y se eligen los métodos adecuados para hallar la intersección.","Se construyen los puntos de la curva intersección''utilizando planos o esferas auxiliares.","Se proyecta la curva sobre los planos del sistema diédrico para visualizar su forma.","Se verifica el resultado utilizando propiedades geométricas o construcciones alternativas."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de una construcción civil compleja en perspectiva cónica.","Se elige la posición del observador y se determinan los puntos de fuga necesarios.","Se trazan los elementos principales del edificio respetando la deformación de la perspectiva.","Se añaden los detalles arquitectónicos como ventanas puertas y elementos decorativos.","Se completa el dibujo con sombras y materiales para dar realismo a la representación."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema de homología entre dos figuras planas en el espacio.","Se identifican el centro de homología el eje y la pareja de puntos correspondientes.","Se aplican las propiedades fundamentales para construir los puntos correspondientes en ambas figuras.","Se verifica que las rectas que unen puntos correspondientes pasan por el centro.","Se aplica la homología para transformar cónicas y resolver problemas geométricos avanzados."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un cuerpo geométrico complejo para representarlo mediante secciones múltiples.","Se eligen los planos de corte que mejor revelan la estructura interna del cuerpo.","Se trazan las secciones obtenidas utilizando los rayados convencionales para cada material.","Se acotan las dimensiones interiores que solo son visibles gracias a las secciones.","Se completa el plano con las vistas auxiliares necesarias para entender la pieza."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un mecanismo de engranajes en plano de fabricación.","Se identifican los engranajes principales y sus relaciones de transmisión''en el conjunto.","Se aplican las representaciones normalizadas para los dientes y las características funcionales.","Se acotan los módulos diámetros primitivos y otros parámetros característicos de cada engranaje.","Se completa el plano con las cotas funcionales y las tolerancias necesarias para la fabricación."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda la representación de un elemento estructural metálico en plano técnico.","Se identifica el perfil normalizado utilizado y se consultan sus dimensiones en tablas técnicas.","Se dibujan las vistas necesarias mostrando las uniones soldadas y atornilladas del elemento.","Se aplican los símbolos normalizados de soldadura para indicar el tipo y dimensiones.","Se completa el plano con las cotas funcionales y las indicaciones para el montaje."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se introduce el dibujo de instalaciones en planos arquitectónicos como electricidad y fontanería.","Se aprenden los símbolos normalizados para cada elemento de las distintas instalaciones.","Se trazan los esquemas de cada instalación sobre la planta del edificio correspondiente.","Se incluyen las cotas y referencias necesarias para identificar cada elemento de la instalación.","Se completa una leyenda explicativa con todos los símbolos utilizados en el plano."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un problema avanzado sobre superficies regladas en el sistema diédrico.","Se determinan las directrices y las generatrices de la superficie reglada en cuestión.","Se proyectan las directrices en el sistema diédrico utilizando las dos vistas principales.","Se trazan las generatrices conectando los puntos correspondientes en cada directriz.","Se verifica el resultado comprobando la coherencia entre las dos proyecciones obtenidas."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un proyecto de mobiliario en planos detallados.","Se elaboran las vistas necesarias incluyendo planta alzados y vistas laterales del mueble.","Se acotan todas las dimensiones siguiendo las normas técnicas para mobiliario y carpintería.","Se incluyen detalles constructivos como ensambles cajeados y herrajes utilizados en el mueble.","Se completa el proyecto con una memoria de materiales y un presupuesto estimado."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema de tangentes a una elipse desde un punto exterior dado.","Se traza la elipse y se sitúa el punto exterior según las indicaciones del enunciado.","Se aplica el método del círculo principal para localizar los puntos de tangencia buscados.","Se trazan las dos rectas tangentes desde el punto exterior a los puntos obtenidos.","Se verifica que las rectas son efectivamente tangentes utilizando las propiedades de la elipse."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un envase comercial mediante su desarrollo plano.","Se identifica la forma geométrica del envase y se calcula sus dimensiones reales.","Se traza el desarrollo de las superficies laterales y de las bases del envase.","Se añaden las pestañas necesarias para el plegado y pegado del envase final.","Se incluyen las marcas gráficas y los textos comerciales que aparecerán''en el envase."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema de proyecciones gnomónicas utilizadas en cartografía celeste antigua.","Se identifica la esfera celeste con los astros que se desean proyectar sobre un plano.","Se elige el punto de proyección''y el plano de proyección''adecuados al problema.","Se proyectan los astros obteniendo sus posiciones en el plano de proyección''elegido.","Se completa el mapa celeste con las constelaciones y referencias astronómicas necesarias."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un problema sobre superficies de revolución para representarlas en planos.","Se determina el eje de revolución''y la curva generatriz que define la superficie.","Se proyecta la superficie en el sistema diédrico utilizando vistas adecuadas.","Se obtienen los contornos aparentes en cada vista mediante construcciones geométricas precisas.","Se completa el dibujo con las cotas necesarias para fabricar la pieza."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un proyecto urbanístico en plano arquitectónico.","Se identifican los elementos principales como edificios calles zonas verdes y mobiliario urbano.","Se elige una escala adecuada para representar el conjunto con suficiente detalle.","Se trazan los elementos siguiendo las normas urbanísticas y simbologías establecidas.","Se completa el plano con la leyenda los rótulos y las referencias correspondientes al proyecto."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema avanzado de geometría proyectiva utilizando conceptos de razón doble.","Se identifican cuatro puntos colineales y se calcula su razón doble como invariante proyectivo.","Se aplica la razón doble para resolver problemas de construcción geométrica complejos.","Se verifica que la razón doble se mantiene constante bajo transformaciones proyectivas.","Se aplica el resultado a problemas concretos de tangencia y cónicas en el plano."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se introduce el concepto de modelado tridimensional asistido por ordenador en aplicaciones técnicas.","Se aprenden las herramientas básicas para crear sólidos a partir de operaciones booleanas.","Se utilizan extrusiones revoluciones y barridos para generar formas complejas tridimensionales.","Se aplican materiales y texturas para visualizar el modelo de forma realista.","Se generan los planos técnicos automáticamente a partir del modelo tridimensional creado."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica una pieza con elementos esféricos para representarla en plano técnico.","Se trazan las vistas necesarias mostrando las esferas y sus puntos de tangencia.","Se aplican las convenciones específicas para acotar elementos esféricos en planos técnicos.","Se utilizan los símbolos normalizados para indicar el diámetro y el radio de cada esfera.","Se completa el plano con las cotas auxiliares necesarias para la fabricación."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un proyecto de diseño industrial completo en planos.","Se elaboran los planos de conjunto el de despiece y los planos individuales de cada pieza.","Se aplican las normas de presentación cajetín lista de despiece y referencias.","Se acotan todas las piezas con las tolerancias y especificaciones necesarias para la fabricación.","Se completa el proyecto con la memoria descriptiva y las instrucciones de montaje."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema de potencia y eje radical entre dos circunferencias en el plano.","Se calculan las potencias de varios puntos respecto a las dos circunferencias dadas.","Se traza el eje radical como lugar geométrico de los puntos con potencias iguales.","Se aplican las propiedades del eje radical para resolver problemas de tangencia avanzados.","Se completa el ejercicio con las construcciones auxiliares necesarias y la solución final."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un sistema mecánico complejo para representarlo en perspectiva explosionada.","Se separan visualmente las piezas del conjunto mostrando las relaciones de montaje.","Se trazan las líneas de unión''entre las piezas para indicar el orden del ensamblaje.","Se acotan las piezas y se incluyen referencias numéricas para identificarlas individualmente.","Se completa el dibujo con una leyenda y las instrucciones de montaje del conjunto."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda la representación de elementos arquitectónicos como bóvedas y arcos en planos.","Se identifican los tipos de arcos y bóvedas según su forma geométrica característica.","Se trazan las proyecciones necesarias mostrando la planta el alzado y los detalles constructivos.","Se aplican las técnicas de la geometría descriptiva para representar las superficies curvas.","Se completa el plano con las cotas y referencias necesarias para la construcción del elemento."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un proyecto de iluminación''en planos arquitectónicos.","Se identifican los puntos de luz necesarios y sus características técnicas para cada estancia.","Se trazan los símbolos normalizados sobre la planta del edificio en cada posición.","Se incluyen los esquemas eléctricos y las conexiones necesarias para la instalación completa.","Se completa el plano con la leyenda y la lista de materiales del proyecto eléctrico."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica un problema avanzado sobre las cuádricas como superficies en el espacio.","Se aprenden las ecuaciones generales y las clasificaciones de las distintas cuádricas.","Se representan las cuádricas más comunes como elipsoides paraboloides e hiperboloides.","Se calculan las secciones planas obtenidas al cortar cada cuádrica con un plano.","Se completa el ejercicio con las construcciones gráficas correspondientes a cada caso."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un proyecto de paisajismo en plano arquitectónico.","Se identifican los elementos vegetales el mobiliario urbano y los caminos del proyecto.","Se eligen los símbolos adecuados para cada tipo de árbol arbusto o elemento decorativo.","Se traza el plano respetando la escala las cotas y las referencias necesarias.","Se completa el proyecto con la leyenda los textos y las indicaciones técnicas correspondientes."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema sobre ejes radicales y centros radicales de tres circunferencias.","Se calculan los tres ejes radicales correspondientes a las parejas de circunferencias.","Se demuestra que los tres ejes radicales son concurrentes en un mismo punto del plano.","Se localiza el centro radical aplicando esta propiedad fundamental de la geometría.","Se aplica el centro radical para resolver problemas avanzados de tangencias entre circunferencias."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica una superficie helicoidal para representarla en el sistema diédrico clásico.","Se determinan los parámetros de la hélice como el paso el radio y el sentido.","Se proyectan los puntos de la hélice obteniendo sus posiciones en cada vista del sistema.","Se trazan las generatrices que conectan los puntos correspondientes formando la superficie.","Se completa el dibujo con las cotas y referencias necesarias para la fabricación del elemento."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se planifica la representación de un proyecto técnico mediante planos a varias escalas.","Se elabora un plano general a escala pequeña que muestra el conjunto del proyecto.","Se elaboran planos de detalle a escala mayor que amplían las zonas más complejas.","Se referencia cada plano de detalle dentro del plano general mediante símbolos específicos.","Se completa el conjunto de planos con un índice y la documentación técnica complementaria."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se aborda un problema sobre la perspectiva caballera con coeficiente de reducción''aplicado.","Se trazan los ejes con un ángulo de cuarenta y cinco grados para el tercer eje.","Se aplica el coeficiente de reducción''al eje de profundidad para evitar deformaciones excesivas.","Se trazan los elementos de la pieza respetando las direcciones y las medidas correspondientes.","Se completa la perspectiva con líneas vistas y ocultas mostrando todos los detalles geométricos."]'),
('dibujo-tecnico', 'bachillerato', '{2}', '["Se identifica una intersección compleja entre dos sólidos geométricos en el espacio.","Se proyectan los sólidos en el sistema diédrico utilizando las vistas necesarias para el problema.","Se determinan los puntos de intersección''utilizando planos auxiliares estratégicamente posicionados.","Se traza la curva de intersección''uniendo los puntos en cada vista del sistema.","Se completa el dibujo con las cotas y referencias necesarias para fabricar el conjunto."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'bachillerato', '{1}', '["Se plantea el problema de calcular la media aritmética de varios números introducidos.","Se diseña un algoritmo que pide los números al usuario mediante un bucle.","Se acumulan los valores en una variable suma y se cuenta cuántos números se introducen.","Al terminar el bucle se calcula la media dividiendo la suma entre la cantidad.","Se muestra la media por pantalla con el formato adecuado y un mensaje explicativo."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere desarrollar un programa que determine si un número es primo o no.","Se diseña un algoritmo que prueba todos los divisores posibles del número introducido.","Si el número tiene algún divisor distinto de uno y de sí mismo no es primo.","Se utiliza un bucle con una condición de salida para optimizar la búsqueda.","Finalmente se muestra el resultado por pantalla indicando si el número es primo."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear un sistema de gestión de una biblioteca pequeña.","Se identifican las entidades principales como libros usuarios y préstamos del sistema.","Se diseña la base de datos con las tablas y las relaciones necesarias entre ellas.","Se programa la interfaz para añadir buscar prestar y devolver libros del sistema.","Finalmente se prueba el sistema con datos reales para verificar su correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se plantea un problema sobre ordenar una lista de números enteros de menor a mayor.","Se elige el algoritmo de la burbuja como solución didáctica para entender el concepto.","Se compara cada par de elementos consecutivos intercambiándolos si están''en orden incorrecto.","Se repite el proceso hasta que la lista esté completamente ordenada según''el criterio.","Se muestra la lista ordenada por pantalla y se analiza la eficiencia del algoritmo."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere crear un programa que convierta una temperatura entre Celsius y Fahrenheit.","Se diseña la interfaz pidiendo al usuario el valor y la escala de origen.","Se aplican las fórmulas correspondientes para realizar la conversión''entre las dos escalas.","Se muestra el resultado por pantalla con el formato adecuado y las unidades.","Se prueba el programa con varios valores para verificar la corrección de los cálculos."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que calcula el factorial de un número entero positivo.","Se elige entre una solución''iterativa con un bucle o una solución recursiva más''elegante.","Se implementa la versión''iterativa multiplicando los números desde uno hasta el valor introducido.","Se prueba el programa con varios valores para verificar la corrección del resultado.","Se compara el rendimiento de las dos versiones con números grandes para entender la diferencia."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere desarrollar un programa que cuente las vocales en una cadena de texto.","Se diseña un algoritmo que recorre cada carácter de la cadena introducida por el usuario.","Se comprueba si cada carácter es una vocal mayúscula o minúscula del alfabeto.","Se incrementa un contador cada vez que se encuentra una vocal en la cadena.","Finalmente se muestra el número total de vocales encontradas en el texto."]'),
('programacion', 'bachillerato', '{1}', '["Se plantea el desarrollo de una calculadora básica con las cuatro operaciones aritméticas.","Se diseña la interfaz gráfica con los botones para los números y las operaciones.","Se programan las funciones que realizan las operaciones de suma resta multiplicación''y división.","Se gestionan los casos especiales como la división por cero o las entradas inválidas.","Se prueba la calculadora con diferentes operaciones para verificar su correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear un juego sencillo de adivinar un número aleatorio.","El programa genera un número aleatorio entre uno y cien al inicio del juego.","Pide al usuario que introduzca un número y le indica si es mayor o menor.","Cuenta los intentos hasta que el usuario adivina el número correcto solicitado.","Al final muestra cuántos intentos se necesitaron para adivinarlo y un mensaje de éxito."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que valide si una contraseña cumple los criterios de seguridad.","Los criterios incluyen longitud mínima mayúsculas minúsculas números y caracteres especiales.","Se diseña una función que comprueba cada uno de los criterios sobre la contraseña.","Si algún criterio no se cumple se muestra un mensaje específico al usuario.","Si todos los criterios se cumplen se valida la contraseña como segura para usar."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un programa que gestione una lista de tareas pendientes con su estado.","Se diseña la estructura de datos para almacenar las tareas con sus atributos básicos.","Se programan funciones para añadir eliminar marcar como completada y listar las tareas.","Se utiliza un menú interactivo que permite al usuario seleccionar las opciones disponibles.","Se guardan las tareas en un archivo para mantener la información''entre diferentes ejecuciones."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un problema sobre buscar un elemento en una lista ordenada de números.","Se elige el algoritmo de búsqueda binaria por su eficiencia frente a la lineal.","Se comparara el elemento buscado con el central de la lista en cada iteración.","Se descarta la mitad correspondiente y se repite el proceso hasta encontrarlo.","Se muestra la posición del elemento o un mensaje si no está en la lista."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que dibuje figuras geométricas básicas con la tortuga gráfica.","Se importa la biblioteca específica para utilizar las funciones de la tortuga gráfica.","Se programan funciones que dibujan triángulos cuadrados pentágonos y otros polígonos regulares.","Se utiliza un menú para que el usuario elija la figura y el tamaño deseados.","Se ejecuta el programa para verificar que las figuras se dibujan correctamente en pantalla."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere crear un programa que simule el lanzamiento de un dado virtual.","Se utiliza la función para generar números aleatorios entre uno y seis.","Se diseña la interfaz que permite al usuario lanzar el dado tantas veces como desee.","Se cuenta cuántas veces sale cada número durante todos los lanzamientos realizados.","Se muestran las estadísticas finales para verificar la distribución''uniforme aleatoria."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un programa que lee un archivo de texto y cuenta sus palabras.","Se abre el archivo en modo lectura y se carga su contenido en memoria.","Se divide el contenido en palabras utilizando los espacios como separadores estándar.","Se cuenta el número total de palabras encontradas en el archivo de texto.","Se muestra el resultado por pantalla y se cierra correctamente el archivo abierto."]'),
('programacion', 'bachillerato', '{1}', '["Se plantea el desarrollo de un programa que convierta números entre diferentes bases numéricas.","Se diseña la interfaz que pide al usuario el número y las bases de origen y destino.","Se aplica el algoritmo de conversión correspondiente a cada caso particular del problema.","Se valida que el número introducido sea correcto para la base de origen indicada.","Se muestra el resultado de la conversión por pantalla con el formato adecuado."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere desarrollar un programa que calcule el área de figuras geométricas básicas.","Se diseña un menú que permite al usuario elegir la figura geométrica deseada.","Se piden las dimensiones necesarias para cada figura como base altura o radio.","Se aplican las fórmulas correspondientes para calcular el área de cada figura.","Se muestra el resultado por pantalla con el formato adecuado y las unidades."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear un programa que gestione las notas de los alumnos.","Se diseña la estructura para almacenar el nombre y las notas de cada alumno.","Se programan funciones para añadir alumnos calcular medias y mostrar listados ordenados.","Se utilizan archivos para guardar la información''entre diferentes ejecuciones del programa.","Se prueba el programa con datos reales para verificar el correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un programa que detecta si una palabra es palíndromo o no.","Se diseña un algoritmo que compara la palabra con su versión''invertida en posiciones.","Se ignoran las mayúsculas y los espacios para hacer la comparación más flexible.","Si la palabra es igual a su inversa se considera un palíndromo válido.","Se muestra el resultado por pantalla indicando claramente al usuario el tipo encontrado."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que muestra los números primos hasta un valor introducido.","Se utiliza el algoritmo de la criba de Eratóstenes para encontrar los primos eficientemente.","Se inicializa una lista con todos los números desde dos hasta el valor indicado.","Se eliminan los múltiplos de cada primo encontrado durante el proceso de cálculo.","Se muestran al final todos los números primos encontrados en el rango especificado."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear una página web sencilla sobre un tema personal.","Se diseña la estructura HTML con secciones de inicio sobre mí galería y contacto.","Se aplican estilos CSS para dar un aspecto visual atractivo y responsive a la web.","Se añade JavaScript para crear elementos interactivos como menús desplegables y formularios.","Finalmente se publica la página en un servidor web gratuito para compartirla con todos."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere crear un programa que simule el funcionamiento básico de un cajero automático.","Se diseña la interfaz que permite al usuario introducir su PIN para acceder al sistema.","Se programan las funciones para consultar el saldo retirar dinero o realizar ingresos.","Se gestionan los casos de PIN incorrecto y de saldo insuficiente con mensajes adecuados.","Se prueba el programa con diferentes operaciones para verificar el correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un problema sobre encontrar el valor máximo y mínimo de una lista.","Se diseña un algoritmo que recorre la lista comparando cada elemento con los valores actuales.","Se actualiza el valor máximo si el elemento actual es mayor que el almacenado.","Se actualiza el valor mínimo si el elemento actual es menor que el almacenado.","Al final del bucle se muestran los valores máximo y mínimo encontrados en la lista."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que cifre un mensaje utilizando el método del César clásico.","Se diseña una función que recibe el mensaje y el desplazamiento como parámetros.","Se aplica el desplazamiento a cada letra del mensaje respetando mayúsculas y minúsculas.","Se mantienen los caracteres no alfabéticos sin cambios para no alterar la legibilidad.","Se muestra el mensaje cifrado por pantalla y se prueba con diferentes ejemplos."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un programa que dibuje un fractal sencillo como el triángulo de Sierpinski.","Se utiliza la recursividad como técnica fundamental para generar las distintas iteraciones del fractal.","Se programa una función recursiva que dibuja triángulos cada vez más pequeños.","Se establece un caso base para detener la recursividad cuando alcance cierto nivel.","Se ejecuta el programa para visualizar el fractal generado en pantalla con detalle."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un programa que calcule estadísticas básicas de un conjunto de datos numéricos.","Se diseña la estructura para almacenar los datos introducidos por el usuario en una lista.","Se programan funciones para calcular la media la mediana la moda y la desviación.","Se muestran los resultados por pantalla con el formato adecuado y mensajes explicativos.","Se prueba el programa con diferentes conjuntos de datos para verificar la corrección."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere crear un programa que genere contraseñas aleatorias seguras de longitud variable.","Se diseña una función que recibe la longitud deseada como parámetro de entrada.","Se generan caracteres aleatorios eligiendo entre letras números y símbolos especiales.","Se asegura que la contraseña incluya al menos un carácter de cada tipo solicitado.","Se muestra la contraseña generada por pantalla lista para ser usada por el usuario."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear un juego del ahorcado en consola.","Se diseña la lista de palabras que se usarán como diccionario del juego.","Se programa la lógica del juego mostrando las letras adivinadas y los intentos restantes.","Se gestiona la entrada del usuario para introducir letras y verificarlas en la palabra.","Se determina el final del juego cuando se adivina la palabra o se agotan los intentos."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que calcule el interés compuesto de una inversión''a varios años.","Se piden al usuario el capital inicial el tipo de interés''y el plazo en años.","Se aplica la fórmula del interés compuesto para calcular el capital final acumulado.","Se muestra una tabla con la evolución del capital año a año durante todo el plazo.","Se permite al usuario realizar varias simulaciones con diferentes parámetros del problema."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un programa que detecta si dos cadenas de texto son anagramas.","Se diseña un algoritmo que cuenta la frecuencia de cada letra en ambas cadenas.","Se comparan las frecuencias para determinar si las dos cadenas son anagramas válidas.","Se ignoran las mayúsculas y los espacios para hacer la comparación más flexible.","Se muestra el resultado indicando si las cadenas son anagramas o no lo son."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear un programa que gestione una agenda personal.","Se diseña la estructura para almacenar los contactos con nombre teléfono y correo.","Se programan funciones para añadir buscar modificar y eliminar contactos de la agenda.","Se utiliza un archivo para guardar la información''entre diferentes ejecuciones del programa.","Se prueba el programa con varios contactos para verificar su correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere desarrollar un programa que dibuje un reloj analógico con la tortuga gráfica.","Se importa la biblioteca específica y se inicializa la pantalla del programa correctamente.","Se dibuja la esfera del reloj con las marcas de las horas y los minutos.","Se programan las manecillas que se mueven cada segundo según la hora actual.","Se ejecuta el programa para verificar que el reloj funciona correctamente en pantalla."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un programa que valide si un correo electrónico tiene formato correcto.","Se diseña un algoritmo que comprueba la presencia del símbolo arroba en la cadena.","Se verifica que existe un dominio válido después del símbolo arroba en el correo.","Se aplican expresiones regulares para asegurar que cumple las reglas de un correo válido.","Se muestra el resultado indicando si el correo es válido o no en pantalla."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que simule la tirada de dos dados durante varios lanzamientos.","Se utiliza la función para generar números aleatorios entre uno y seis para cada dado.","Se calcula la suma de los dos dados y se incrementa un contador para ese resultado.","Se realizan miles de lanzamientos para obtener una muestra estadística representativa del problema.","Se muestra una tabla con las frecuencias de cada suma para verificar la distribución."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear una aplicación de notas que se guarden en archivo.","Se diseña la interfaz de menú con las opciones de crear listar editar y eliminar.","Se programan las funciones que gestionan cada operación con las notas del usuario.","Se utiliza un archivo de texto para almacenar las notas entre diferentes ejecuciones.","Se prueba la aplicación creando varias notas y modificándolas para verificar su funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un problema sobre invertir una cadena de texto sin usar funciones internas.","Se diseña un algoritmo que recorre la cadena desde el último carácter hasta el primero.","Se construye una nueva cadena añadiendo cada carácter en el orden inverso al original.","Se muestra la cadena invertida por pantalla junto con la cadena original para comparar.","Se prueba el algoritmo con diferentes cadenas para verificar el correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que calcule el máximo común divisor de dos números enteros.","Se elige el algoritmo de Euclides como solución''eficiente para resolver este problema.","Se aplica iterativamente el resto de la división''hasta que uno de los números sea cero.","El otro número en ese momento es el máximo común divisor de los originales.","Se muestra el resultado por pantalla y se prueba con diferentes pares de números."]'),
('programacion', 'bachillerato', '{1}', '["Se quiere crear un programa que simule un sistema de votación''electoral simple.","Se diseña la interfaz que permite añadir candidatos y registrar los votos del usuario.","Se programa la función para contar los votos y determinar el ganador final.","Se muestran los resultados por pantalla con el porcentaje de votos de cada candidato.","Se prueba el programa con diferentes escenarios para verificar la corrección del recuento."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un programa que detecte el año bisiesto introducido por el usuario.","Se aplica la regla del calendario gregoriano para determinar si el año es bisiesto.","Un año es bisiesto si es divisible por cuatro pero no por cien.","Sin embargo si es divisible por cuatrocientos también''es bisiesto sin excepciones.","Se muestra el resultado por pantalla indicando si el año introducido es bisiesto."]'),
('programacion', 'bachillerato', '{1}', '["Se desarrolla un programa que calcule la serie de Fibonacci hasta un valor introducido.","Se diseña un algoritmo iterativo que calcula cada término sumando los dos anteriores.","Se inicializan las primeras dos posiciones con los valores cero y uno respectivamente.","Se almacenan los términos en una lista para mostrarlos al final del programa.","Se prueba el programa con diferentes valores para verificar su correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se aborda un programa que simule una calculadora de funciones matemáticas avanzadas.","Se diseña la interfaz con los botones para las funciones trigonométricas logarítmicas y exponenciales.","Se importan las bibliotecas matemáticas necesarias para realizar los cálculos correspondientes.","Se gestionan los errores como las divisiones por cero o los argumentos inválidos.","Se prueba la calculadora con diferentes operaciones para verificar su correcto funcionamiento."]'),
('programacion', 'bachillerato', '{1}', '["Se inicia un proyecto para crear un programa que gestione un inventario de productos.","Se diseña la estructura para almacenar los productos con su nombre cantidad y precio.","Se programan funciones para añadir buscar actualizar y eliminar productos del inventario.","Se calcula el valor total del inventario sumando los productos del precio por la cantidad.","Se utiliza un archivo para guardar la información''entre diferentes ejecuciones del programa."]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto avanzado para desarrollar una aplicación web con base de datos.","Se diseña la arquitectura cliente-servidor con una API REST como interfaz principal.","Se implementa el backend en Python con Flask y la base de datos en MySQL.","Se desarrolla el frontend en React con componentes reutilizables y diseño responsive.","Finalmente se despliega la aplicación''en un servidor en la nube para acceso público."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implemente el algoritmo de Dijkstra para grafos.","Se modela el grafo utilizando una representación con listas de adyacencia y pesos.","Se inicializa una cola de prioridad para procesar los nodos en el orden adecuado.","Se actualizan las distancias mínimas a cada nodo aplicando el algoritmo iterativamente.","Se muestra el camino más corto desde el nodo origen al nodo destino solicitado."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para desarrollar una aplicación móvil con Flutter para iOS y Android.","Se diseña la interfaz utilizando los widgets predefinidos de Flutter para crear las pantallas.","Se programa la lógica de negocio separándola de la interfaz mediante el patrón BLoC.","Se integran servicios externos como notificaciones autenticación''y almacenamiento en la nube.","Se publica la aplicación''en las tiendas oficiales tras superar las pruebas necesarias."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un sistema de recomendación basado en filtrado colaborativo.","Se recopila un conjunto de datos con usuarios productos y valoraciones para entrenar el modelo.","Se calcula la similitud entre usuarios utilizando métricas como la correlación de Pearson.","Se generan recomendaciones para cada usuario basadas en los gustos de usuarios similares.","Se evalúa el sistema utilizando métricas como la precisión''y el recall sobre datos de prueba."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un programa que implementa el algoritmo de ordenación quicksort de manera recursiva.","Se elige un pivote y se particiona la lista colocando elementos menores a la izquierda.","Se aplica recursivamente el algoritmo a las dos sublistas resultantes de la partición.","Se combina el resultado obteniendo la lista completamente ordenada al final del proceso.","Se analiza la complejidad temporal y espacial del algoritmo en los diferentes casos posibles."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para crear un chatbot utilizando técnicas de procesamiento del lenguaje natural.","Se entrena un modelo de aprendizaje automático con un conjunto de conversaciones de ejemplo.","Se diseña la interfaz que permite al usuario interactuar con el chatbot mediante texto.","Se integran respuestas automáticas según los patrones detectados en los mensajes del usuario.","Se evalúa la efectividad del chatbot con diferentes tipos de consultas y se mejora iterativamente."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para desarrollar un videojuego en dos dimensiones con Unity.","Se diseñan los personajes los escenarios y los elementos interactivos del juego.","Se programa la lógica del juego en C Sharp incluyendo los movimientos colisiones y puntuaciones.","Se añaden efectos sonoros música y animaciones para mejorar la experiencia del jugador.","Se compila el juego para diferentes plataformas y se publica en una tienda online."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implemente un árbol binario de búsqueda.","Se diseña la estructura del nodo con los atributos valor hijo izquierdo y hijo derecho.","Se programan las operaciones básicas como inserción búsqueda eliminación''y recorrido del árbol.","Se implementan los recorridos en preorden inorden y postorden con funciones recursivas.","Se prueba el árbol con diferentes operaciones para verificar el correcto funcionamiento."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear una API REST que gestione una tienda online.","Se diseñan los endpoints necesarios para gestionar productos categorías clientes y pedidos.","Se implementa el backend con Node.js y Express.js conectándolo a una base de datos.","Se documenta la API utilizando Swagger para facilitar su uso por otros desarrolladores.","Se prueba la API con herramientas como Postman para verificar todos los endpoints."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para desarrollar un sistema de detección de objetos en imágenes.","Se utiliza una biblioteca de visión''artificial como OpenCV o TensorFlow para el desarrollo.","Se entrena un modelo de aprendizaje profundo con un conjunto de imágenes etiquetadas.","Se evalúa la precisión del modelo utilizando un conjunto de imágenes de prueba.","Se integra el modelo en una aplicación que detecta objetos en tiempo real desde una cámara."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un sistema de gestión de contraseñas seguro utilizando técnicas criptográficas avanzadas.","Se diseña la interfaz para añadir buscar y eliminar contraseñas de la aplicación.","Se cifran las contraseñas utilizando algoritmos como AES con una clave maestra del usuario.","Se almacenan los datos cifrados en un archivo local protegido contra accesos no autorizados.","Se prueba el sistema con diferentes contraseñas para verificar la seguridad y usabilidad."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implemente el algoritmo de búsqueda A estrella.","Se modela el problema como un grafo con nodos y aristas con costes asociados.","Se diseña la función''heurística que estima el coste desde un nodo al objetivo.","Se implementa el algoritmo utilizando una cola de prioridad para procesar los nodos.","Se prueba el algoritmo con diferentes mapas para verificar la eficiencia y la corrección."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear una aplicación de seguimiento de hábitos personal.","Se diseña la base de datos para almacenar los hábitos del usuario y sus registros diarios.","Se desarrolla la interfaz utilizando frameworks como React Native para móviles multiplataforma.","Se implementan notificaciones que recuerdan al usuario realizar sus hábitos diariamente.","Se añaden gráficos y estadísticas que muestran el progreso del usuario a lo largo del tiempo."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un sistema de control de versiones simple inspirado en el funcionamiento de Git.","Se diseña la estructura de archivos para almacenar las versiones de los documentos.","Se implementan las funciones básicas como inicializar un repositorio commit y revertir cambios.","Se utilizan algoritmos de comparación para detectar las diferencias entre versiones del archivo.","Se prueba el sistema con varios documentos para verificar el correcto funcionamiento."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para desarrollar un compilador básico para un lenguaje sencillo.","Se diseña la gramática del lenguaje incluyendo las palabras clave operadores y estructuras.","Se implementa el analizador léxico que convierte el código fuente en una lista de tokens.","Se programa el analizador sintáctico que construye un árbol de sintaxis abstracta del programa.","Se desarrolla el generador de código que produce el código máquina final ejecutable."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear una red social básica con funcionalidades de mensajería.","Se diseña la base de datos para almacenar usuarios publicaciones comentarios y mensajes privados.","Se desarrolla el backend utilizando Django y se implementan las funciones de autenticación segura.","Se programa el frontend utilizando Vue.js para crear una interfaz interactiva y atractiva.","Se despliega la aplicación''en un servidor accesible desde internet para uso de los usuarios."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implementa el algoritmo de encriptación RSA.","Se generan dos números primos grandes y se calcula su producto como módulo del cifrado.","Se calculan las claves pública y privada utilizando las propiedades de la teoría de números.","Se programa el proceso de cifrado y descifrado utilizando las claves generadas anteriormente.","Se prueba el algoritmo con diferentes mensajes para verificar el correcto funcionamiento."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de aprendizaje automático para clasificación.","Se recopila un conjunto de datos etiquetado para entrenar el modelo de clasificación.","Se eligen las características más relevantes mediante técnicas de selección de variables.","Se entrena el modelo utilizando algoritmos como árboles de decisión''o redes neuronales artificiales.","Se evalúa el modelo con un conjunto de datos de prueba calculando métricas de precisión."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla una aplicación de escritorio multiplataforma utilizando el framework Electron.","Se diseña la interfaz utilizando HTML CSS y JavaScript para crear una experiencia atractiva.","Se programa la lógica de negocio aprovechando las capacidades de Node.js en el backend.","Se integran funcionalidades nativas como el sistema de archivos las notificaciones y los menús.","Se empaqueta la aplicación para Windows Mac y Linux utilizando las herramientas de Electron."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para desarrollar un sistema de reconocimiento de voz simple.","Se utiliza una API de reconocimiento de voz como la de Google Cloud o Microsoft Azure.","Se diseña la interfaz que permite al usuario grabar un audio y obtener su transcripción.","Se procesan los comandos detectados y se ejecutan acciones específicas en la aplicación.","Se prueba el sistema con diferentes voces y comandos para verificar la precisión''obtenida."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de gestión de proyectos al estilo kanban.","Se diseña la base de datos para almacenar los proyectos las tareas y los usuarios involucrados.","Se desarrolla el frontend utilizando React con un tablero kanban interactivo y arrastrable.","Se implementa el backend con una API REST que gestiona todas las operaciones del sistema.","Se despliega la aplicación''en un servidor accesible para todos los usuarios del equipo."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implementa el algoritmo de programación dinámica.","Se identifica un problema clásico como la mochila o la subsecuencia común más larga.","Se diseña la tabla de subproblemas y la relación de recurrencia entre ellos.","Se implementa el algoritmo iterativamente rellenando la tabla de abajo hacia arriba.","Se analiza la complejidad temporal y espacial del algoritmo comparándola con otras alternativas."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un programa que utiliza redes neuronales para clasificar imágenes de dígitos.","Se utiliza el conjunto de datos MNIST que contiene miles de imágenes de dígitos manuscritos.","Se diseña una red neuronal convolucional con varias capas utilizando Keras o TensorFlow.","Se entrena el modelo con el conjunto de datos durante varias épocas hasta obtener buena precisión.","Se evalúa el modelo con un conjunto de prueba calculando la precisión''obtenida final."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para crear un sistema de gestión de eventos con calendario integrado.","Se diseña la base de datos para almacenar eventos usuarios invitaciones y notificaciones.","Se desarrolla el frontend con una vista de calendario que muestra los eventos por mes.","Se programa el envío de notificaciones por correo electrónico cuando se acerca un evento.","Se despliega la aplicación''en un servidor accesible para todos los usuarios autorizados."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para desarrollar un sistema de seguimiento de mascotas con GPS.","Se utiliza una placa Arduino con un módulo GPS y un módulo de comunicación''inalámbrica.","Se programa el firmware que envía la ubicación de la mascota a un servidor remoto.","Se desarrolla una aplicación móvil que muestra la ubicación''en tiempo real en un mapa.","Se prueba el sistema con una mascota real para verificar la precisión''y la fiabilidad."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implementa el algoritmo de ordenación merge sort.","Se divide la lista en dos mitades aplicando recursivamente el algoritmo a cada mitad.","Se combinan las dos mitades ordenadas utilizando un algoritmo de mezcla con dos punteros.","Se obtiene la lista completamente ordenada al terminar el proceso recursivo de manera eficiente.","Se analiza la complejidad temporal del algoritmo demostrando que es O de n log n."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de domótica casera con sensores Arduino.","Se conectan sensores de temperatura humedad luminosidad y presencia a una placa Arduino.","Se programa el firmware que recopila los datos y los envía a un servidor central.","Se desarrolla una interfaz web que muestra los datos en tiempo real y permite el control.","Se prueba el sistema en una casa real para verificar el funcionamiento de todos los componentes."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para desarrollar un sistema de criptomoneda básico utilizando blockchain.","Se diseña la estructura de los bloques con sus campos como hash anterior datos y nonce.","Se implementa el algoritmo de prueba de trabajo para asegurar la integridad de los bloques.","Se programa una red simple donde varios nodos pueden enviar y recibir transacciones.","Se prueba el sistema con varias transacciones para verificar la seguridad y la consistencia."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un sistema de búsqueda de información tipo motor de búsqueda básico.","Se recopila un conjunto de documentos y se construye un índice invertido para acelerar las búsquedas.","Se implementa la búsqueda de palabras clave utilizando el índice creado anteriormente.","Se calcula la relevancia de cada documento utilizando el algoritmo TF-IDF clásico.","Se prueba el sistema con diferentes consultas para verificar la precisión de los resultados."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para crear un sistema de gestión de bibliotecas multiusuario.","Se diseña la base de datos para almacenar libros usuarios préstamos reservas y multas.","Se desarrolla el backend utilizando Spring Boot para Java con todas las funciones necesarias.","Se programa el frontend utilizando Angular para crear una interfaz moderna y responsive.","Se despliega el sistema en un servidor accesible para los usuarios de la biblioteca."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de inteligencia artificial que juegue al ajedrez.","Se utiliza el algoritmo minimax con poda alfa beta para evaluar las posiciones del tablero.","Se diseña una función de evaluación que calcula el valor de cada posición del tablero.","Se programa el motor que decide el mejor movimiento explorando varias profundidades de juego.","Se prueba el motor jugando contra otros motores y humanos para verificar su nivel."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un programa que implementa una expresión regular para validar entradas.","Se diseñan las expresiones regulares para validar correos teléfonos códigos postales y fechas.","Se programan funciones que comprueban si una cadena cumple con cada expresión regular definida.","Se gestionan los casos especiales como caracteres internacionales o formatos alternativos comunes.","Se prueba el sistema con diferentes entradas para verificar la corrección de las validaciones."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un programa que aplica algoritmos genéticos para resolver problemas de optimización.","Se diseña la representación de los individuos como vectores con los parámetros del problema.","Se implementan las operaciones de selección cruce y mutación que componen el algoritmo genético.","Se ejecuta el algoritmo durante varias generaciones hasta encontrar una solución satisfactoria.","Se compara la solución''obtenida con métodos clásicos para evaluar la eficacia del algoritmo."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de monitorización de servidores en tiempo real.","Se desarrolla un agente que recopila datos como uso de CPU memoria disco y red.","Se programa un servidor central que recibe los datos de todos los agentes desplegados.","Se desarrolla un dashboard web que muestra los datos mediante gráficos y alertas en tiempo real.","Se despliega el sistema en una infraestructura real para verificar su escalabilidad y fiabilidad."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para desarrollar un sistema de visualización de datos científicos.","Se utilizan bibliotecas como Matplotlib Plotly o D3.js para crear los gráficos interactivos.","Se implementan diferentes tipos de gráficos como barras líneas mapas de calor y burbujas.","Se desarrolla una interfaz web que permite al usuario filtrar y explorar los datos.","Se prueba el sistema con diferentes conjuntos de datos para verificar la efectividad visual."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un programa que implementa el algoritmo de Floyd Warshall para grafos densos.","Se modela el grafo utilizando una matriz de adyacencia con los pesos de las aristas.","Se inicializa la matriz de distancias mínimas con los valores iniciales del problema.","Se aplica el algoritmo iterativamente actualizando las distancias mínimas a través de cada vértice.","Se obtiene la matriz final con las distancias mínimas entre todos los pares de nodos."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de comercio electrónico completo y funcional.","Se diseña la base de datos con productos categorías clientes pedidos pagos y reseñas.","Se desarrolla el backend con una arquitectura de microservicios para garantizar la escalabilidad.","Se programa el frontend con un diseño moderno y atractivo utilizando React o Vue.js.","Se integra una pasarela de pago segura y se despliega la aplicación''en producción."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un sistema de pruebas automatizadas para una aplicación web.","Se utilizan herramientas como Selenium o Cypress para automatizar las pruebas en el navegador.","Se programan pruebas unitarias para los componentes individuales utilizando Jest o Mocha.","Se implementan pruebas de integración que verifican el funcionamiento conjunto de varios módulos.","Se integran las pruebas en un sistema de integración continua para ejecutarlas automáticamente."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear una aplicación de realidad aumentada con dispositivos móviles.","Se utiliza un framework como ARKit para iOS o ARCore para Android para el desarrollo.","Se diseñan modelos tridimensionales que aparecerán superpuestos sobre el mundo real visualizado.","Se programa la interacción del usuario con los objetos virtuales mediante toques y gestos.","Se prueba la aplicación''en diferentes entornos para verificar la precisión del rastreo."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un programa que implementa una máquina virtual sencilla para un lenguaje propio.","Se diseña el conjunto de instrucciones que la máquina virtual será capaz de ejecutar.","Se implementa el intérprete que lee las instrucciones y las ejecuta secuencialmente.","Se programa la gestión de la pila los registros y la memoria de la máquina virtual.","Se prueba la máquina virtual ejecutando programas sencillos en el lenguaje diseñado anteriormente."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda un proyecto para crear un sistema de gestión de archivos en la nube.","Se diseña la arquitectura distribuida que permite almacenar archivos en varios servidores.","Se implementan funciones para subir descargar compartir y sincronizar archivos entre dispositivos.","Se programa el cifrado de los archivos para garantizar la seguridad de los datos.","Se despliega el sistema en una infraestructura cloud y se prueba con diferentes usuarios."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un sistema de detección de anomalías en datos.","Se recopila un conjunto de datos históricos para entrenar el modelo de detección de anomalías.","Se utilizan algoritmos como Isolation Forest o One-Class SVM para detectar patrones inusuales.","Se evalúa el modelo con datos reales para verificar la precisión''y reducir falsos positivos.","Se integra el modelo en una aplicación que alerta cuando detecta anomalías en tiempo real."]'),
('programacion', 'bachillerato', '{2}', '["Se aborda el desarrollo de un sistema de procesamiento de imágenes con filtros avanzados.","Se utilizan bibliotecas como OpenCV para implementar los filtros más comunes.","Se programan filtros como desenfoque enfoque detección de bordes y conversión''a escala de grises.","Se desarrolla una interfaz que permite al usuario aplicar los filtros sobre sus propias imágenes.","Se prueba el sistema con diferentes imágenes para verificar la calidad de los resultados."]'),
('programacion', 'bachillerato', '{2}', '["Se inicia un proyecto para crear un asistente virtual personal con reconocimiento de voz.","Se integra una API de reconocimiento de voz para convertir el audio del usuario a texto.","Se procesa el texto utilizando técnicas de procesamiento del lenguaje natural para entender la intención.","Se ejecutan las acciones correspondientes como buscar información''o realizar tareas en el sistema.","Se sintetiza la respuesta utilizando una API de síntesis de voz para responder al usuario."]'),
('programacion', 'bachillerato', '{2}', '["Se desarrolla un programa que implementa el algoritmo de Kruskal para encontrar el árbol de expansión mínima.","Se ordenan todas las aristas del grafo por peso de menor a mayor.","Se utilizan estructuras de unión''y búsqueda para detectar los ciclos durante el proceso.","Se añaden las aristas al árbol mientras no formen un ciclo con las anteriores.","Se obtiene el árbol de expansión mínima con el menor coste total posible."]');
